-- Poems batch 283
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6939649b-4dfd-41c2-a3df-4fa50ae829a4','謝到水仙二本','韓維','宋','宋诗','song-poetry','','[]','黄中秀外幹虛通，乃喜佳名近帝聰。',64,'全唐诗/poet.song.25000.json','["黄中秀外幹虛通，乃喜佳名近帝聰。", "密葉暗傳深夜露，殘花猶及早春風。", "拒霜已失芙蓉艷，出水難留菡萏紅。", "多謝使君憐寂寞，許教綽約伴仙翁。"]'),
('09363dc5-e4ba-491e-bf16-e827c229f67d','送孫通直','韓維','宋','宋诗','song-poetry','','[]','白首歸來養性情，同時流輩盡彫零。',64,'全唐诗/poet.song.25000.json','["白首歸來養性情，同時流輩盡彫零。", "忘懷物外思游好，訪舊樽前得典刑。", "霜月醉留湖榭白，雪風吟度隴山青。", "斯民利病君多識，好奉新書謁帝庭。"]'),
('d60efdce-3246-49be-b478-45395c3f55c9','和杜七學士見寄','韓維','宋','宋诗','song-poetry','','[]','謀猷久恨辜明主，骸骨終蒙賜老臣。',64,'全唐诗/poet.song.25000.json','["謀猷久恨辜明主，骸骨終蒙賜老臣。", "絕口敢論當世事，放懷重老故園春。", "閑尋物外忘言客，喜遇杯中得趣人。", "能作新詩仍寄我，知君心不在埃塵。"]'),
('df358def-d4a3-4eb9-a006-40433a515c96','會微之諸君','韓維','宋','宋诗','song-poetry','','[]','開齋坐閱歲華空，樂與賢豪燕喜同。',64,'全唐诗/poet.song.25000.json','["開齋坐閱歲華空，樂與賢豪燕喜同。", "清影屢移松桂月，和聲頻送管弦風。", "遠于籍外追歌妓，恨不樽前作醉翁。", "况近始郊多廢事，共迎蕭露入弦中。"]'),
('f99bd946-129b-4580-8dc2-990de55881a2','觀安公亭戲呈觀文主人','韓維','宋','宋诗','song-poetry','','[]','十五年來此地行，白頭重到不勝情。',64,'全唐诗/poet.song.25000.json','["十五年來此地行，白頭重到不勝情。", "寒梅未放黄金蕊，冰綻初流碧玉聲。", "憔悴霜松如有訴，紛披風竹似相迎。", "紅裙散後歌音絕，海鶴階前時一鳴。"]'),
('1a363af6-e175-4fc2-8560-968c3e14fde1','招王微之','韓維','宋','宋诗','song-poetry','','[]','龍圖老學士，腰痛比如何。',48,'全唐诗/poet.song.25000.json','["龍圖老學士，腰痛比如何。", "久闋新詩和，應尋曲舊歌。", "梅紅輕綻萼，池綠細生波。", "欲與君同醉，春風試舞羅。"]'),
('79d1416a-6c57-4136-9692-56fb95ed44d3','和曾通判招飲後見貽','韓維','宋','宋诗','song-poetry','','[]','竹際松間構小堂，高眠客榻燕華觴。',64,'全唐诗/poet.song.25000.json','["竹際松間構小堂，高眠客榻燕華觴。", "每詢濁酒頻加釀，不問餘金幾在囊。", "自愧效陶無好語，敢煩凌杜發新章。", "慶門又喜親才子，藉藉聲華滿士鄉。"]'),
('ba440850-b8a8-4c87-98d6-2ead2be53846','次韵玉汝','韓維','宋','宋诗','song-poetry','','[]','浮生難得是華顛，美景能并屬禁烟。',64,'全唐诗/poet.song.25000.json','["浮生難得是華顛，美景能并屬禁烟。", "况值公庭多暇日，且欣農畝兆豐年。", "曾裁酒量容杯斝，謂品歌聲被管弦。", "莫道老人無氣力，能排萬事付陶然。"]'),
('7f2b5ea5-1f35-4806-adc1-14e7eb72d9cd','和曾令綽資政西湖見貽','韓維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','虎節嘗三換，琳宮亦再來。',48,'全唐诗/poet.song.25000.json','["虎節嘗三換，琳宮亦再來。", "白添新鬢髪，紅識舊亭臺。", "酒爲迎寒好，花應趁暖栽。", "但愁衰謝意，未到已思迴。"]'),
('23e9bdbb-9609-48f6-a192-4a7879242ed1','同芳公上人遊湖','韓維','宋','宋诗','song-poetry','','[]','晴陽溢目盡光華，乘興閑來步徑沙。',64,'全唐诗/poet.song.25000.json','["晴陽溢目盡光華，乘興閑來步徑沙。", "水滿不知新穫稻，霜嚴猶放後凋花。", "傳心密處寧離妄，著眼高時亦是邪。", "竟日清談何所得，魚沉鷺起各歸家。"]'),
('bd4f46b7-2135-4919-b3e1-1863975e9b8e','和公美以諸家會集所賦詩','韓維','宋','宋诗','song-poetry','','[]','道在何非樂，官閑不近權。',72,'全唐诗/poet.song.25000.json','["道在何非樂，官閑不近權。", "過從只閭里，真率易盤筵。", "捉麈躬千聖，銜杯慕八仙。", "清歡垂老得，佳句即時傳。", "玉醴初醇日，瓊花欲墜天。", "誰能于此際，華髪問流年。"]'),
('fa24189a-c1de-40d6-91c5-a77aab475820','送忠玉提刑還朝','韓維','宋','宋诗','song-poetry','','[]','十五年前相遇地，白頭還喜一樽同。',64,'全唐诗/poet.song.25000.json','["十五年前相遇地，白頭還喜一樽同。", "從容笑貌忘君老，款密情期似乃翁。", "別席俯迎籬菊秀，全家看盡渚蓮紅。", "臨分不用言爲贈，奕世忠臣自祖風。"]'),
('17f1b442-9581-4b97-8c95-476181f5b013','和微之','韓維','宋','宋诗','song-poetry','','[]','早接忠賢論，常欽古學風。',72,'全唐诗/poet.song.25000.json','["早接忠賢論，常欽古學風。", "何期華髪後，更得綠樽同。", "遠水秋光外，高亭夕照中。", "芡盤凋晚翠，菊艷奪春紅。", "歌放聊娛老，談精本代工。", "歡餘笑張翰，迢遞想江東。"]'),
('d5b33e31-566c-4939-8b90-b19522672161','寓展江亭謝堯夫寄酒及花','韓維','宋','宋诗','song-poetry','','[]','措枉我先違陛石，均勞公亦下堤沙。',64,'全唐诗/poet.song.25000.json','["措枉我先違陛石，均勞公亦下堤沙。", "已欣晚歲逢良友，更喜高秋見好花。", "旨酒芳新來似水，危亭清絕至如家。", "三杯舉白歌相和，忘却風前兩鬢華。"]'),
('403d9d60-7d1f-476f-9b7d-b46be7761651','予招賓和微之','韓維','宋','宋诗','song-poetry','','[]','恩予琳宮庇病身，閑中得近酒杯頻。',64,'全唐诗/poet.song.25000.json','["恩予琳宮庇病身，閑中得近酒杯頻。", "偶成五老追前會，仍喜三公作主賓。", "歡興到來歌自發，吝情消盡語皆真。", "時人不用驚疏放，同是羲皇以上人。"]'),
('577d6900-16e5-4fb2-b19e-a7edcec51c2a','和微之堯夫作會','韓維','宋','宋诗','song-poetry','','[]','燕豆何頻設，歸鞍夜屢闌。',72,'全唐诗/poet.song.25000.json','["燕豆何頻設，歸鞍夜屢闌。", "敢言揮麈倦，惟怯釂觴難。", "就暖歌筵密，憑高繪境寬。", "未甘閑處卧，猶學少時歡。", "浮蟻凌山玉，飛花掩袖紈。", "幸同諸老醉，擊壤頌安安。"]'),
('4657fa68-07de-4a51-901e-3a5386915b71','予會賓答微之惠詩','韓維','宋','宋诗','song-poetry','','[]','官冷身閑百不營，一時高會得耆英。',64,'全唐诗/poet.song.25000.json','["官冷身閑百不營，一時高會得耆英。", "杯心酒氣兼香重，池面水華共月清。", "鐵騎忽從弦上出，水龍爭向笛中鳴。", "白頭學士耽禪習，未免詩魔攪道情。"]'),
('67545e4d-8fcd-4211-85bf-dd382e845cbb','陪范堯夫之北第飲彝叟新堂','韓維','宋','宋诗','song-poetry','','[]','光祿新堂指顧成，非奢非儉稱高情。',64,'全唐诗/poet.song.25000.json','["光祿新堂指顧成，非奢非儉稱高情。", "春風爲我開朱戶，晴日從公駐彩旌。", "庭下早梅驚喜客，門前垂柳欲啼鶑。", "追攀夢境終何得，識取家鄉舊路行。"]'),
('d273571f-1ca2-4eb4-8ef4-b4dca79d481c','寄慶州德孺待制','韓維','宋','宋诗','song-poetry','','[]','常愛公家好弟兄，忠言直道友于情。',64,'全唐诗/poet.song.25000.json','["常愛公家好弟兄，忠言直道友于情。", "心期光祿朝中駕，目斷將軍塞上旌。", "埤堄高風回過雁，琵琶宵寂語流鶑。", "共欣出處非它轍，報國誠身各自行。"]'),
('59696480-fe16-4e20-a2ed-25dc16329d13','燈夕次韵答微之','韓維','宋','宋诗','song-poetry','','[]','白首還家再遇春，每將弦管樂脾神。',64,'全唐诗/poet.song.25000.json','["白首還家再遇春，每將弦管樂脾神。", "况逢舊相分藩契，仍喜閑官脫世紛。", "燈散異光全作晝，歌翻新調欲留雲。", "歸時絕景醒餘醉，極望銀蟾照玉塵。"]'),
('4b249b31-5790-4021-9046-aada1ef43c84','寄鄭州曾資政','韓維','宋','宋诗','song-poetry','','[]','魯公旌旆鎮茲邦，曾奉樽罍佚老堂。',64,'全唐诗/poet.song.25000.json','["魯公旌旆鎮茲邦，曾奉樽罍佚老堂。", "彩服過庭聞政術，緇衣傳世見詩章。", "鬥龍門外波光綠，集鳳臺邊柳色黄。", "應感歸歟形麗唱，故園春草滿池塘。"]'),
('dba42dd9-8cc2-4f4b-9344-df21509d87ea','答李正議見貽','韓維','宋','宋诗','song-poetry','','[]','如公舉世幾何人，八十年齡自在身。',64,'全唐诗/poet.song.25000.json','["如公舉世幾何人，八十年齡自在身。", "處俗不繞諸有相，持心肯受一微塵。", "逢僧便出衣中寶，待士多陳席上珍。", "火宅未須生厭苦，不離當處豈非神。"]'),
('220dd83b-42f4-4cc4-95b0-cd5e34599536','和堯夫思湖上秋時見寄','韓維','宋','宋诗','song-poetry','','[]','落盡芙蕖十頃紅，敗荷衰草滿秋風。',64,'全唐诗/poet.song.25000.json','["落盡芙蕖十頃紅，敗荷衰草滿秋風。", "夷猶畫鷁來天外，嘹唳驚鴻入鏡中。", "亭榭裝成如待我，樽罍開處便思翁。", "粗官豈得君留滯，府第深嚴合在東。"]'),
('e9289c75-867d-4c10-8c8c-0cda0f4337f7','答唐州鄭郎','韓維','宋','宋诗','song-poetry','','[]','先帝宮藩昔曳裾，便將狂直許傾舒。',64,'全唐诗/poet.song.25000.json','["先帝宮藩昔曳裾，便將狂直許傾舒。", "制分內外常更掌，省列東西亦預除。", "敢以功名爲己任，自知謀議與時疏。", "歸來粗足生生計，幸免鄉鄰厭乞諸。"]'),
('b9db5c08-26d5-40d9-b4b3-57256fef554d','答外孫楊承務','韓維','宋','宋诗','song-poetry','','[]','享厚功微每愧顔，辭榮聊企漢疏賢。',64,'全唐诗/poet.song.25000.json','["享厚功微每愧顔，辭榮聊企漢疏賢。", "居民未睹黄公化，過客空疑絳老年。", "適用每慚龜手伎，全生真頼馬蹄篇。", "從今風月知無負，鴨子陂中有釣船。"]'),
('66828647-b48e-4df2-971b-9ef8ed1e2c9c','答張念五','韓維','宋','宋诗','song-poetry','','[]','浮雲名宦祗勞人，解組歸來徑杜門。',64,'全唐诗/poet.song.25000.json','["浮雲名宦祗勞人，解組歸來徑杜門。", "繼世命官聯六傅，傳家與子及諸孫。", "聖賢相對書千帙，閭里交歡酒一樽。", "荷芰滿湖秋氣早，待君方駕踐誠言。"]'),
('179bde7f-4ed0-4346-a320-224d32c2f802','范奉議作西江月勸酒','韓維','宋','宋诗','song-poetry','','[]','故里親交半柏城，坐中牢落似明星。',64,'全唐诗/poet.song.25000.json','["故里親交半柏城，坐中牢落似明星。", "雨多秋草荒三逕，零重寒花坼萬鈴。", "閑後并和詩筆廢，興來未放酒杯停。", "樽前一曲西江月，猶識當年舊典刑。"]'),
('e7d6c93f-825d-49e9-8f45-4b1f0fa9e45e','請微之飲','韓維','宋','宋诗','song-poetry','','[]','句解章通字字安，書成進御九重觀。',64,'全唐诗/poet.song.25000.json','["句解章通字字安，書成進御九重觀。", "更加親切從新詔，却得高閑是舊官。", "禁閣不憂連夜直，好山應許老年看。", "菊香酒熟身無事，且盡樽前一笑歡。"]'),
('22abacb2-14c1-4f37-bdb1-dfae5c96bec6','桃花承露紅','韓維','宋','宋诗','song-poetry','','[]','蕣英憔悴藕花零，籬下紅芳特地榮。',64,'全唐诗/poet.song.25000.json','["蕣英憔悴藕花零，籬下紅芳特地榮。", "妍麗頓添秋氣象，歡娛潛動老心情。", "武陵溪上分顔色，洛水園中得號名。", "爲此徑須判一醉，緩調絲管促飛觥。"]'),
('0b399219-2e96-468a-94a0-4b0f934c7055','招致仕諸君飲','韓維','宋','宋诗','song-poetry','','[]','閑裏高官物外身，追歡高會及良辰。',64,'全唐诗/poet.song.25000.json','["閑裏高官物外身，追歡高會及良辰。", "菊含曉露精神健，酒入凉天氣味醇。", "雙管龍吟清徹漢，四弦鶑語巧回春。", "樽前不用存形迹，同是鄉閭白髪人。"]'),
('690a416a-37ae-4b7f-823a-56aecfe36394','和厚卿值風阻遊范園','韓維','宋','宋诗','song-poetry','','[]','光祿名園慘淡中，十年樽酒與誰同。',64,'全唐诗/poet.song.25000.json','["光祿名園慘淡中，十年樽酒與誰同。", "有秋方畢隨軒雨，未節俄驚落帽風。", "坐想池塘生碧草，獨行階砌惜芳叢。", "陽春絕唱知難和，白首空搔兩鬢蓬。"]'),
('739ff05e-38c8-45b3-be4e-58280006876d','和曾通直','韓維','宋','宋诗','song-poetry','','[]','誤落塵中四十年，乞歸骸骨喜安全。',64,'全唐诗/poet.song.25000.json','["誤落塵中四十年，乞歸骸骨喜安全。", "廟廊論道徒虛耳，彝鼎銘勛愧缺然。", "一視榮枯真若夢，兩忘喧寂始知禪。", "金仙秘典容傳玩，似與君家有舊緣。"]'),
('a0536765-16c2-4e5a-8ad3-51914023441a','依前韵和朱朝奉  其一','韓維','宋','宋诗','song-poetry','','[]','起坐終朝在一堂，興來賓至更銜觴。',64,'全唐诗/poet.song.25000.json','["起坐終朝在一堂，興來賓至更銜觴。", "逢春預展新花檻，扶老時翻舊藥囊。", "心慮已能安止止，聲名何用漸章章。", "少遊有志今方遂，坐守松楸不去鄉。"]'),
('fe0d3e22-95b5-4a59-a6b2-a24bae5b5356','依前韵和朱朝奉  其二','韓維','宋','宋诗','song-poetry','','[]','攬轡宿心終不效，墜車餘骨老猶全。',64,'全唐诗/poet.song.25000.json','["攬轡宿心終不效，墜車餘骨老猶全。", "居仁由義吾之素，處順安時理則然。", "名教地中真有樂，色聲頭上豈非禪。", "樽前醉客應相笑，一曲悲歌幾處緣。"]'),
('1bd04339-d857-4f1b-bc2e-4d37d41a3340','喜雪呈安觀文謝惠酒','韓維','宋','宋诗','song-poetry','','[]','雪花盈尺覆春田，太守勤民慶有年。',64,'全唐诗/poet.song.25000.json','["雪花盈尺覆春田，太守勤民慶有年。", "介任袁安從放卧，寒矜枚叟不加延。", "桃根度曲今何在，柳絮裁詩久未傳。", "內集豈宜虛舊貺，爲公舉白抹朱弦。"]'),
('952f4450-1e6b-47da-8928-260b4823de75','自歡','韓維','宋','宋诗','song-poetry','','[]','逢春何事有咨嗟，短髮昏瞳對好花。',64,'全唐诗/poet.song.25000.json','["逢春何事有咨嗟，短髮昏瞳對好花。", "歡□到來惟止暫，酒分加處更論些。", "一簞□□慚顔氏，百指笙歌類白家。", "送老忘形樂吾分，爲謀豈不是良邪。"]'),
('1adc0fdf-72a2-4bf9-b973-e1c69b29d488','和厚卿飲西湖時小侄同赴','韓維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','勞生從宦意多違，常恨交親會合稀。',64,'全唐诗/poet.song.25000.json','["勞生從宦意多違，常恨交親會合稀。", "父子相隨今不間，主賓交錯暮忘歸。", "微波穩送蘭船度，遲景徐看玉斝飛。", "盡日清歡猶有憾，無人爲唱縷金衣。"]'),
('cacdbb69-fe64-477b-9c1a-b65464fc9c6e','侍講侄告滿還京師以詩送之','韓維','宋','宋诗','song-poetry','','[]','身隨群動各東西，別日常多見面稀。',64,'全唐诗/poet.song.25000.json','["身隨群動各東西，別日常多見面稀。", "老去心情如水淡，暫同樽酒惜花飛。", "仲容任達常知退，公子成名莫忘歸。", "共說無生閑過日，也勝塵土弊朝衣。"]'),
('956202e8-6367-46bb-ab51-2c621c33c10a','風雪偶成','韓維','宋','宋诗','song-poetry','','[]','狂風吹虐雪，勢欲奪春華。',48,'全唐诗/poet.song.25000.json','["狂風吹虐雪，勢欲奪春華。", "委地摧珠貫，依林聚玉沙。", "爐添新熾火，瓶插未殘花。", "一盡忘憂酒，胡爲浪戚嗟。"]'),
('e492db87-5503-4184-9c66-6f7e961fc967','西堂前雙海棠花','韓維','宋','宋诗','song-poetry','','[]','群芳斂色避妖妍，細葉柔條盡可憐。',64,'全唐诗/poet.song.25000.json','["群芳斂色避妖妍，細葉柔條盡可憐。", "明艷濃常因日暖，清香秘不許風傳。", "麗于宮錦如新濯，紅甚山櫻恐墜燃。", "若使退之堂下有，不應長被五楸牽。"]'),
('f9f8ba18-252d-40ab-921d-726722c221da','和三哥登太行山','韓維','宋','宋诗','song-poetry','','[]','三朝恩渥重丘山，論報輸忠豈易殫。',64,'全唐诗/poet.song.25000.json','["三朝恩渥重丘山，論報輸忠豈易殫。", "移疾暫休丞相筆，坐謾猶著侍臣冠。", "清樽一笑聊相樂，白首分飛益自嘆。", "閭里從遊應有日，凝然性海絕波瀾。"]'),
('bf12361c-3c83-41c4-b223-26f20fe4c3f5','送李閣使出守冀州','韓維','宋','宋诗','song-poetry','','[]','天子仁恩撫四陲，邊兵坐飽太平時。',64,'全唐诗/poet.song.25000.json','["天子仁恩撫四陲，邊兵坐飽太平時。", "只知使者持金絮，不識將軍有鼓鼙。", "君去守藩憂就重，古來忘戰志當危。", "祖門事業如南仲，無使家聲愧鼎彝。"]'),
('e83f802b-1cba-449d-a565-8b08840bbe36','和子華兄清洛阻風','韓維','宋','宋诗','song-poetry','','[]','將相身榮大耋年，高懷先到碧嵩前。',64,'全唐诗/poet.song.25000.json','["將相身榮大耋年，高懷先到碧嵩前。", "牙兵不用驅雙節，神物應須護兩舷。", "錦段已傳佳句麗，絲頭無復世情牽。", "華顛學士聆風喜，歸思如今已浩然。"]'),
('69c9f6a8-88cc-4aab-8ed7-8ea24854e8f3','上元夜','韓維','宋','宋诗','song-poetry','','[]','結綵山爲對斗魁，和風清月共徘徊。',64,'全唐诗/poet.song.25000.json','["結綵山爲對斗魁，和風清月共徘徊。", "喧闐樂曲鑾輿近，烜赫袍光雉扇開。", "午夜明缸回照景，晴天華轂發春雷。", "太平時節身無補，慚愧年年游騎來。"]'),
('52597f40-27a9-43a6-a21c-e5b67ff888ff','餞朱□郎席上作','韓維','宋','宋诗','song-poetry','','[]','狂風凍雨□無時，坐惜良辰樂事違。',64,'全唐诗/poet.song.25000.json','["狂風凍雨□無時，坐惜良辰樂事違。", "娛老便甘千日面，減春何啻一花飛。", "池塘新漲魚紋亂，臺榭餘寒燕語稀。", "莫唱鄉關動離思，爲君勤抹醉中歸。"]'),
('6abe098f-a08b-4ba7-8581-0323bd78f0ec','送安厚卿','韓維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','廟廊接武窺風範，藩翰交符識典刑。',64,'全唐诗/poet.song.25000.json','["廟廊接武窺風範，藩翰交符識典刑。", "即聽攀轅傾里巷，少回征轡燕家亭。", "池邊密葉聽鶑語，庭下殘花墜鶴翎。", "不必陽關動離思，西湖柳色正青青。"]'),
('720ae5ee-5fb0-4542-b10d-204ca6506019','陪堯夫兄弟一飯清話','韓維','宋','宋诗','song-poetry','','[]','相別相逢似轉輪，迹雖遼遠意常親。',64,'全唐诗/poet.song.25000.json','["相別相逢似轉輪，迹雖遼遠意常親。", "美羹舊手欽元老，鹽菜誠心待故人。", "密竹環波寧受暑，殘花映葉尚留春。", "逍遥竟日聞嘉話，時節方知自有因。"]'),
('3716802b-1659-40eb-a5ce-a28cd8698be4','寄亳州范待制','韓維','宋','宋诗','song-poetry','','[]','知公道韵厭軒裳，得郡今猶占厲鄉。',64,'全唐诗/poet.song.25000.json','["知公道韵厭軒裳，得郡今猶占厲鄉。", "館御列仙蘭終馥，迭唱篇章玉競溫。", "開卷不知雙淚墜，同時惟止一身存。", "尚欣儒雅風流在，今見吾交二葉親。"]'),
('4b780207-3620-4797-82e3-69dcd28d1906','觀燈','韓維','宋','宋诗','song-poetry','','[]','稻收禾熟廩囷盈，民俗熙熙鼓腹行。',64,'全唐诗/poet.song.25000.json','["稻收禾熟廩囷盈，民俗熙熙鼓腹行。", "萬點華燈雖不夜，十分芳酒是無明。", "齊人有本先循法，愛己何心欲更生。", "更有一機當妙悟，寥寥空外管弦聲。"]'),
('f2b9cd44-4c36-4165-938d-dcb12f68180f','寄范侍郎','韓維','宋','宋诗','song-poetry','','[]','行年八十幸安强，半在空門半醉鄉。',64,'全唐诗/poet.song.25000.json','["行年八十幸安强，半在空門半醉鄉。", "能保其身歸我里，閔勞以事荷吾皇。", "題詩遠寄幽棲地，開卷猶聞燕寢香。", "待得公來花未落，出游方駕酒同觴。"]'),
('70ff28e8-2c8b-4660-b13f-755b81c42e17','酬劉郎安孺慶八十','韓維','宋','宋诗','song-poetry','','[]','桂起安居濯了纓，結茅憑几坐忘情。',64,'全唐诗/poet.song.25000.json','["桂起安居濯了纓，結茅憑几坐忘情。", "行年及老漸仁德，終日爲歡盡孝誠。", "垂白退休承世範，紆朱列侍愧朝榮。", "近來捉得文章婿，陡覺吾門喜氣生。"]'),
('6bde55db-f3fe-449d-aa75-366c6f439cf8','答歐陽通直以予年八十見寄','韓維','宋','宋诗','song-poetry','','[]','人生七十古云稀，况復行年又十期。',64,'全唐诗/poet.song.25000.json','["人生七十古云稀，况復行年又十期。", "奕世未嘗欺暗室，全身又喜遇明時。", "消磨舊業憑黄卷，斷送餘光近玉卮。", "佳句祝延誠厚意，不忘交戒是吾師。"]'),
('4492c0e8-5d85-49e9-8e79-bfbf285e0834','仁宗皇帝挽歌三首  其一','韓維','宋','宋诗','song-poetry','','[]','遠俗長歸塞，中原不見兵。',48,'全唐诗/poet.song.25000.json','["遠俗長歸塞，中原不見兵。", "禮文興廢絕，刑典蹈寬平。", "慘動三危色，哀纏萬國情。", "新宮表仁號，堯德恐難名。"]'),
('9842a75c-cbdc-4d90-aa0f-5f8ddd9d1778','仁宗皇帝挽歌三首  其二','韓維','宋','宋诗','song-poetry','','[]','玉几宵登寢，靈衣晝入宮。',48,'全唐诗/poet.song.25000.json','["玉几宵登寢，靈衣晝入宮。", "追□□□□，□□□兒童。", "松柏三川路，旌旗十月風。", "龍髯攀才得，法泣抱遺弓。"]'),
('7f46fc28-4ee9-40b2-a881-182b1d74b4ae','仁宗皇帝挽歌三首  其三','韓維','宋','宋诗','song-poetry','','[]','丹扆中天坐，猶思玉色臨。',48,'全唐诗/poet.song.25000.json','["丹扆中天坐，猶思玉色臨。", "威神隨日遠，德澤在人深。", "謚定圜丘意，功傳清廟音。", "誰將良史筆，難狀志仁心。"]'),
('08bc7b65-d1fb-44be-a66f-9518013b5de2','曾太皇太后挽歌二首  其一','韓維','宋','宋诗','song-poetry','','[]','不宰功參帝，無疆道合坤。',48,'全唐诗/poet.song.25000.json','["不宰功參帝，無疆道合坤。", "簾帷保明辟，社稷付神孫。", "身蹈姜任德，心通黄老言。", "褒揚存手詔，奚仗史毫論。"]'),
('77b98cff-e766-455b-b056-db650bdf9420','曾太皇太后挽歌二首  其二','韓維','宋','宋诗','song-poetry','','[]','慶緒鍾王國，柔儀儷帝家。',48,'全唐诗/poet.song.25000.json','["慶緒鍾王國，柔儀儷帝家。", "仁深天與性，教盛月增華。", "海上黄金闕，人間素柰花。", "臣民懷慕意，猶冀返雲車。"]'),
('7f5981f3-9eaf-451d-b3fe-c90ee60960af','神宗皇帝挽歌三首  其一','韓維','宋','宋诗','song-poetry','','[]','立政追王體，修文邁古風。',48,'全唐诗/poet.song.25000.json','["立政追王體，修文邁古風。", "漢儀遵別廟，堂典備新宮。", "却號追前美，更元記屢豐。", "龍髯攀不得，號絕抱遺弓。"]'),
('e7585c06-b004-4964-9ed8-584471a5666c','神宗皇帝挽歌三首  其二','韓維','宋','宋诗','song-poetry','','[]','庠序尊儒術，梯航走德輝。',48,'全唐诗/poet.song.25000.json','["庠序尊儒術，梯航走德輝。", "玉龍何地駐，金雁不時飛。", "聖治歸簾幄，歡謳奉衮衣。", "未嗟軒御遠，猶仰百年威。"]'),
('684a59ea-5f20-4343-a53d-61121ad21455','神宗皇帝挽歌三首  其三','韓維','宋','宋诗','song-poetry','','[]','奧並商宗學，雄趨漢武才。',48,'全唐诗/poet.song.25000.json','["奧並商宗學，雄趨漢武才。", "難回九清駕，空湛萬年杯。", "旂旐翻風遠，簫韶度阪來。", "臣民仰遺像，血書有餘哀。"]'),
('a147194a-2246-4487-acea-c923e586596c','太皇太后挽歌二首  其一','韓維','宋','宋诗','song-poetry','','[]','沙麓開祥兆，河洲邁德風。',48,'全唐诗/poet.song.25000.json','["沙麓開祥兆，河洲邁德風。", "壯猷咨故老，柔道息諸戎。", "在己儀常損，於民惠少豐。", "誰持太史筆，善述九年功。"]'),
('b408dc96-cb3f-4ecf-85bd-2984e26928e1','太皇太后挽歌二首  其二','韓維','宋','宋诗','song-poetry','','[]','雲路回仙仗，簾帷閟玉音。',48,'全唐诗/poet.song.25000.json','["雲路回仙仗，簾帷閟玉音。", "詒孫爲後法，復辟是初心。", "教被宮庭肅，恩沾海宇深。", "常叨侍文陛，白首淚盈襟。"]'),
('8ee169c2-2300-4df8-b798-ed77fdcc357b','晏元獻公挽辭三首  其一','韓維','宋','宋诗','song-poetry','','[]','大策安宗社，高文著廟堂。',48,'全唐诗/poet.song.25000.json','["大策安宗社，高文著廟堂。", "從容造辟議，感激薦賢章。", "貂冕崇廞服，鑾輿俯奠觴。", "哀榮豈無有，公德倍輝光。"]'),
('addbd396-dd9c-4e4e-95d5-663f6eed25e6','晏元獻公挽辭三首  其二','韓維','宋','宋诗','song-poetry','','[]','先帝文章老，東朝羽翼臣。',48,'全唐诗/poet.song.25000.json','["先帝文章老，東朝羽翼臣。", "風流至公盡，哀憤與時均。", "簫鼓悲將曙，烟雲慘不春。", "靈輀歸舊治，遺愛泣州民。"]'),
('67f6dff7-ffe8-4d1d-922b-65d1d8e4b842','晏元獻公挽辭三首  其三','韓維','宋','宋诗','song-poetry','','[]','直道初終見，高情出處同。',48,'全唐诗/poet.song.25000.json','["直道初終見，高情出處同。", "光華兩朝內，文字一生中。", "愛酒憐陶散，言詩許賜通。", "平生知己類，灑盡九原風。"]'),
('b1b84dc3-d697-486d-9cb6-d140447bc3b6','司徒杜正獻公挽辭二首  其一','韓維','宋','宋诗','song-poetry','','[]','舊相論全德，當朝獨盛明。',48,'全唐诗/poet.song.25000.json','["舊相論全德，當朝獨盛明。", "一身清比玉，萬務倚如衡。", "正色排群枉，溫辭接後生。", "暫持禮官筆，無以大休聲。"]'),
('e9a6ad73-2df0-4aa6-818d-496466e7ecbb','司徒杜正獻公挽辭二首  其二','韓維','宋','宋诗','song-poetry','','[]','讜議開帷幄，仁風逐旆旟。',48,'全唐诗/poet.song.25000.json','["讜議開帷幄，仁風逐旆旟。", "生靈瞻用舍，賢俊入吹噓。", "去位猶憂國，終身不廢書。", "傳家無異物，惟挂舊安車。"]'),
('a9b39526-17dd-44e3-9441-e081f3d8d889','太傅李康靖公挽歌三首  其一','韓維','宋','宋诗','song-poetry','','[]','秉哲歸元老，宣忠輔至平。',48,'全唐诗/poet.song.25000.json','["秉哲歸元老，宣忠輔至平。", "四蕃流惠愛，三事頼謨明。", "國予哀榮備，人推壽寵并。", "紀言惇史在，猶足庇蒼生。"]'),
('5731a69e-a948-4ccb-b268-1e86c58fa8d1','太傅李康靖公挽歌三首  其二','韓維','宋','宋诗','song-poetry','','[]','知止冠早挂，娛閑金屢揮。',48,'全唐诗/poet.song.25000.json','["知止冠早挂，娛閑金屢揮。", "緒言猶在聽，英魄遽何歸。", "去國簫笳遠，迎風旌旐飛。", "邦人慰懷慕，餘慶在緇衣。"]'),
('df375d84-8d60-4c01-a8b3-3860b96d001a','太傅李康靖公挽歌三首  其三','韓維','宋','宋诗','song-poetry','','[]','烜赫三台責，優游二品終。',48,'全唐诗/poet.song.25000.json','["烜赫三台責，優游二品終。", "幹時身有盡，報國意無窮。", "事業傳青史，英靈峻紫嵩。", "輀車隔攀慟，悲淚灑秋風。"]'),
('6fa300ea-73c1-4fb5-960e-f5049e18bfad','中書令程文簡公挽辭二首  其一','韓維','宋','宋诗','song-poetry','','[]','謀猷國稱老，政事吏爲師。',48,'全唐诗/poet.song.25000.json','["謀猷國稱老，政事吏爲師。", "始卒君臣分，哀榮將相儀。", "行人看笳鼓，舊部泣旌旗。", "千載伊嵩路，蕭蕭隴樹悲。"]'),
('01a2ad53-a894-4ec3-8bd6-1e3e1f168cc5','中書令程文簡公挽辭二首  其二','韓維','宋','宋诗','song-poetry','','[]','政罷機衡後，功成屏翰間。',48,'全唐诗/poet.song.25000.json','["政罷機衡後，功成屏翰間。", "未聞持節召，俄見挽喪還。", "畫戟空留第，丹旌獨出關。", "忠勞不須問，宸篆揭碑顔。"]'),
('fce4061c-f06b-4665-aeb4-fa3d296e338b','宋元獻公挽辭三首  其一','韓維','宋','宋诗','song-poetry','','[]','先帝英雄彀，司空第一人。',48,'全唐诗/poet.song.25000.json','["先帝英雄彀，司空第一人。", "文章通日域，聲價重天倫。", "典策歸鴻筆，謀猷轉大均。", "欲知全盛美，華衮就安輪。"]'),
('4d22a628-b374-41a4-8724-937940c13567','宋元獻公挽辭三首  其二','韓維','宋','宋诗','song-poetry','','[]','儉是終身事，書無釋手時。',48,'全唐诗/poet.song.25000.json','["儉是終身事，書無釋手時。", "搯膺誰戒妾，易簀自呼兒。", "冠劍平生象，簫笳一品儀。", "邦人知所法，宸篆表忠規。"]'),
('6c0c9b97-c7d3-4917-82c5-70e96f265692','宋元獻公挽辭三首  其三','韓維','宋','宋诗','song-poetry','','[]','昔侍從容論，猶能記緒餘。',48,'全唐诗/poet.song.25000.json','["昔侍從容論，猶能記緒餘。", "精深義山句，妙絕漆園書。", "顧鈍嘗加礪，憐枯每借噓。", "霜風國西路，揮涕灑靈車。"]'),
('cdd15fad-bed3-4ef0-98d8-cda2b3da0300','僕射高文莊公挽辭三首  其一','韓維','宋','宋诗','song-poetry','','[]','群經分上下，大節凜終初。',48,'全唐诗/poet.song.25000.json','["群經分上下，大節凜終初。", "國仰謨猷在，人傳論議餘。", "藏家惟古器，納壙或奇書。", "儒者哀榮極，臨觴降玉輿。"]'),
('7ab78e37-f589-4a90-8ea1-50c9eb66de98','僕射高文莊公挽辭三首  其二','韓維','宋','宋诗','song-poetry','','[]','懇上畿庭印，來敷秘殿經。',48,'全唐诗/poet.song.25000.json','["懇上畿庭印，來敷秘殿經。", "退朝多謝客，隠几或忘形。", "道勝於生達，時窮與化冥。", "高談無復見，遺像泣丹青。"]'),
('ac684f33-3cf8-40f0-a2da-e08413ec8bda','僕射高文莊公挽辭三首  其三','韓維','宋','宋诗','song-poetry','','[]','未卒金華業，俄聞鹵簿行。',48,'全唐诗/poet.song.25000.json','["未卒金華業，俄聞鹵簿行。", "音容如夙昔，文雅是平生。", "偃蹇丹旌動，徘徊素驥鳴。", "霜風九京路，凄愴國人情。"]'),
('74d615db-77fb-43d2-8cab-7c833f1d82ff','王侍讀挽辭二首  其一','韓維','宋','宋诗','song-poetry','','[]','舊族人猶鳳，清班署冠鰲。',48,'全唐诗/poet.song.25000.json','["舊族人猶鳳，清班署冠鰲。", "法書傳隸古，才筆擬莊騷。", "贈印官稱寵，題旌謚典高。", "無由攀葬紼，佇立望行艘。"]'),
('09a8abf0-2dc7-4262-bfb1-d827f44206d3','王侍讀挽辭二首  其二','韓維','宋','宋诗','song-poetry','','[]','去日還鄉旆，今朝反葬車。',48,'全唐诗/poet.song.25000.json','["去日還鄉旆，今朝反葬車。", "露門虛近位，東觀束殘書。", "論議留臺閣，哀榮動里閭。", "始終稽古力，當代幾人如。"]'),
('3ea1a6cf-da1b-4a47-8192-290a47bfdfe0','鄧聖求挽詩二首  其一','韓維','宋','宋诗','song-poetry','','[]','南國丞旄士，西清對宿儒。',48,'全唐诗/poet.song.25000.json','["南國丞旄士，西清對宿儒。", "晚躋淹廟勝，速奪動宸吁。", "正色持風憲，嘉猷儼典謨。", "惟書仁者勇，傳世厲非夫。"]'),
('53b4f132-9d81-4556-be0d-c97515f65efc','鄧聖求挽詩二首  其二','韓維','宋','宋诗','song-poetry','','[]','鄉有先生號，朝多長者言。',48,'全唐诗/poet.song.25000.json','["鄉有先生號，朝多長者言。", "談經人服戴，辨獄世高袁。", "雨濕銘旌暗，風摇挽鐸喧。", "無緣攀葬紼，灑淚望秋原。"]'),
('b9948d6b-ac57-4112-8c9a-263123f37d6f','蘇才翁挽辭二首  其一','韓維','宋','宋诗','song-poetry','','[]','勛業經營內，賢豪許與中。',48,'全唐诗/poet.song.25000.json','["勛業經營內，賢豪許與中。", "遠圖宜將相，高論自兒童。", "名挂江雲白，魂歸楚樹紅。", "諸孤盡才秀，它日大門風。"]'),
('6bdd9645-385e-4f6a-9811-6e995e513921','蘇才翁挽辭二首  其二','韓維','宋','宋诗','song-poetry','','[]','奕世婚姻舊，平生昆弟游。',48,'全唐诗/poet.song.25000.json','["奕世婚姻舊，平生昆弟游。", "篇章每驚坐，談笑得忘憂。", "不復銜杯樂，空能助紼謳。", "凄凉篋中字，揮灑看銀鈎。"]'),
('e36041ca-869c-43e0-a934-0787f3742b80','哭蘇子美三首  其一','韓維','宋','宋诗','song-poetry','','[]','未起蛟龍卧，俄纏鵩鳥悲。',48,'全唐诗/poet.song.25000.json','["未起蛟龍卧，俄纏鵩鳥悲。", "寢門號故友，繐帳哭孤兒。", "業履歸輿議，銘文愧絕辭。", "滄浪亭下路，長負故人期。"]'),
('935da268-c5a9-4ac1-895c-98a144176d35','哭蘇子美三首  其二','韓維','宋','宋诗','song-poetry','','[]','魄動書流愴，誠通夢告悲。',48,'全唐诗/poet.song.25000.json','["魄動書流愴，誠通夢告悲。", "人生要有盡，君沒竟何施。", "白日空塵几，春風自酒卮。", "旅魂歸未得，藁葬近要離。"]'),
('b4bf634a-c2d8-475a-8d1c-436aeab42b5e','哭蘇子美三首  其三','韓維','宋','宋诗','song-poetry','','[]','才大終爲累，冤深豈復論。',48,'全唐诗/poet.song.25000.json','["才大終爲累，冤深豈復論。", "幾年流落恨，千里寂寥魂。", "功業初懷負，風流秀句存。", "英靈邈無所，灑淚望閶門。"]'),
('1cf7103b-9675-4c4e-8de4-6b4aa14b8f79','鄭公挽辭','韓維','宋','宋诗','song-poetry','','[]','兼才不廢刑名學，雅意多從翰墨遊。',64,'全唐诗/poet.song.25000.json','["兼才不廢刑名學，雅意多從翰墨遊。", "通德門中傳舊業，平蠻記上見佳謀。", "朝衣永閟泉臺夜，挽鐸猶添夢野秋。", "文彩聲名今不泯，郎官君聽在鰲頭。"]'),
('200e14dd-836a-4bcc-b0fc-03443c2aefaa','范蜀公挽辭二首  其一','韓維','宋','宋诗','song-poetry','','[]','正學躋經席，孤忠入諫垣。',48,'全唐诗/poet.song.25000.json','["正學躋經席，孤忠入諫垣。", "論儲十九疏，議樂數千言。", "勇去高門地，歸乘下澤轅。", "華顛不及用，遺恨滿丘樊。"]'),
('fb5fbe90-2f5c-4b3d-bbbc-55ae463a2fc6','范蜀公挽辭二首  其二','韓維','宋','宋诗','song-poetry','','[]','白圭絕玷成高節，古井無波見靜心。',64,'全唐诗/poet.song.25000.json','["白圭絕玷成高節，古井無波見靜心。", "朝廟肯隨時俯仰，閭閻寧與俗浮沉。", "新聲未及乘儀鳳，麗賦空餘擲地金。", "曾是南園預遊客，春風淚灑百花林。"]'),
('feb9da99-2d00-4cf3-aeca-6a43e5334afb','孫曼叔挽詞三首  其一','韓維','宋','宋诗','song-poetry','','[]','高才正論動朝紳，出入光華二十春。',64,'全唐诗/poet.song.25000.json','["高才正論動朝紳，出入光華二十春。", "褒詔未登新學士，恤章俄賁舊宮臣。", "履聲長絕高門地，墨妙空留素壁塵。", "一奠華觴不知慟，白頭相好苦無人。"]'),
('d7a1f9ee-11e0-42c5-be36-324ff192092c','孫曼叔挽詞三首  其二','韓維','宋','宋诗','song-poetry','','[]','定契仍三世，從游復一鄉。',48,'全唐诗/poet.song.25000.json','["定契仍三世，從游復一鄉。", "擲金看麗賦，報玉得雕章。", "不盡良哉用，空令識者傷。", "欲知恩禮重，恤視走銀璫。"]'),
('28d998fe-8bf2-41b7-926e-a57d27d592f2','孫曼叔挽詞三首  其三','韓維','宋','宋诗','song-poetry','','[]','青邸傳經罷，朱轓報政成。',48,'全唐诗/poet.song.25000.json','["青邸傳經罷，朱轓報政成。", "近民緣愷樂，致主出忠精。", "屢困清漳卧，終乘下澤行。", "衰年失良友，行泣望銘旌。"]'),
('c33f7b5c-7e85-441e-9b30-04f23b26e85e','中書傅欽之侍郎挽詞三首  其一','韓維','宋','宋诗','song-poetry','','[]','聖主方思助，皇天亦棐誠。',48,'全唐诗/poet.song.25000.json','["聖主方思助，皇天亦棐誠。", "屢空安可病，久困卒能亨。", "廊廟虛槐位，家園近柏城。", "聲名流不竭，長共濟時清。"]'),
('34b5727d-8f5c-48c6-98fb-b5aabc3f6c82','中書傅欽之侍郎挽詞三首  其二','韓維','宋','宋诗','song-poetry','','[]','久敬欽交舊，雍和浹弟昆。',48,'全唐诗/poet.song.25000.json','["久敬欽交舊，雍和浹弟昆。", "玉溫儒者行，矢直諫臣言。", "遽返生申魄，猶虛命說恩。", "只因爲善報，餘慶在高門。"]'),
('4ff96fd9-4a02-4a53-b3fc-9101cf18f784','中書傅欽之侍郎挽詞三首  其三','韓維','宋','宋诗','song-poetry','','[]','壯節淹鵬海，高年集鳳池。',48,'全唐诗/poet.song.25000.json','["壯節淹鵬海，高年集鳳池。", "謨猷未及展，簫鼓已成悲。", "經擿留天幄，書囊入殿帷。", "傷心濟源道，無復故人期。"]'),
('51ab0c7b-03c2-4304-b00b-af8e386ba677','謝師厚挽詞三首  其一','韓維','宋','宋诗','song-poetry','','[]','落筆無塵語，垂髫有俊聲。',48,'全唐诗/poet.song.25000.json','["落筆無塵語，垂髫有俊聲。", "人咨漢故事，坐屈魯諸生。", "道不緣貧病，心能處困亨。", "它年文苑傳，不愧著公明。"]'),
('d6ff6c7f-d199-4429-a28a-38eeea6a91bb','謝師厚挽詞三首  其二','韓維','宋','宋诗','song-poetry','','[]','論文滿樽酒，別恨幾筒詩。',48,'全唐诗/poet.song.25000.json','["論文滿樽酒，別恨幾筒詩。", "不謂相思久，終無一笑期。", "地卑傷賈誼，冢近得要離。", "尚有芝蘭秀，風流未覺衰。"]'),
('47544376-f070-4b2c-8e2d-f6881ac0b852','謝師厚挽詞三首  其三','韓維','宋','宋诗','song-poetry','','[]','幻有終何得，真空夙所歸。',48,'全唐诗/poet.song.25000.json','["幻有終何得，真空夙所歸。", "丘陵甘一跌，霄漢任群飛。", "妙墨嗟猶在，華觴不重揮。", "交親半零落，衰淚下沾衣。"]'),
('d99df852-6e15-4ea8-b4c3-47d7b8f7bf79','鄭閎中挽辭二首  其一','韓維','宋','宋诗','song-poetry','','[]','南宮平昔佐文衡，麗賦親聆擲地聲。',64,'全唐诗/poet.song.25000.json','["南宮平昔佐文衡，麗賦親聆擲地聲。", "群進士中連得雋，四先生裏舊知名。", "嚴凝□□來何暮，瀟灑安輿去已輕。", "萬里故鄉歸不得，要離冢畔有佳城。"]'),
('e0d5e7b4-0f15-4fa9-a506-e134308ebd66','鄭閎中挽辭二首  其二','韓維','宋','宋诗','song-poetry','','[]','守道貧原憲，傳經老伏生。',48,'全唐诗/poet.song.25000.json','["守道貧原憲，傳經老伏生。", "聲名徒自振，心慮淡無營。", "廢卷多懷古，銜杯靡吝情。", "思君最深處，始卒盡純誠。"]'),
('396370ef-6ce9-41de-bd86-6ded7c8e708f','王微之龍圖挽辭二首  其一','韓維','宋','宋诗','song-poetry','','[]','用舍時焉爾，窮通命也歟。',48,'全唐诗/poet.song.25000.json','["用舍時焉爾，窮通命也歟。", "石渠推舊德，王座閱新書。", "雪飲連揮斝，春遊每並輿。", "平生寢門淚，白首倍連茹。"]'),
('5d26a123-d62f-4e6b-8cee-d5ccede8211e','王微之龍圖挽辭二首  其二','韓維','宋','宋诗','song-poetry','','[]','高情夙慕冥鴻舉，晚節終隨倦鳥回。',64,'全唐诗/poet.song.25000.json','["高情夙慕冥鴻舉，晚節終隨倦鳥回。", "物外忘情常隠几，酒中得趣亦銜杯。", "每因誤曲煩周顧，幾廢言詩每鼎來。", "九十年齡隨化盡，所嗟不盡是君才。"]'),
('46755781-ac7f-4fff-a496-7cae5a5e2abc','馮當世挽詞二首  其一','韓維','宋','宋诗','song-poetry','','[]','名冠英雄彀，身參將相尊。',48,'全唐诗/poet.song.25000.json','["名冠英雄彀，身參將相尊。", "有客滄海量，無玷白圭言。", "密議調羹鼎，高懷寄酒樽。", "從今此中意，無復故人論。"]'),
('dd763bc5-7418-4274-ab3b-5dffc852f9c6','馮當世挽詞二首  其二','韓維','宋','宋诗','song-poetry','','[]','逍遥靈壽杖，嚴密具茨書。',48,'全唐诗/poet.song.25000.json','["逍遥靈壽杖，嚴密具茨書。", "脫屣遺浮世，披衣得舊廬。", "酹非光祿酒，祭乏武昌魚。", "禮薄情從厚，秋風淚滿裾。"]'),
('0b43f21c-4fa2-4ed5-8d4c-a156cb2c6c9f','哭曾令綽三首  其一','韓維','宋','宋诗','song-poetry','','[]','密勿論兵地，光華問俗車。',48,'全唐诗/poet.song.25000.json','["密勿論兵地，光華問俗車。", "嘉謀盡戎幕，惠澤浹民閭。", "語道多忘己，言詩屢起予。", "去思何以慰，遺像儼精廬。"]'),
('b652d85a-5746-430a-8b28-09ccbbfcd3c1','哭曾令綽三首  其二','韓維','宋','宋诗','song-poetry','','[]','典麗文章雅正躬，高才又出相門中。',64,'全唐诗/poet.song.25000.json','["典麗文章雅正躬，高才又出相門中。", "廟堂帝識精忠議，蕃服民歌愷悌風。", "一息不還成昨夢，六情都盡見真空。", "平時共說無生和，生死如今異與同。"]'),
('bd7d6389-7a52-4633-9969-e589fa20ff08','哭曾令綽三首  其三','韓維','宋','宋诗','song-poetry','','[]','飾館延歸馭，維舟結勝遊。',48,'全唐诗/poet.song.25000.json','["飾館延歸馭，維舟結勝遊。", "黄花頻採掇，白髪共淹留。", "預約歸田計，仍懷許國憂。", "斯言兩不遂，慟哭竟何尤。"]'),
('46005687-e10d-4d6d-a36f-e59c906d835f','毌沆挽辭二首  其一','韓維','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','早接英豪論，聞君伯仲賢。',48,'全唐诗/poet.song.25000.json','["早接英豪論，聞君伯仲賢。", "高談諸老屈，懿行一鄉傳。", "處順寧違俗，求歸不待年。", "終南山色好，長到酒樽前。"]'),
