('2010d58d-d588-4a6c-a2aa-24e806afa420','聯句','韓維','宋','宋诗','song-poetry','','[]','古木含清吹，池上增晚凉。',96,'全唐诗/poet.song.25000.json','["古木含清吹，池上增晚凉。", "余懷本達曠，聯此傲羲皇。", "孤鷗可與狎，幽岸足以觴。", "幸有彭澤酒，便同永嘉堂。", "潘生起爲壽，王子齊陳章。", "林端見新月，草際聞寒螿。", "照水螢影亂，拂筵蓼花香。", "徘徊戀嘉境，坐使歸興忘。"]'),
('b20fa90f-f0eb-4a87-abc6-ccf5c7637eed','金山寺','韓維','宋','宋诗','song-poetry','','[]','寶勢中流起，香園此布金。',36,'全唐诗/poet.song.25000.json','["寶勢中流起，香園此布金。", "鴿棲秋殿冷，龍伏夜潭深。", "水鳥銜生食，江神聽梵音。"]'),
('9615c899-f67c-4b97-8c9c-01a427a764a2','過杜甫墳','韓維','宋','宋诗','song-poetry','','[]','三尺孤墳墓，空留萬古名。',48,'全唐诗/poet.song.25000.json','["三尺孤墳墓，空留萬古名。", "風騷誰是主，天地太無情。", "入夜月虛白，逢春草自生。", "耒陽江色迥，吊罷恨難平。"]'),
('7a0d9530-11b5-4ae9-aa3b-2659971fbde9','潤州','韓維','宋','宋诗','song-poetry','','[]','雄風摇碧綠，畫角吊黄昏。',24,'全唐诗/poet.song.25000.json','["雄風摇碧綠，畫角吊黄昏。", "一带分江記，雙峰點海門。"]'),
('d1e8ed26-56cc-42af-adb2-aba5c67301f9','詩一首','韓維','宋','宋诗','song-poetry','','[]','鶴使曉來華表上，分明說得帝都春。',32,'全唐诗/poet.song.25000.json','["鶴使曉來華表上，分明說得帝都春。", "門開閶闔星河在，榜注神仙姓字新。"]'),
('3cda56d8-7915-472f-914d-3c1b8a629e51','題招提院靜照堂','韓維','宋','宋诗','song-poetry','','[]','道人幽棲地，瀟灑臨江湖。',72,'全唐诗/poet.song.25000.json','["道人幽棲地，瀟灑臨江湖。", "江湖置外物，妙觀造無餘。", "匆匆從世役，沒沒已爲愚。", "何况毫髪間，計畫窮萬殊。", "檻外薝蔔林，几前沈水爐。", "世人欲問道，指象聊躊躕。"]'),
('4c617ec5-5ed2-4568-b2e9-1247464e9507','窊樽','韓維','宋','宋诗','song-poetry','','[]','閑坐閑行水際，自吟自嘯雲根。',28,'全唐诗/poet.song.25000.json','["閑坐閑行水際，自吟自嘯雲根。", "過盡春風秋月，無人共醉窊樽。"]'),
('92e01888-8cbf-456c-8fe8-698511307b2b','送回聖過洞清會','韓維','宋','宋诗','song-poetry','','[]','狂飈攪驚塵，□□□□□。',84,'全唐诗/poet.song.25000.json','["狂飈攪驚塵，□□□□□。", "支生强我遊，華構忽在暇。", "入門已□□，□□□且况。", "主人道門老，興趣久已炎。", "□□□□□，□□有清泛。", "沖融一境寂，□□□□□。", "□□□□□，竹日光艷艷。"]'),
('39e58378-5ad2-4479-9c50-6598ad900f54','和鄰幾社日','韓維','宋','宋诗','song-poetry','','[]','春陽□□□，□□□□□。',84,'全唐诗/poet.song.25000.json','["春陽□□□，□□□□□。", "□□□流光，連坐嘆故園。", "遊□□□□，□□□□□。", "擊鼓會鄉人，莫觴爲曰□。", "□□□□□，□□割肉歸。", "獨我恨不與，京塵空□□。", "□□□時驚，先入舊廬飛。"]'),
('133b9413-9392-4da3-a0f0-62408083a7dc','句  其一','韓維','宋','宋诗','song-poetry','','[]','兩君曠度皆吾黨，紅燭迎舟盡醉還。',16,'全唐诗/poet.song.25000.json','["兩君曠度皆吾黨，紅燭迎舟盡醉還。"]'),
