('80ab3dae-f9ac-433a-a6e6-81af16846467','句  其四','韓維','宋','宋诗','song-poetry','','[]','日華川上動，風光草際浮。',12,'全唐诗/poet.song.25000.json','["日華川上動，風光草際浮。"]'),
('b7807fc6-003c-43d9-a509-af464a490dba','句  其五','韓維','宋','宋诗','song-poetry','','[]','一笛西風吹落日，滿帆行客背孤城。',16,'全唐诗/poet.song.25000.json','["一笛西風吹落日，滿帆行客背孤城。"]'),
('ecc8d639-e468-4707-bcb6-4f8389964698','句','柳瑾','宋','宋诗','song-poetry','','[]','過盡金湯知帝策，見求貂虎識軍儀。',32,'全唐诗/poet.song.25000.json','["過盡金湯知帝策，見求貂虎識軍儀。", "男兒本有四方志，祗在蓬瀛自不知。"]'),
('e062ecca-b755-4955-9b78-8c9f61dd54ec','題餘干縣干越亭','李孝先','宋','宋诗','song-poetry','','[]','吳越猶干地要衝，樹亭危岸勢憑空。',64,'全唐诗/poet.song.25000.json','["吳越猶干地要衝，樹亭危岸勢憑空。", "春潭倒影黄昏月，古木喧聲白晝風。", "鷗鷺慣來窺讌席，烟雲無著護簾櫳。", "凄凉故國多遷變，獨有溪山在望中。"]'),
('825d93b4-c13a-4c2c-9f92-9e558b5e7f9a','登江瀆水心亭','李孝先','宋','宋诗','song-poetry','','[]','晚興清無比，幽亭積水中。',48,'全唐诗/poet.song.25000.json','["晚興清無比，幽亭積水中。", "芰荷千柄雨，松竹四軒風。", "鬥鴨飛翎健，潛魚靜思沖。", "飛潛乃常事，何足較窮通。"]'),
('ee9e628b-f67c-4cdb-a6d8-358a598bfc89','春日有感','李孝先','宋','宋诗','song-poetry','','[]','雨斂輕寒淑氣回，曉街清霽斷浮埃。',64,'全唐诗/poet.song.25000.json','["雨斂輕寒淑氣回，曉街清霽斷浮埃。", "風高柳倦終朝舞，歲閏花遲數日開。", "歸夢每逾千里去，遠書新過萬山來。", "旅情宦况都無頼，强對韶輝殢酒杯。"]'),
('5b4fb002-f33f-440e-b728-244feb5a5c5b','句','倪天隠','宋','宋诗','song-poetry','','[]','物外風塵不染顔。',8,'全唐诗/poet.song.25000.json','["物外風塵不染顔。"]'),
('29c64e4b-de55-40d0-885b-2c5f2a547175','留題洞巖','宋禧','宋','宋诗','song-poetry','','[]','翠巖仙洞白雲深，躡石捫蘿一訪尋。',32,'全唐诗/poet.song.25000.json','["翠巖仙洞白雲深，躡石捫蘿一訪尋。", "真馭不逢山色映，澗風吹袂冷森森。"]'),
('9345b85f-7727-42fb-9124-161c67d49af1','巡歷屬部留題青帝觀','宋禧','宋','宋诗','song-poetry','','[]','按部到天孫，因過清靜軒。',48,'全唐诗/poet.song.25000.json','["按部到天孫，因過清靜軒。", "山尖覆雲蓋，石罅迸松根。", "危磴關河路，遠林桑柘村。", "閑邀羽人話，洞究五千言。"]'),
('4c1dad4c-92c4-4258-b525-4bbd59cc8d2c','手植檜','孔舜亮','宋','宋诗','song-poetry','','[]','聖人嘉異種，移對誦弦堂。',240,'全唐诗/poet.song.25000.json','["聖人嘉異種，移對誦弦堂。", "雙本無今古，千年任雪霜。", "右旋符地順，左紐象乾綱。", "影覆詩書府，根盤禮義鄉。", "盛同文不朽，高與道相當。", "洙泗滋榮茂，龜蒙借鬰蒼。", "毓靈全木帝，鍾秀極勾芒。", "氣爽群居席，烟凝數仞牆。", "陰連槐市綠，子落杏壇香。", "布露周千尺，騰凌上百常。", "傍欺泮林小，遠笑嶧桐黄。", "屹若擎天柱，森如出日桑。", "風中雕虎嘯，雲際老龍驤。", "直欲驚魑魅，端疑待鳳凰。", "鱗差闕鞏甲，幹錯羽林槍。", "大節忠臣概，堅心志士方。", "魯宮侵不得，秦火縱何傷。", "宣子休誇樹，姬人漫愛堂。", "松卑虛視爵，花賤柱封王。", "誰念真儒迹，何當議寵章。"]'),
('040d9772-b5b2-4336-84f8-7a24f378dc45','題靈巖寺','孔舜思','宋','宋诗','song-poetry','','[]','忽從平地出塵籠，親到諸天釋梵宮。',96,'全唐诗/poet.song.25000.json','["忽從平地出塵籠，親到諸天釋梵宮。", "却悟冗官長役物，爭如大士日談空。", "山橫青壁千層合，泉迸丹崖一綫通。", "幽鳥靜啼人外境，疏鐘不墮世間風。", "目無可欲猿猱伏，心絕微塵冰鑑融。", "自恨無緣陪宴坐，它生願效種松翁。"]'),
('55132483-4ede-449d-a6ff-c76660c64af6','華清懷古  其一','李周','宋','宋诗','song-poetry','','[]','胡雛鐵騎正縱橫，環上羅衣血染腥。',32,'全唐诗/poet.song.25000.json','["胡雛鐵騎正縱橫，環上羅衣血染腥。", "蜀道歸來應悔禍，香囊特地泣娉婷。"]'),
('456fc12d-4d81-4d18-a26c-a243a238181c','華清懷古  其二','李周','宋','宋诗','song-poetry','','[]','吾家居處本關西，舊記遺蹤事不迷。',32,'全唐诗/poet.song.25000.json','["吾家居處本關西，舊記遺蹤事不迷。", "屢過華清無一字，恐人笑我不留題。"]'),
('e7499181-34ea-4362-910f-642a25cda3f8','雙檜聯句','李周','宋','宋诗','song-poetry','','[]','古宇列雙檜，森鬰欹檐角。',192,'全唐诗/poet.song.25000.json','["古宇列雙檜，森鬰欹檐角。", "高幹若偃蓋，低枝羅翠幄。", "葉硬攢猬毛，子圓如雀殻。", "盤根雖輪囷，呈才終卓犖。", "枯冬傲霜雪，炎夏宜雨雹。", "蒼皮繞龍蛇，危巔巢鸑鷟。", "歲寒知後凋，清風到先覺。", "月涵煙影孤，雨溜苔蘚駁。", "願逢繁輅用，勿使爲榱桷。", "春姿筆工偷，風韵溪虎學。", "松筠比節操，蟲鳥敢蠹啄。", "黛色晚山分，清香朝露濯。", "桃李耻妖饒，椅梧羞齷齪。", "俗名强雌雄，奇勝重古樸。", "氣勢已千尋，栽培從一握。", "五松慚忝位，秦封受殊渥。"]'),
('a289fa54-ff84-4a52-8938-0fc607fbe525','雙檜聯句','李邵','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.25000.json','["無正文。"]'),
('37f64647-09af-45da-aa76-99b85fcdbdfb','雙檜聯句','楊致祥','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.25000.json','["無正文。"]'),
('6775ca09-6e2b-4232-a2ad-012a9e3df9a2','雙檜聯句','种古','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.25000.json','["無正文。"]'),
('75bb4510-9e2c-468b-90d5-f912a020dca3','雙檜聯句','种診','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.25000.json','["無正文。"]'),
('1e3cfc6a-4680-4e02-97e3-68b1df1453a7','寄茅處士知至','鄭少連','宋','宋诗','song-poetry','','[]','世爭趨捷徑，君獨掩柴關。',48,'全唐诗/poet.song.25000.json','["世爭趨捷徑，君獨掩柴關。", "名利紅塵老，詩書白日閑。", "情恬神氣逸，琴淡古風還。", "誰識冥冥意，軒裳咳唾間。"]'),
('c9fe3bf0-291a-4d8c-aac5-b8b5fcb0197e','句  其一','史驤','宋','宋诗','song-poetry','','[]','坐來夜半天河轉，挑盡寒燈心自知。',16,'全唐诗/poet.song.25000.json','["坐來夜半天河轉，挑盡寒燈心自知。"]'),
