('63bc8f98-18a0-4b5e-a3c7-b2d13d5eb366','句  其一','崔子厚','宋','宋诗','song-poetry','','[]','興盡回蘭棹。',6,'全唐诗/poet.song.25000.json','["興盡回蘭棹。"]'),
('c60f2b15-f09f-4845-86b1-8b5fc894ab6a','句  其二','崔子厚','宋','宋诗','song-poetry','','[]','衣錦榮名雖烜赫，挂冠高節莫因循。',16,'全唐诗/poet.song.25000.json','["衣錦榮名雖烜赫，挂冠高節莫因循。"]'),
('03e4b7df-1c56-4ecb-b5a5-108ede103afc','和陳襄巖老堂','徐融','宋','宋诗','song-poetry','','[]','大老富詩書，不煩耕與漁。',48,'全唐诗/poet.song.25000.json','["大老富詩書，不煩耕與漁。", "巖同傅說築，人學仲尼居。", "靜性觀三極，窮神味六虛。", "欲知休復意，仁義是蘧廬。"]'),
('1b0abc66-cd8c-4c49-835b-3558c0fd0b6a','句','徐融','宋','宋诗','song-poetry','','[]','淮船分蟻點，江市聚蠅聲。',12,'全唐诗/poet.song.25000.json','["淮船分蟻點，江市聚蠅聲。"]'),
('4f8e16d7-153d-44ce-9b7d-f265d67b2792','秦王卷衣','文同','宋','宋诗','song-poetry','','[]','咸陽秦王家，宮闕明曉霞。',120,'全唐诗/poet.song.25000.json','["咸陽秦王家，宮闕明曉霞。", "丹文映碧鏤，光采相鈎加。", "銅螭逐銀猊，壓屋矜蟠拏。", "洞戶鎖日月，其中光景賒。", "春風動珠箔，鸞額金窠斜。", "美人却扇坐，羞落庭下花。", "閑弄玉指環，輕冰扼紅牙。", "君王顧之笑，爲駐七寶車。", "自卷金縷衣，龍鸞蔚紛葩。", "持以贈所愛，結歡期無涯。"]'),
('88102452-30ce-4d3a-aadf-9f80837eaefe','殿前生桂樹','文同','宋','宋诗','song-poetry','','[]','童童彼芳桂，藹藹生廣內。',48,'全唐诗/poet.song.25000.json','["童童彼芳桂，藹藹生廣內。", "靈根浹和液，柯葉冬不改。", "日月最臨照，雨露偏汪濊。", "願保剛勁質，與君同萬歲。"]'),
('87044380-6e51-4b51-944a-a382f5cadf49','臨高臺','文同','宋','宋诗','song-poetry','','[]','臨高臺，望故鄉。',40,'全唐诗/poet.song.25000.json','["臨高臺，望故鄉。", "地千里，天一方。", "極目外，空茫茫。", "孤雲飛，不我將。", "安得羽翼西南翔。"]'),
('23699fcb-8def-47a7-9cb9-4baaf7725dc9','自君之出矣','文同','宋','宋诗','song-poetry','','[]','自君之出矣，弔影度晨夕。',48,'全唐诗/poet.song.25000.json','["自君之出矣，弔影度晨夕。", "中門一步地，未省有行迹。", "閨闈足儀檢，常恐犯繩尺。", "欲寄錦字書，知誰者云的。"]'),
('5e8db6db-34c3-412e-a032-f20d4a7b2c4a','東門行','文同','宋','宋诗','song-poetry','','[]','士有失所偶，難甘蓬蓽微。',60,'全唐诗/poet.song.25000.json','["士有失所偶，難甘蓬蓽微。", "拔劍出東門，感憤不顧歸。", "賢哉彼嘉匹，逐逐牽其衣。", "願同此饘粥，節義安得違。", "况今謂清世，不可復爲非。"]'),
('687db259-55f4-4065-bfd5-abe99a8334e4','西門行','文同','宋','宋诗','song-poetry','','[]','盛年可愛重，芳辰宜嬉遊。',72,'全唐诗/poet.song.25000.json','["盛年可愛重，芳辰宜嬉遊。", "金甕釀醇酒，玉盤炙肥牛。", "青春九十日，不可一日休。", "勿自汨浩氣，滿胸藏百憂。", "君莫惜黄金，黄金身後讎。", "自古貪與吝，常爲賢者羞。"]'),
('195de7a4-9261-49eb-b5f2-7c47768b8f27','塘上行','文同','宋','宋诗','song-poetry','','[]','寒塘漲新雨，灧灧翠波滿。',60,'全唐诗/poet.song.25000.json','["寒塘漲新雨，灧灧翠波滿。", "沙晴步聲澀，風引羅带緩。", "蒲牙妒舌利，荷葉歡心卷。", "生平玉衣夢，至此神亦誕。", "徒誦小星篇，無人覺腸斷。"]'),
('b7700455-73ae-439e-af33-893c54def11c','釣竿','文同','宋','宋诗','song-poetry','','[]','霜刀裁綠筠，桂餌挂輕緡。',48,'全唐诗/poet.song.25000.json','["霜刀裁綠筠，桂餌挂輕緡。", "斂迹天地間，側身江海濱。", "悠悠寶帳夜，寂寂烟波春。", "何時投竿歸，再與君子親。"]'),
('c0b5e460-ae24-42df-80d1-24cd837fbcf9','烏生八九子','文同','宋','宋诗','song-poetry','','[]','南山有烏鳥，生子層崖巔。',120,'全唐诗/poet.song.25000.json','["南山有烏鳥，生子層崖巔。", "戢戢新羽成，相將弄晴烟。", "朝饑集壠上，暮渴來巖前。", "託居深林中，自足終爾年。", "胡爲去所依，無乃甘葉捐。", "却愛庭樹好，群飛投碧圓。", "高枝踏未穩，身已隨潛弦。", "因知萬物理，主者持默權。", "凡云愛此命，生死期已然。", "出入既有定，何嘆于後先。"]'),
('4ccfe964-d1bb-40cd-aa87-777f7a6ba120','野田黄雀行','文同','宋','宋诗','song-poetry','','[]','搥鼉鏗鯨宴瑶臺，紅鴉弄翼春徘徊。',96,'全唐诗/poet.song.25000.json','["搥鼉鏗鯨宴瑶臺，紅鴉弄翼春徘徊。", "和風入坐賓主樂，金觥玉豆天中來。", "勸君劇飲莫自訴，暗中光景能相催。", "試看庭前好花謝，枝下落多枝上開。", "人生不厭苦行樂，勿用蹙促相驚猜。", "賢愚貴賤各有命，此理悟者真賢哉。"]'),
('833ddba1-7228-44da-b71f-034dfcf29608','苦寒行','文同','宋','宋诗','song-poetry','','[]','上太行兮高盤盤，日將暮兮歲已闌。',96,'全唐诗/poet.song.25000.json','["上太行兮高盤盤，日將暮兮歲已闌。", "入谷口兮出林端，風慘慘兮吹骨寒。", "冰霜結兮玉巑岏，光上照兮天色乾。", "紛橫委兮草樹殘，黯慄烈兮烟雲𩆓。", "僕足皸兮馬蹄抏，望所舍兮摧心肝。", "囊立空兮衣且單，嗟道途兮胡艱難。"]'),
('6fddabbe-e0fc-45ec-b868-ba065081ab03','苦熱行','文同','宋','宋诗','song-poetry','','[]','黄人頓駕留天中，金鴉吐火燒碧空。',64,'全唐诗/poet.song.25000.json','["黄人頓駕留天中，金鴉吐火燒碧空。", "炎光染雲聳岌岌，旱氣爍土飛蓬蓬。", "龍摇乾胡不作雨，虎裂渴吻無生風。", "安得有術擘海水，入底一扣鮫人宮。"]'),
('3f45b15f-2cb9-48de-b8e3-58c8b5c0d1ec','俠客行','文同','宋','宋诗','song-poetry','','[]','紫髯圍碧瞳，勇氣炙坐熱。',96,'全唐诗/poet.song.25000.json','["紫髯圍碧瞳，勇氣炙坐熱。", "生平脫羈檢，少小服義烈。", "堂堂吐高論，牙齒若嚼鐵。", "寶劍壓䏶橫，誰耻我可雪。", "酣歌入都市，當面洗人血。", "常言荆軻愚，每笑豫讓拙。", "事已不受謝，門前車馬絕。", "自謂取功名，焉能由筆舌。"]'),
('57e9df86-0b26-40cc-9c50-b7a7e813ab1f','巫山高','文同','宋','宋诗','song-poetry','','[]','巫山高，高凝烟，十二碧簪寒插天。',114,'全唐诗/poet.song.25000.json','["巫山高，高凝烟，十二碧簪寒插天。", "危巖絕壁已飛動，况復下壓萬丈之蒼淵。", "波衝浪激作深井，虎眼徹底時一漩。", "長風澒涌發灧澦，惡色怒勢因誰然。", "我欲截中流，虹梁莫得施𧐖蜷。", "東西相遠望不到，兩目欲斷心將穿。", "回看高唐廟下灑靈雨，遣我歸意常翩翩。"]'),
('8309139d-171f-4466-ad16-0df6ef09d019','水仙操','文同','宋','宋诗','song-poetry','','[]','嗟哉先生去何所兮，杳不可尋。',126,'全唐诗/poet.song.25000.json','["嗟哉先生去何所兮，杳不可尋。", "捨我於此使形影之外兮，唯莽蒼之山林。", "仰圓嶠之峨峨兮，俯大壑之沉沉。", "長波澒涌以蕩潏兮，群鳥翻翻而悲吟。", "寂擾擾之煩慮兮，納冥冥之至音。", "先生將一我之正性兮，何設意之此深。", "我已窮神而造妙兮，達真指於素琴。", "先生盍還此兮，度明明乎我心。"]'),
('5abac7de-dc2c-454b-b866-fa5520c5e243','大垂手','文同','宋','宋诗','song-poetry','','[]','華堂合樂轟春晝，鳳叫龍嘶畫鼉吼。',104,'全唐诗/poet.song.25000.json','["華堂合樂轟春晝，鳳叫龍嘶畫鼉吼。", "瓊猊壓地開組繡，美人舞兮獻君壽。", "紅婆娑兮翠蚴蟉，雪翻花兮風入柳。", "曳輕裾兮揚綵綬，金鸞飛兮玉麟走。", "入急破，大垂手。", "香檀扎扎江雨驟，情凝力定方舉袖。", "烟收霧斂曲徹後，錦盈車兮珠滿斗。"]'),
('07ce97a0-fea1-457d-b28f-b9c12dc6476a','採蓮曲','文同','宋','宋诗','song-poetry','','[]','綠纈襠，紅繡裳，衫盤蜂蝶裙鴛鴦。',160,'全唐诗/poet.song.25000.json','["綠纈襠，紅繡裳，衫盤蜂蝶裙鴛鴦。", "雕瑰錯寶垂鬢長，紫冒翠蓋行新粧。", "蹁躚曲堤下回塘，畫橈送入波中央。", "羅袖卷起金釧光，摇輕撼脆敲短芒。", "丹瓊紺玉低復昂，霑裛薄粉撲嫩黄。", "蠶腰蛛腹絲飄揚，列坐綵舫求比方。", "笑聲吃吃動明璫，挨蒲拂蓼次岸旁。", "風吹落霞供晚凉，西城鴉鴉啼女牆。", "歸來索酒酌滿觴，吳屏蜀帳圍象床。", "困卧不起燈燭張，琉璃盎缶叢生香。"]'),
('ebde84fc-f76f-4ee8-bdf9-0bd360514593','對酒','文同','宋','宋诗','song-poetry','','[]','朝廷皦如日，區宇清若水。',96,'全唐诗/poet.song.25000.json','["朝廷皦如日，區宇清若水。", "殊方文教達，微品德澤被。", "伊人復何幸，遇此栗陸氏。", "茫然大虛內，蒸鬰盡和氣。", "真風浹敦俗，無所容一僞。", "唯宜對樽酒，酣飲樂無事。", "人間此昭世，得偶須自貴。", "無爲名所勞，區區取愚謚。"]'),
('144b1a26-37b2-47df-b731-904276bc7986','白頭吟','文同','宋','宋诗','song-poetry','','[]','憶昔宴華堂，金徽導幽意。',72,'全唐诗/poet.song.25000.json','["憶昔宴華堂，金徽導幽意。", "雖知取名賤，越禮奉君子。", "相期本同穴，誰復耻犢鼻。", "一見茂陵人，烟霄與泥滓。", "願言保新愛，妾以甘自棄。", "恩義薄所終，多生於富貴。"]'),
('13da612a-9292-4f31-83ab-82c312630f83','芳樹','文同','宋','宋诗','song-poetry','','[]','庭前有芳樹，穠陰滿軒碧。',48,'全唐诗/poet.song.25000.json','["庭前有芳樹，穠陰滿軒碧。", "莫惜更携酒，醉此青春色。", "朝來見鶗鴂，飛鳴繞其側。", "光景不可留，徒遣君嘆息。"]'),
('eb129697-c8d1-47cb-9512-ca524291ac90','武溪深','文同','宋','宋诗','song-poetry','','[]','嶠南之武溪，其深不能測。',96,'全唐诗/poet.song.25000.json','["嶠南之武溪，其深不能測。", "潭潭滀瘴癘，水色重如墨。", "昏然潦霧作，上下毒氣塞。", "仰視高飛鳶，跕跕墮兩翼。", "交州惡女子，制馭費銜勒。", "伊余繆兵寄，得總浪泊役。", "常甘馬革死，持此期報國。", "卧念少游言，從之何可得。"]'),
('d6b66e10-45a2-4789-91a2-88364a390a74','走馬引','文同','宋','宋诗','song-poetry','','[]','群蹄踏空山，半夜若風雨。',72,'全唐诗/poet.song.25000.json','["群蹄踏空山，半夜若風雨。", "平明即其地，已復天上去。", "惟予迫大義，盍免以名捕。", "蟠蝸入寒殻，此豈謂安處。", "脫身入浩渺，固有神物護。", "禮謂不戴天，天知天亦許。"]'),
('2510cf72-3c60-4d69-9b52-9aad1089c534','起夜來','文同','宋','宋诗','song-poetry','','[]','曉窗明綠紗，蜀錦壓春卧。',48,'全唐诗/poet.song.25000.json','["曉窗明綠紗，蜀錦壓春卧。", "橫腮虎魄冷，驚起新夢破。", "玲瓏轉條脫，縹緲梳矮墮。", "高軸響銀床，時誤君車過。"]'),
('2739ac2c-a397-45fe-8523-2f6504f5c447','長安道','文同','宋','宋诗','song-poetry','','[]','長安道，隋唐宮殿生秋草。',28,'全唐诗/poet.song.25000.json','["長安道，隋唐宮殿生秋草。", "若使皆知嗣業難，爭得行人望中老。"]'),
('8f9124c5-6571-4ae1-abe0-a587e4f1ce7e','王昭君  其一','文同','宋','宋诗','song-poetry','','[]','不惜將黄金，爭頭買顔色。',24,'全唐诗/poet.song.25000.json','["不惜將黄金，爭頭買顔色。", "妾貌自可恃，誰能苦勞力。"]'),
('17b28e4c-0a2d-4139-a697-8d2ba98103b2','王昭君  其二','文同','宋','宋诗','song-poetry','','[]','絕艷生殊域，芳年入內庭。',24,'全唐诗/poet.song.25000.json','["絕艷生殊域，芳年入內庭。", "誰知金屋寵，只是信丹青。"]'),
('c294abfd-4c33-41d5-ac71-ff687f3bfe45','王昭君  其三','文同','宋','宋诗','song-poetry','','[]','幾歲後宮塵，今朝絕國春。',24,'全唐诗/poet.song.25000.json','["幾歲後宮塵，今朝絕國春。", "君王重恩信，不欲遣他人。"]'),
('290f727a-3c29-4f60-bc7a-29866be1c604','王昭君  其四','文同','宋','宋诗','song-poetry','','[]','極目胡沙滿，傷心漢月圓。',24,'全唐诗/poet.song.25000.json','["極目胡沙滿，傷心漢月圓。", "一生埋沒恨，長入四條弦。"]'),
('bd6d3e1f-fac3-4ee6-a4de-040ed4fb2de6','吳趨曲  其一','文同','宋','宋诗','song-poetry','','[]','萬頃平湖水，晴光射早霞。',24,'全唐诗/poet.song.25000.json','["萬頃平湖水，晴光射早霞。", "紅裙鬥畫楫，相結採荷花。"]'),
('2291cfc3-39fc-407c-a40c-3a20d33bac79','吳趨曲  其二','文同','宋','宋诗','song-poetry','','[]','岸上相將疊鼓催，青翰齊上碧波開。',32,'全唐诗/poet.song.25000.json','["岸上相將疊鼓催，青翰齊上碧波開。", "鵁鶄屬鳿不驚起，慣見蘭橈日日來。"]'),
('aec0f8ca-be0e-4571-89c8-ed7f37146500','吳趨曲  其三','文同','宋','宋诗','song-poetry','','[]','蕩漾水中舟，徘徊岸邊馬。',24,'全唐诗/poet.song.25000.json','["蕩漾水中舟，徘徊岸邊馬。", "相看兩不語，密意待誰寫。"]'),
('bd88eaa7-f737-42cb-a39f-02dd99333df4','劉生','文同','宋','宋诗','song-poetry','','[]','歷古推任俠，彼劉生者何。',48,'全唐诗/poet.song.25000.json','["歷古推任俠，彼劉生者何。", "提槌擊朱亥，引劍刺荆軻。", "飲肆扶頭出，歌樓掉臂過。", "無人繼義勇，關隴氣消磨。"]'),
('a0ba7e01-645b-4878-8fec-c2f11a3a17c7','紫騮馬','文同','宋','宋诗','song-poetry','','[]','翩翩紫騮馬，爛爛黄金鞍。',48,'全唐诗/poet.song.25000.json','["翩翩紫騮馬，爛爛黄金鞍。", "流水四蹄急，飛星雙目寒。", "擁頭青玉釳，蔽臆彩絲鞶。", "誰取交州鼓，摸將骨去看。"]'),
('bb7c3e31-193b-439c-a3ff-e2c4ba1a4ad8','驄馬','文同','宋','宋诗','song-poetry','','[]','𮫃鬣擁如雲，西人號乞銀。',24,'全唐诗/poet.song.25000.json','["𮫃鬣擁如雲，西人號乞銀。", "更逢桓御史，特地起精神。"]'),
('15db90bd-26c2-4963-99e3-cccc0f54a25f','貴侯行','文同','宋','宋诗','song-poetry','','[]','將軍功勳滿旂常，昨日賜對開明光。',64,'全唐诗/poet.song.25000.json','["將軍功勳滿旂常，昨日賜對開明光。", "腰懸橐駝紫金鈕，爵號進拜諸侯王。", "戟衣翩翩弄春影，大第高門臨萬井。", "但願囊書絕邊警，常官中都奉朝請。"]'),
('98d646a8-17ba-496d-9640-7fbd860693e4','朱櫻歌','文同','宋','宋诗','song-poetry','','[]','金衣珍禽弄深樾，禁籞朱櫻斑若纈。',64,'全唐诗/poet.song.25000.json','["金衣珍禽弄深樾，禁籞朱櫻斑若纈。", "上幸離宮促薦新，藤籃寶籠貂璫發。", "凝霞作丸珠尚軟，油露成津蜜初割。", "君王日午坐猗蘭，翡翠一盤紅靺鞨。"]'),
('642e78fd-11f5-4a9a-8cbd-54a698fcb798','拾羽曲','文同','宋','宋诗','song-poetry','','[]','新羅砑紅裙襵齊，綵縷刺衫花倒提。',64,'全唐诗/poet.song.25000.json','["新羅砑紅裙襵齊，綵縷刺衫花倒提。", "新晴暖日麗烟草，金獸齧鎖藏春閨。", "朱橋逼江曉沙白，錦带交風大堤窄。", "蘭洲遺翎得殘碧，歸來驚飛上嬌額。"]'),
('573739fc-5ec3-47c6-9aef-de0919ad96c4','沙堤行','文同','宋','宋诗','song-poetry','','[]','金吾馳騎東復西，督兵萬指平沙堤。',160,'全唐诗/poet.song.25000.json','["金吾馳騎東復西，督兵萬指平沙堤。", "傳言築路拜新相，恐與九衢同一泥。", "夜來上在蓬萊宿，手寫姓名符夢卜。", "連詔黄門下北扉，趣草贊辭登力牧。", "平明劍珮羅東閣，大字滿行書德業。", "謁者長言告紫宸，感召一庭和氣合。", "上心喜曰予良弼，未謝急宣令直筆。", "群吏迎歸政事堂，指顧之間歌畫一。", "午漏初移催入馬，寶带盤腰印垂胯。", "歸來冠蓋爛盈門，異口同音賀太平。"]'),
('e90f7401-b6ab-47fd-b624-ca690fab9562','五原行','文同','宋','宋诗','song-poetry','','[]','雲蕭蕭，草摇摇，風吹黄沙昏泬寥。',112,'全唐诗/poet.song.25000.json','["雲蕭蕭，草摇摇，風吹黄沙昏泬寥。", "胡兒滿窟卧寒日，卓旗繫馬人一疋。", "夜來烽火連篝起，銀鶻呼兵捷如鬼。", "齊集弓刀上隴行，犬噪狐嗥繞空壘。", "羌人鈔暴爲常事，見敵不爭收若雨。", "自高聲勢敘邊功，歲歲年年皆一同。", "將軍玩寇五原上，朝廷不知但推賞。"]'),
('07f110fc-82ad-4aca-85af-6914b971331d','讀武紀','文同','宋','宋诗','song-poetry','','[]','嗟哉徹之有天下，甘心神仙希羽化。',64,'全唐诗/poet.song.25000.json','["嗟哉徹之有天下，甘心神仙希羽化。", "五十餘丈起樓觀，萬八千里走車駕。", "安期羨門竟何在，五利文成終死詐。", "若非留意尚文學，嬴政且賢非爾亞。"]'),
('0d350fca-6347-4d1e-8de4-3edc9ce4d893','題東巖隠者壁','文同','宋','宋诗','song-poetry','','[]','青峰叢叢擁危壑，綠樹團團扶曲閣。',64,'全唐诗/poet.song.25000.json','["青峰叢叢擁危壑，綠樹團團扶曲閣。", "幽人睡起漱寒泉，坐看一林山雨落。", "岩前火氣雜芝朮，澗下苔痕亂猿鶴。", "自憐塵土滿衣衫，欲解從君今尚莫。"]'),
('1ef9730d-b315-4fca-8839-5d116b825501','東山亭','文同','宋','宋诗','song-poetry','','[]','朝陽之峰乃天設，曲嶺長崗地盤結。',64,'全唐诗/poet.song.25000.json','["朝陽之峰乃天設，曲嶺長崗地盤結。", "下臨絕澗走縈回，上聳巍亭飛巀嵲。", "晚雲幾處水墨畫，秋樹數番紅綠纈。", "安能恰會此時閒，靜與詩翁吟曉雪。"]'),
('f4e2a59e-efdd-4930-8885-fa7e40fd20e0','水邊春半','文同','宋','宋诗','song-poetry','','[]','芹牙差差蘭笋短，石渠冰銷水色淺。',64,'全唐诗/poet.song.25000.json','["芹牙差差蘭笋短，石渠冰銷水色淺。", "倡情冶思不可奈，好鳥間關花婉娩。", "鮮衫翠裾者誰氏，行歌楊枝惜時晚。", "臨流有客抱危膝，苦調長謠問誰遣。"]'),
('f6c663ae-5dfc-400f-9a05-1fa45d6c8658','採藥歸晚因宿野人山舍','文同','宋','宋诗','song-poetry','','[]','東岩陰深崖巘古，夾澗垂泉結鵝乳。',64,'全唐诗/poet.song.25000.json','["東岩陰深崖巘古，夾澗垂泉結鵝乳。", "我來採藥晚忘歸，試宿荆扉問鷄黍。", "春風滿林燈火冷，一夜不眠山月苦。", "平明携策下青蒼，松葉紛紛灑新雨。"]'),
('9fb1497f-d045-42a4-b88b-74ab2c4c5b1f','後溪晚步','文同','宋','宋诗','song-poetry','','[]','陰陰芳樹暗回堤，路入蒙籠轉野溪。',64,'全唐诗/poet.song.25000.json','["陰陰芳樹暗回堤，路入蒙籠轉野溪。", "澤雉應媒高復下，林鴉引子歇還啼。", "青蒲宛宛全淹水，紫笋斑斑半出泥。", "倚杖風前感時節，亂烟斜日一蟬嘶。"]'),
('8506db91-fcec-4b4f-894c-fff142faa5ce','山中新晴','文同','宋','宋诗','song-poetry','','[]','山中新晴曉烟暖，散带頹冠漱岩畔。',64,'全唐诗/poet.song.25000.json','["山中新晴曉烟暖，散带頹冠漱岩畔。", "海鹽未去猿鶴喜，柴桑初歸松菊亂。", "林間餘雨時一滴，嶺上飛雲忽雙斷。", "安能舉手恣扶摇，欲共高鴻拂霄漢。"]'),
('e36ef673-581b-433f-833d-1c556bc92a97','鹽亭縣永樂山叩雲亭','文同','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江合高峰，爽氣左右繞。',144,'全唐诗/poet.song.25000.json','["長江合高峰，爽氣左右繞。", "中流望絕巘，萬丈見木杪。", "孤亭揭其上，隠隠一拳小。", "李君令茲邑，邀我升縹緲。", "是時天宇凈，晴色洗霜曉。", "萬象滿四隅，轉盼皆可了。", "神清壓塵坌，志適喜猿鳥。", "人生貴軒豁，世務苦紛擾。", "茲焉獲登覽，浩思欲飛矯。", "令謂亭我爲，勝絕此應少。", "願子立佳號，光輝飾松蔦。", "因名之叩雲，大字榜霞表。"]'),
('6c9eb96c-9c14-40e5-9e98-9ee14c4cbe85','杜逸人歸龍山','文同','宋','宋诗','song-poetry','','[]','上亭北望二百里，頹巘墮壑圍龍山。',64,'全唐诗/poet.song.25000.json','["上亭北望二百里，頹巘墮壑圍龍山。", "余嘗往來見之喜，飲食夢寐皆孱顔。", "恨無羽翼一飛到，羨子長往不欲還。", "安得擺手掉世故，相與傲兀於其間。"]'),
('22ad0227-d512-4a53-bf5a-94ff68ce5750','曉入東谷','文同','宋','宋诗','song-poetry','','[]','振纓效王官，釋耒去鄉縣。',192,'全唐诗/poet.song.25000.json','["振纓效王官，釋耒去鄉縣。", "十年始還此，景物覺盡變。", "東谷素所愛，乍到若創見。", "烟雲引晨策，數里入葱蒨。", "明霞照溪口，花草露初泫。", "長松盤高崗，竦竦擢秀幹。", "垂陰雜群木，上欲接霄漢。", "柔蘿互鈎鎖，攬地走荒蔓。", "修篁揭其間，萬個挺若箭。", "登臨愴舊歷，眺聽悅新玩。", "讀書破茅廬，徑彴已漂斷。", "唯餘舍南水，尚吐石竇濺。", "潺潺落危壑，衮衮引飛練。", "臨流濯塵襟，照影實覿面。", "功名竟何所，旅迹轉孤賤。", "引手謝猿鶴，深慚爾驚怨。"]'),
('6491c1d9-89ca-40d0-8a06-a52aa00ce25c','東谷沿小澗樹木叢蔚中有圓潭愛之久坐書所見','文同','宋','宋诗','song-poetry','','[]','野水瀉古穴，石岸盤回淵。',72,'全唐诗/poet.song.25000.json','["野水瀉古穴，石岸盤回淵。", "飛塵不可入，竹樹圍清漣。", "靜往得勝玩，深居逃俗緣。", "寒光照煩襟，景寂心自圓。", "枯篁蹲碧禽，垂頸窺沉鮮。", "對之不敢動，相望兩俱禪。"]'),
('d69d6e41-3b52-4e83-b827-86537f1d9be7','東谷茅齋','文同','宋','宋诗','song-poetry','','[]','野徑轉深密，靜無車馬痕。',48,'全唐诗/poet.song.25000.json','["野徑轉深密，靜無車馬痕。", "松花金粉墮，苔葉翠茸翻。", "蟲鳥春音雜，烟雲晚色昏。", "俗塵何處入，長是掩溪門。"]'),
('0ceec893-883c-423c-9327-bade9d1b9e2b','夏樹','文同','宋','宋诗','song-poetry','','[]','夏樹始繁密，條縷方且柔。',96,'全唐诗/poet.song.25000.json','["夏樹始繁密，條縷方且柔。", "左右覆吾廬，合如張碧油。", "新蟬噪晴午，餘響藏深幽。", "軒窗轉炎日，清影爲我留。", "蚊蚋亦取庇，鬧若春雨稠。", "拂揮不停手，咀嚼胡爾讎。", "何當薰風來，一與掃蕩收。", "吾將就高蔭，濯足臨寒流。"]'),
('0aeef4a9-d116-4ad6-813d-eb7350b7be11','田舍','文同','宋','宋诗','song-poetry','','[]','園林曉氣清，籬巷夕陽明。',48,'全唐诗/poet.song.25000.json','["園林曉氣清，籬巷夕陽明。", "石竇聞寒碓，烟坡見晚耕。", "豚蹄供禱賽，龜殻問陰晴。", "欲識豐年樂，一村鷄犬聲。"]'),
('c1e57b82-09b6-41de-ab73-a93eb56639b0','高槐','文同','宋','宋诗','song-poetry','','[]','高槐夾前除，合蔭卷若洞。',48,'全唐诗/poet.song.25000.json','["高槐夾前除，合蔭卷若洞。", "交柯載宿雨，壓地翠色重。", "青蟲暖自挂，黄鳥晴輒哢。", "枕簟傲炎風，爲君高興動。"]'),
('25dfc809-9e1d-4097-9843-aa5953a54a1c','春閨','文同','宋','宋诗','song-poetry','','[]','枕带縈春思，窗紗漏曉光。',48,'全唐诗/poet.song.25000.json','["枕带縈春思，窗紗漏曉光。", "蠨蛸傷遠別，鶗鴂感流芳。", "妝匣蒸殘粉，薰爐試舊香。", "洞房燈燭外，只有夢悠揚。"]'),
('a0f7a875-e939-4d1c-8fdd-e165ac351c2e','採桑','文同','宋','宋诗','song-poetry','','[]','溪橋接桑畦，鈎籠曉群過。',48,'全唐诗/poet.song.25000.json','["溪橋接桑畦，鈎籠曉群過。", "今朝去何早，向晚蠶恐卧。", "家家五十日，誰敢一日惰。", "未言給私用，且以應官課。"]'),
('77c126ed-ed99-448d-a742-89de38d2ea65','青城山丈人觀','文同','宋','宋诗','song-poetry','','[]','群峰垂碧光，下擁岷仙家。',72,'全唐诗/poet.song.25000.json','["群峰垂碧光，下擁岷仙家。", "神皇被金巾，坐領五帝衙。", "威靈攝真境，俗語不敢嘩。", "精心叩殊庭，俯首仰紫華。", "願言鳳羅盟，畢世驅塵邪。", "循奉蕊珠戒，期之飛太霞。"]'),
('8147e0ac-e706-44b8-bb8f-93842493fedf','上清宮','文同','宋','宋诗','song-poetry','','[]','瓊臺橫紫霄，上有縹緲居。',48,'全唐诗/poet.song.25000.json','["瓊臺橫紫霄，上有縹緲居。", "雲霞抱窗戶，日月循庭除。", "飛羽下金輦，隠芝吟玉書。", "俯首視人間，人間臭如帤。"]'),
('d434949a-630a-4392-a30c-b2fc707ed30d','張少愚書院','文同','宋','宋诗','song-poetry','','[]','澗水侵斷橋，車馬不得通。',48,'全唐诗/poet.song.25000.json','["澗水侵斷橋，車馬不得通。", "飛嵐積庭礎，秋蘚垂紫茸。", "窗紙爛溪雨，簾衣拆林風。", "主人殊未歸，使我烟景空。"]'),
('7d629b88-1eb4-4bb2-8491-669a8a8670ac','誓鬼碑','文同','宋','宋诗','song-poetry','','[]','正一受天籙，腰垂神虎章。',48,'全唐诗/poet.song.25000.json','["正一受天籙，腰垂神虎章。", "群魔獄幽隠，秘篆刻青蒼。", "故事駭前志，餘威驚大荒。", "誰能識奧訣，禹步學魁罡。"]'),
('6873b3e4-6eaa-451a-8061-61c37b254f82','天師栗','文同','宋','宋诗','song-poetry','','[]','天師携此種，至自上饒遠。',48,'全唐诗/poet.song.25000.json','["天師携此種，至自上饒遠。", "當時十七樹，高幹倚孤巘。", "蒼蓬蒺藜大，紫殻檳榔軟。", "蜀部名果中，推之爲上選。"]'),
('b8e9b738-b824-4828-80d5-813e3b00e022','孫知微畫','文同','宋','宋诗','song-poetry','','[]','太古奇偉士，精思獨於畫。',72,'全唐诗/poet.song.25000.json','["太古奇偉士，精思獨於畫。", "馳心入茫昧，萬物赴揮灑。", "當時一名重，顧陸非爾亞。", "卓哉青城筆，妙絕冠天下。", "寥寥九天仗，一一若神寫。", "吾恐千載後，是終無繼者。"]'),
('1f37636c-3be9-417a-bf9d-b5b5de867a13','早晴至報恩山寺','文同','宋','宋诗','song-poetry','','[]','山石巉巉磴道微，拂松穿竹露沾衣。',64,'全唐诗/poet.song.25000.json','["山石巉巉磴道微，拂松穿竹露沾衣。", "烟開遠水雙鷗落，日照高林一雉飛。", "大麥未收治圃晚，小蠶猶卧斫桑稀。", "暮烟已合牛羊下，信馬林間步月歸。"]'),
('b734f431-298f-4b2c-8260-a4460ec11eb4','楊山人歸綿竹','文同','宋','宋诗','song-poetry','','[]','一別江梅十度花，相逢重爲講胡麻。',64,'全唐诗/poet.song.25000.json','["一別江梅十度花，相逢重爲講胡麻。", "火鈴未降真君宅，金鈕曾盟太帝家。", "道氣滿簪凝綠髪，神光飛鼎護黄芽。", "青騾不肯留歸馭，又入無爲嚥曉霞。"]'),
('6d918253-6924-41a3-a832-3231dc5a0a37','閑遣','文同','宋','宋诗','song-poetry','','[]','庭竹擁高叢，移床就好風。',48,'全唐诗/poet.song.25000.json','["庭竹擁高叢，移床就好風。", "掩門休務外，隠几坐忘中。", "世事元何物，人心了即空。", "客來休借問，此意浩無窮。"]'),
('bcba755b-4fca-4569-b163-a68b8cce94bf','睡起','文同','宋','宋诗','song-poetry','','[]','寥寥公館靜，門掩似山家。',48,'全唐诗/poet.song.25000.json','["寥寥公館靜，門掩似山家。", "竹簟屢移枕，石盤頻浸花。", "閑多新得策，事少早休衙。", "一覺高舂睡，誰來伴試茶。"]'),
('7b37a63c-c5fc-4ce4-8d80-565dd82e2aa5','梅','文同','宋','宋诗','song-poetry','','[]','寒梅引舊枝，映竹復臨池。',48,'全唐诗/poet.song.25000.json','["寒梅引舊枝，映竹復臨池。", "朵露深開處，香聞瞥過時。", "凌兢侵臘雪，散漫入春詩。", "贈我歲寒色，憐君冰玉姿。"]'),
('a071cc97-02e8-4def-973a-2739a4d3a774','永泰劉令清曦亭','文同','宋','宋诗','song-poetry','','[]','木杪照初日，捲簾知曉晴。',48,'全唐诗/poet.song.25000.json','["木杪照初日，捲簾知曉晴。", "軒窗無限思，圖史有餘清。", "露下濛花重，風來泛竹輕。", "何須嫌五斗，持此謝淵明。"]'),
('c705b92a-492f-4066-b21f-092c8f0a7646','貧居','文同','宋','宋诗','song-poetry','','[]','繩床擁敝裯，初起髪未櫛。',96,'全唐诗/poet.song.25000.json','["繩床擁敝裯，初起髪未櫛。", "南窗展書卷，就暖讀寒日。", "門前絕車馬，薄暮垂片席。", "短牆挂纖蔓，幽鳥啄紅實。", "群蝸惡積雨，繚繞篆空壁。", "男兒處貧賤，舉首宇宙窄。", "翩翻槍榆鳩，宛轉匿絮虱。", "妻孥競相笑，憔悴守文筆。"]'),
('e7f56062-adeb-4209-934c-f7bdcefbe5f1','惜花','文同','宋','宋诗','song-poetry','','[]','胡蜂採花花氣薄，黄鳥啄花花蕊落。',64,'全唐诗/poet.song.25000.json','["胡蜂採花花氣薄，黄鳥啄花花蕊落。", "林風吹花花片亂，池水浸花花色惡。", "少年惜花會花意，晴張青幃雨油幕。", "勸君直須爲花飲，明日春歸空晚萼。"]'),
('c8e18072-adae-4016-98eb-899011db21d2','貞女吟','文同','宋','宋诗','song-poetry','','[]','身外無一簪，何以供鉛華。',72,'全唐诗/poet.song.25000.json','["身外無一簪，何以供鉛華。", "飾行不飾容，濁水白藕花。", "藕心亂如絲，妾心圓如珠。", "絲亂端緒多，珠圓瑕纇無。", "焉得偶君子，奉之此高節。", "所生雖至親，此意安可說。"]'),
('20d82dcf-0e65-4e77-8fe5-99e66bac8e96','莫折花','文同','宋','宋诗','song-poetry','','[]','莫折花，花好亦自喜。',66,'全唐诗/poet.song.25000.json','["莫折花，花好亦自喜。", "勿謂花無言，請以君心酌花意。", "君容待花轉豐艷，花枝因君愈憔悴。", "莫折花，任花飛落地。", "但對春風倚芳樹，長遣香英伴君醉。"]'),
('f8ee0937-e5a0-4e47-83f0-b6b571f45ffc','織婦怨','文同','宋','宋诗','song-poetry','','[]','擲梭兩手倦，踏籋雙足趼。',168,'全唐诗/poet.song.25000.json','["擲梭兩手倦，踏籋雙足趼。", "三日不住織，一疋纔可剪。", "織處畏風日，剪時謹刀尺。", "皆言邊幅好，自愛經緯密。", "昨朝持入庫，何事監官怒。", "大字雕印文，濃和油墨污。", "父母抱歸舍，拋向中門下。", "相看各無語，淚迸若傾瀉。", "質錢解衣服，買絲添上軸。", "不敢輒下機，連宵停火燭。", "當須了租賦，豈暇恤襦袴。", "前知寒切骨，甘心肩骭露。", "里胥踞門限，叫駡嗔納晚。", "安得織婦心，變作監官眼。"]'),
('0c91de30-7cdf-45f1-be14-52ab066edf33','野花嘆','文同','宋','宋诗','song-poetry','','[]','昨看百草抽新芽，今看百草開新花。',160,'全唐诗/poet.song.25000.json','["昨看百草抽新芽，今看百草開新花。", "岩隈水側自成列，紅醜紫賤何交加。", "東皇施恩豈不溥，隨所付受無少差。", "爾之瑣細亦蒙被，盡使奮發爭春華。", "織叢密蔓不可數，競起塗抹如矜誇。", "妖鶑冶蝶不爾顧，去爾自欲尋名葩。", "爾知有艷貴爾否，歌管匝樹侯王家。", "爾徒此地弄顔色，只自狼籍隨泥沙。", "何當照水自窺覽，枝赧葉懼相藏遮。", "晚村無限曬殘日，索酒爲爾成吁嗟。"]'),
('d1ac6412-4244-40a5-8f50-0688384d4628','普州三亭 均逸亭','文同','宋','宋诗','song-poetry','','[]','亭宇跨城端，新苔磴道盤。',48,'全唐诗/poet.song.25000.json','["亭宇跨城端，新苔磴道盤。", "風光晴水石，烟景暮林巒。", "簿領仍多暇，賓從每盡歡。", "何由掉塵鞅，聊問借闌干。"]'),
('79d3423b-1fc0-4a3e-814a-ae6c62a656a9','普州三亭 東溪亭','文同','宋','宋诗','song-poetry','','[]','短彴逶迤渡，高檐夭矯沉。',48,'全唐诗/poet.song.25000.json','["短彴逶迤渡，高檐夭矯沉。", "波光環堵凈，日色綵梁深。", "萍荇翻金鯽，蘭苕超翠禽。", "主人公事簡，時此照清襟。"]'),
('2c78b053-d839-444d-8d17-50ef0e0a59ef','普州三亭 碧崖亭','文同','宋','宋诗','song-poetry','','[]','斷巘淥溪邊，危亭翠壁前。',48,'全唐诗/poet.song.25000.json','["斷巘淥溪邊，危亭翠壁前。", "軒窗誰是客，詩酒自稱仙。", "遠壑春藏雨，長波晝起烟。", "吏人休報事，高興正陶然。"]'),
('b40152b8-1695-4461-95a8-968b1fa718c1','送郭經知縣','文同','宋','宋诗','song-poetry','','[]','促促送歸客，短亭垂柳風。',48,'全唐诗/poet.song.25000.json','["促促送歸客，短亭垂柳風。", "離樽掩殘日，去騎若輕蓬。", "百里謳歌內，三年畏謹中。", "鄉人問蜀物，笑指一囊空。"]'),
('c041d54c-7d23-46b4-8250-755ce053c559','過祿氏山齋','文同','宋','宋诗','song-poetry','','[]','過水得憑檻，滿川皆夕陽。',48,'全唐诗/poet.song.25000.json','["過水得憑檻，滿川皆夕陽。", "江山逢勝絕，手筆恨荒唐。", "城郭蒙籠近，汀洲杳靄長。", "明朝又東去，塵土入衣裳。"]'),
('b4d70cef-e819-4ad0-9381-6d214746c051','題李處士月軒','文同','宋','宋诗','song-poetry','','[]','圓蟾噴金波，萬里灑清滴。',48,'全唐诗/poet.song.25000.json','["圓蟾噴金波，萬里灑清滴。", "幽軒得虛敞，皓彩溢素壁。", "繩床有高隠，苦調起岑寂。", "盈襟納孤光，靜與爽氣敵。"]'),
('1338eab8-3218-4f28-9e46-b5190a8406a9','余過興州太守晁侯延之於東池晴碧亭且道其所以爲此池亭之意使余賦詩','文同','宋','宋诗','song-poetry','','[]','鄭谷題詩處，荒凉不復知。',48,'全唐诗/poet.song.25000.json','["鄭谷題詩處，荒凉不復知。", "使君來問日，景物欲歸時。", "崖巘供清溜，亭臺繞翠漪。", "主人憐過客，借與傲炎曦。"]'),
('62fee9e2-9f08-47ae-8299-87c06fadf946','蒲氏別墅十詠 方湖','文同','宋','宋诗','song-poetry','','[]','風交蒲葦亂，烟斷鳬鶩飛。',24,'全唐诗/poet.song.25000.json','["風交蒲葦亂，烟斷鳬鶩飛。", "日暮一笛起，扁舟垂釣歸。"]'),
('58a1d204-9f0c-4bc1-bddc-d64c8aa84571','蒲氏別墅十詠 涵碧亭','文同','宋','宋诗','song-poetry','','[]','軒窗曉吹清，枕簟晴光冷。',24,'全唐诗/poet.song.25000.json','["軒窗曉吹清，枕簟晴光冷。", "亭上逍遥人，滿身摇水影。"]'),
('b11a3d09-aab4-4338-b09f-c2b8e8dc317d','蒲氏別墅十詠 白蓮堂','文同','宋','宋诗','song-poetry','','[]','逼簾呈素艷，入座薦清香。',24,'全唐诗/poet.song.25000.json','["逼簾呈素艷，入座薦清香。", "何以陪暑飲，對之飛玉觴。"]'),
('e842cbbc-8c84-426c-9407-8429303f1e64','蒲氏別墅十詠 芙蓉溪','文同','宋','宋诗','song-poetry','','[]','曉靄滋花色，晴輝發水光。',24,'全唐诗/poet.song.25000.json','["曉靄滋花色，晴輝發水光。", "何人露新纈，不管著秋霜。"]'),
('f5b9be48-a71b-4e6a-9465-74ec4047dc2e','蒲氏別墅十詠 魚池','文同','宋','宋诗','song-poetry','','[]','積水自淵淵，來源常汩汩。',24,'全唐诗/poet.song.25000.json','["積水自淵淵，來源常汩汩。", "岸上翠衣禽，對人時一沒。"]'),
('07a8b4e2-5527-44d9-ab1a-7b690426bba4','蒲氏別墅十詠 蓮池','文同','宋','宋诗','song-poetry','','[]','紫蓋嫩貼水，玉梢長刺沙。',24,'全唐诗/poet.song.25000.json','["紫蓋嫩貼水，玉梢長刺沙。", "避風紅出沒，驚雨綠交加。"]'),
('53c93c1a-764f-4143-86f1-dfc6c2cb704f','蒲氏別墅十詠 清蟾橋','文同','宋','宋诗','song-poetry','','[]','溪光摇玉璧，雲影漏金盤。',24,'全唐诗/poet.song.25000.json','["溪光摇玉璧，雲影漏金盤。", "誰此伴高興，畫橋憑曲欄。"]'),
('4129d59d-c3d5-4525-ad70-fdc3a2cd6418','蒲氏別墅十詠 稻畦','文同','宋','宋诗','song-poetry','','[]','决水轉橫渠，交塍畫方罫。',24,'全唐诗/poet.song.25000.json','["决水轉橫渠，交塍畫方罫。", "秋風報秋熟，滿頃吹罷亞。"]'),
('69228580-45c6-47d4-a64f-0be6d51f25f1','蒲氏別墅十詠 朝真堂','文同','宋','宋诗','song-poetry','','[]','高臺按虛境，飛駕羅太空。',24,'全唐诗/poet.song.25000.json','["高臺按虛境，飛駕羅太空。", "小兆佩神虎，每來清夜中。"]'),
('696ed84a-3c3a-418e-a030-dbbe5bc261f7','蒲氏別墅十詠 草庵','文同','宋','宋诗','song-poetry','','[]','深深鄭真谷，小小焦先廬。',24,'全唐诗/poet.song.25000.json','["深深鄭真谷，小小焦先廬。", "借問貯何物，滿床皆隠書。"]'),
('f704b7c4-43db-4ff7-8c98-31ddf8db2a30','蒼溪山寺','文同','宋','宋诗','song-poetry','','[]','正午風色高，遂泊蒼溪縣。',144,'全唐诗/poet.song.25000.json','["正午風色高，遂泊蒼溪縣。", "層崖抱林木，有寺藏葱蒨。", "出船步危磴，蔭密頗縈轉。", "上到金仙家，緣空列臺殿。", "修篁掛懸溜，坐覺炎暑變。", "老僧曉經論，言語何貫穿。", "引我上高閣，闌干俯江面。", "寥寥百里內，山水盡奇觀。", "誰謂羈旅中，所見皆所願。", "汀洲白鳥聚，井邑青烟散。", "樂此暮忘歸，疏鐘起岩畔。", "徙倚下松門，尚怪舟人喚。"]'),
('b7586acf-1846-4fd9-aac0-e8ee8fcd2f19','五里三灘','文同','宋','宋诗','song-poetry','','[]','群石壅水成哀湍，五里之地凡三灘。',112,'全唐诗/poet.song.25000.json','["群石壅水成哀湍，五里之地凡三灘。", "船如走丸勢不住，力敵萬弩雲濤盤。", "門窗掩塞怕飛浪，已倒床座翻杯槃。", "長年三老色自落，捩眼不敢窺波瀾。", "捎渦撇漩出九死，衆命幸免魚鱉餐。", "須臾出纜繫高岸，競以好語相慰安。", "是時左右有觀者，應亦爲我心曾寒。"]'),
('94b7d7b7-c3ac-4b59-9327-07273ef9740c','昝公溉','文同','宋','宋诗','song-poetry','','[]','晚泊昝公溉，船頭餘落暉。',120,'全唐诗/poet.song.25000.json','["晚泊昝公溉，船頭餘落暉。", "携家上岸行，愛此風滿衣。", "村巷何蕭條，四顧烟火稀。", "問之曰去歲，此地遭凶饑。", "斯民半逃亡，在者生計微。", "請看林木下，牆屋皆空圍。", "好田無人耕，惟有荆棘肥。", "至今深夜中，鬼火流清煇。", "衆稚聞此語，競走來相依。", "錯莫驚且哭，牽挽求速歸。"]'),
('095d827c-6ff8-4a9d-946d-957f9cc0fe8d','王會之秀才山亭','文同','宋','宋诗','song-poetry','','[]','盤盤翠城山，君在城中住。',120,'全唐诗/poet.song.25000.json','["盤盤翠城山，君在城中住。", "溪流第縈轉，岡勢復回互。", "蒼林無春冬，啼鳥常旦暮。", "漠漠嶺頭雲，霏霏岩底霧。", "中間列亭榭，佳景實天付。", "物象皆自然，人巧誰能寓。", "浮生欲何事，有此即樂處。", "况君弟兄賢，信道各已固。", "詩書誨兒侄，觴豆燕逢遇。", "敢問彼簪裾，何如此巾屨。"]'),
('273beed3-27d1-4816-bcc8-11287f60ace7','謝友人寄畫','文同','宋','宋诗','song-poetry','','[]','客從長安來，厚紙封小軸。',180,'全唐诗/poet.song.25000.json','["客從長安來，厚紙封小軸。", "題云此奇畫，寄贈公可蓄。", "開之掛高壁，爛絹止一幅。", "中有兩駱駝，氣韻頗不俗。", "大駝載半髀，正面頸愈曲。", "小駝方就乳，蹲身脚微跼。", "一馬立其後，才露頭與足。", "三犬乃子母，共卧銜臠肉。", "老胡抱朱旗，狀貌何狠愎。", "端然立高岸，勢若不可觸。", "定是虜中酋，華旃蓋鮮服。", "不知何所來，隨從無一僕。", "初誰作此畫，精妙亦可錄。", "應餘右方在，次第不止獨。", "更願君訪來，我肯萬錢贖。"]'),
('26e19b40-4bcd-4640-b6d4-28aedff32281','夏日閑書墨君堂壁二首  其一','文同','宋','宋诗','song-poetry','','[]','先人有敝廬，涪水之東邊。',240,'全唐诗/poet.song.25000.json','["先人有敝廬，涪水之東邊。", "我罷漢中守，歸此聊息焉。", "是時五六月，赤日烘遥天。", "山川盡燥燥，草木皆焦燃。", "塵襟既暫解，勝境乃獨專。", "高林抱深麓，清蔭密石綿。", "層岩敞戶外，淺瀨流窗前。", "邀客上素琴，留僧酌寒泉。", "竹簟白石枕，穩處只屢遷。", "忽時乘高風，遠望立雲烟。", "野興極浩蕩，俗慮無一緣。", "氣爽神自樂，世故便可捐。", "却憶爲吏時，荷重常滿肩。", "几案堆簿書，區處忘食眠。", "冠带坐大暑，顙汗常涓涓。", "每懼落深責，取適敢自便。", "安閑獲在茲，怳若夢游仙。", "行將佩守符，復爾趨洋川。", "山中豈不戀，事有勢外牽。", "尚子願未畢，安能賦歸田。"]'),
('938c0282-cbec-4ffe-beb5-58eb13f30af1','夏日閑書墨君堂壁二首  其二','文同','宋','宋诗','song-poetry','','[]','歸來山中住，便作山中人。',120,'全唐诗/poet.song.25000.json','["歸來山中住，便作山中人。", "冠带亦自閑，累月不著身。", "散髪層岩阿，濯足清澗濱。", "石蘚黏簡冊，松風墮衣巾。", "鄉里多舊游，不厭過從頻。", "山肴與野釀，待我如佳賓。", "有召即走赴，愛其愛我真。", "常恐禮數乖，取問吾交親。", "正此一夏樂，忽茲遘蕭辰。", "還愧擁千騎，又走西道塵。"]'),
('1f1b0d9d-60f4-4a2d-9a77-09901481b560','送馮允南倅梓','文同','宋','宋诗','song-poetry','','[]','去年父老送督郵，衣上淚痕猶未變。',160,'全唐诗/poet.song.25000.json','["去年父老送督郵，衣上淚痕猶未變。", "今年吏民迎別乘，馬前歡聲挽不斷。", "梓州城中十萬家，家家盡喜見君面。", "以君鄉里最相近，物態人情素諳練。", "况復才力强且明，中理之的無漫箭。", "從來府政號少事，今更得君愈清簡。", "太守李公詞掖老，淘汰心源無滓澱。", "時携賓從訪山寺，惟以高譚侑清宴。", "蒼崖素壁多自書，是處新詩題欲遍。", "君今到彼亦爾爲，異日唱酬知幾卷。"]'),
('d27bb614-c1f1-4857-81dd-e46234ce82ac','宿東山村舍','文同','宋','宋诗','song-poetry','','[]','八十雪眉翁，燈前屢歔欷。',168,'全唐诗/poet.song.25000.json','["八十雪眉翁，燈前屢歔欷。", "問之爾何者，不語惟抆淚。", "良久云老矣，未始逢此事。", "種粟滿川原，幸已皆茂遂。", "喜聞欲登熟，近復失所冀。", "有蟲大如蠶，日夜嚙其穗。", "群鴉利蟲食，剪摘俱在地。", "驅呵力難及，十止餘三四。", "供家固未足，王稅何由備。", "瘠土耕至骨，所得幾何利。", "又令遭此禍，不曉上天意。", "在世幸許年，必以饑饉死。", "聞之不敢詰，但愧有祿位。", "移燈面空壁，到曉曾不寐。"]'),
('13dd2212-0452-4f09-8588-2f9c17384fb5','季夏己亥大雨','文同','宋','宋诗','song-poetry','','[]','黑雲堆空天地昏，風勢猛惡山岳掀。',144,'全唐诗/poet.song.25000.json','["黑雲堆空天地昏，風勢猛惡山岳掀。", "怪電燒爇嗔霆喧，鯨海起立星漢翻。", "玉竿銀索傾瓶盆，豪威怒力凌乾坤。", "川陸浩渺同一源，泛濫直欲浮高原。", "澗谷洶涌龍蛇奔，溝渠溪壑相吐吞。", "土肉刮盡惟骨存，漂蕩秋稼無一根。", "天生烝民主仁恩，覆露養育生理蕃。", "誰持害鑰開禍門，絕滅黍豆災元元。", "無路能去陳九閽，此事是非安可論。"]'),
('98631d55-2579-4767-b87d-856b09e9e63c','謝任遵聖光祿惠詩','文同','宋','宋诗','song-poetry','','[]','常念文選詩，最愛顔光祿。',216,'全唐诗/poet.song.25000.json','["常念文選詩，最愛顔光祿。", "君今作此官，詩亦顔之躅。", "尋常得君詩，如隼饑見肉。", "凡當憂憤際，不可不取讀。", "我自山南歸，幽居值炎溽。", "六月久不雨，萬物蒸煮熟。", "正在墨君堂，流體汗可掬。", "單絺與圓素，豈解療煩毒。", "聞君有詩至，猛起捧大軸。", "拆開得累紙，半日了一幅。", "使我困病除，如藥清頭目。", "把詩坐前軒，憤惋幾欲哭。", "君也實高才，徑庭無骫曲。", "六十尚爲縣，不自耻碌碌。", "近聞移小麾，所用愈局促。", "安得長康莊，走此老驥騄。", "哲士甘藜藿，鄙夫厭粱肉。", "天理不可問，長吁倚喬木。"]'),
('322f27d4-5198-42ce-bd9a-54e741e3d777','謝任瀘州師中寄荔枝','文同','宋','宋诗','song-poetry','','[]','有客來山中，云附瀘南信。',120,'全唐诗/poet.song.25000.json','["有客來山中，云附瀘南信。", "開門得君書，歡喜失鄙吝。", "筠籨包荔子，四角具封印。", "童稚瞥聞之，群來立如陣。", "競言此佳果，生眼不識認。", "相前求拆觀，顆顆紅且潤。", "衆手攫之去，爭奪遞追趁。", "貪多乃爲得，廉耻曾不問。", "喧鬧俄頃聞，咀嚼一時盡。", "空餘皮與核，狼籍入煨燼。"]'),
('c89c4461-2448-4f07-9e57-63be2638660c','霹靂','文同','宋','宋诗','song-poetry','','[]','君不見，前時忽疑天地坼，萬里一聲晴霹靂。',68,'全唐诗/poet.song.25000.json','["君不見，前時忽疑天地坼，萬里一聲晴霹靂。", "彼某氏者爾何人，敢自欺誣被誅磔。", "子爛華容神火燎，父碎梓潼靈䃸劈。", "惟震與曜今曉然，誰對君親肆姦逆。"]'),
('f4bc9282-8960-4007-bf86-2d6330ba4818','後溪','文同','宋','宋诗','song-poetry','','[]','新晴揉藍染溪色，我愛常來坐溪側。',64,'全唐诗/poet.song.25000.json','["新晴揉藍染溪色，我愛常來坐溪側。", "一林奇石宛如畫，兩岸野花殊不識。", "蟬鳴盡日競何事，鷺下多時猶未食。", "細觀物理須靜中，歸去無辭更昏黑。"]'),
('8df306f0-489c-4a97-a143-ac8dbe6b2c04','黄功垂秘書嵐城閣','文同','宋','宋诗','song-poetry','','[]','群峰繞高軒，四望如城密。',72,'全唐诗/poet.song.25000.json','["群峰繞高軒，四望如城密。", "晴嵐逼窗戶，凈若新洗熨。", "杳杳其中人，衣襟照寒碧。", "臨風設橫几，蕭灑坐終日。", "門前車馬道，擾擾亂如蝨。", "轉眼不復觀，長歌傲簪紱。"]'),
('09b55292-004a-4f24-83b8-9df78421e5e5','鳳山古祠','文同','宋','宋诗','song-poetry','','[]','林木摧折堂廡傾，其中塑像猶縱橫。',64,'全唐诗/poet.song.25000.json','["林木摧折堂廡傾，其中塑像猶縱橫。", "狂巫騰踏野老拜，瘦鷄薄酒邀神明。", "形容詭怪蛇虺亂，聲音醜惡鴟梟鳴。", "災牛禍犬亦可作，世有此事何由平。"]'),
('ed173aac-5228-4a3c-82f5-50c95b03cd86','靜中吟','文同','宋','宋诗','song-poetry','','[]','客去復掩戶，高松下清陰。',60,'全唐诗/poet.song.25000.json','["客去復掩戶，高松下清陰。", "微風動其間，對語雙珍禽。", "幽人獨憑几，聽此古意深。", "起來南窗下，被以朱弦琴。", "彈之代佳話，俚耳誰知音。"]'),
('7812f5d2-1c8c-47f9-b46d-e5dcb1e27e98','送黄庶先岷州赴舉','文同','宋','宋诗','song-poetry','','[]','朝庭取士及洮西，君今去就岷州薦。',64,'全唐诗/poet.song.25000.json','["朝庭取士及洮西，君今去就岷州薦。", "男兒致身自有地，六月萬里君莫憚。", "君也經術三十年，此發必中后羿箭。", "聲名大抵重文章，慎莫便從班定遠。"]'),
('394a07ae-f6a9-4d45-ad44-f0f74fc2e408','大熱見田中病牛','文同','宋','宋诗','song-poetry','','[]','壠上病牛良可悲，皮毛枯槁頭角垂。',64,'全唐诗/poet.song.25000.json','["壠上病牛良可悲，皮毛枯槁頭角垂。", "兩鼻谽谺只自喘，四蹄屴岌曾不皮。", "牧童默坐罷牽挽，耕叟拱立徒嗟咨。", "朝驅暮使氣力盡，爾死主人安得知。"]'),
('b3d63902-14cf-45fb-b0fb-63fe881b394a','呈里中諸友','文同','宋','宋诗','song-poetry','','[]','君莫怪我不讀書，君莫笑我不飲酒。',64,'全唐诗/poet.song.25000.json','["君莫怪我不讀書，君莫笑我不飲酒。", "更精文史豈足用，漸老歡娛復何有。", "負郭安得二百畝，舉家已聚三十口。", "且來伴我數月閑，未幾區區又西走。"]'),
('9fee7cc4-a785-42fa-bfe8-a2fa62b6a59e','寄彰明任光祿遵聖','文同','宋','宋诗','song-poetry','','[]','軒軒任公子，本是釣鰲人。',72,'全唐诗/poet.song.25000.json','["軒軒任公子，本是釣鰲人。", "手把虹蜺竿，一舉百萬鈞。", "得鰲謂無用，坐卷千丈綸。", "却自絓蚯蚓，淺瀨收纖鱗。", "悠悠世上兒，不識此有神。", "但將俗士眼，下視窮水濱。"]'),
('19ec6718-399c-4b08-b01d-9106b5de26e8','庶先北谷','文同','宋','宋诗','song-poetry','','[]','路自西溪入，園當北谷開。',48,'全唐诗/poet.song.25000.json','["路自西溪入，園當北谷開。", "月亭詩作客，雨館睡爲媒。", "摘果衣霑露，尋泉屐漬苔。", "閑居正無事，莫問我頻來。"]'),
('c5a49197-fc36-427c-89df-208fc16cb6bc','謝王庶軻秀才見贈諸篇','文同','宋','宋诗','song-poetry','','[]','覽君山中詩，多有贈我篇。',72,'全唐诗/poet.song.25000.json','["覽君山中詩，多有贈我篇。", "感此意愛厚，使我將潸然。", "世態日衰薄，交道君獨全。", "豈若賤丈夫，心醜貌甚妍。", "我已嬰組綬，君方傲林泉。", "出處雖有殊，所樂同一天。"]'),
('92f4d589-3ec0-4573-88a3-c05e22cbb0da','前溪獨遊','文同','宋','宋诗','song-poetry','','[]','溪水碧溶溶，紆餘短彴通。',48,'全唐诗/poet.song.25000.json','["溪水碧溶溶，紆餘短彴通。", "小灘晴靄外，獨鶴夕陽中。", "倚杖對清瀨，披襟當好風。", "幾時歸住此，長下釣魚筒。"]'),
('dbe28f61-95b4-4e01-a9f6-49b84551a617','書綠帷亭壁','文同','宋','宋诗','song-poetry','','[]','喬木繞舍如綠幃，群山四面寒參差。',64,'全唐诗/poet.song.25000.json','["喬木繞舍如綠幃，群山四面寒參差。", "春禽入秋啼自別，早雲到暮歸常遲。", "庭前好菊勸飲酒，案上佳紙邀吟詩。", "閑居數月興便野，渾忘簿書相聒時。"]'),
('f15e76b3-77c3-4254-871a-da2d404ea4cb','青山道','文同','宋','宋诗','song-poetry','','[]','冥冥青山道，叢木含古烟。',48,'全唐诗/poet.song.25000.json','["冥冥青山道，叢木含古烟。", "遠客事行役，未晚不敢前。", "乳虎正養子，采食大路邊。", "但顧己所急，其誰辨愚賢。"]'),
('29a63d39-16b1-4168-8d9f-0eef128fef11','野老','文同','宋','宋诗','song-poetry','','[]','野老扶白頭，耕墾事田壠。',48,'全唐诗/poet.song.25000.json','["野老扶白頭，耕墾事田壠。", "豈無兒與孫，凍餒實我恐。", "地産止數出，財用知幾種。", "食肉與衣帛，賢者何言冗。"]'),
('d19ae4e4-4013-46e5-83ba-be4a7186c3db','誰氏子','文同','宋','宋诗','song-poetry','','[]','縹緲誰氏子，學道要昇仙。',48,'全唐诗/poet.song.25000.json','["縹緲誰氏子，學道要昇仙。", "人世豈不樂，何苦求上天。", "反首顧我語，子豈得謂賢。", "智如撲燈蛾，甘就膏火煎。"]'),
('2b95a56c-ea47-45a4-9717-546b0ef3a582','秋興二首  其一','文同','宋','宋诗','song-poetry','','[]','晨風吹茂林，夕露下芳畹。',48,'全唐诗/poet.song.25000.json','["晨風吹茂林，夕露下芳畹。", "秋容變憔悴，復此白日短。", "蕭蕭歲華暮，冉冉節物換。", "浩嘆倚前楹，使我心曲亂。"]'),
('6d677aa9-336d-404c-a4db-914ef9ace58b','秋興二首  其二','文同','宋','宋诗','song-poetry','','[]','百蟲感秋陰，入夜聲更切。',48,'全唐诗/poet.song.25000.json','["百蟲感秋陰，入夜聲更切。", "問爾苦何事，到曉啼不歇。", "盈庭不可止，蓊薉藏萬穴。", "會是天使然，相將送凋節。"]'),
('910033bb-ceaf-4f1a-a414-83a000a16c3d','書平泉草木記後二首  其一','文同','宋','宋诗','song-poetry','','[]','衛公當國日，力與天地均。',48,'全唐诗/poet.song.25000.json','["衛公當國日，力與天地均。", "平泉植草木，取盡四方春。", "海嶽欲必得，亦能役鬼神。", "可笑身未冷，已聞屬他人。"]'),
('0ab38d83-b152-49a0-bf95-5d509a2327f8','書平泉草木記後二首  其二','文同','宋','宋诗','song-poetry','','[]','公豈不聰明，嗜好乃如此。',48,'全唐诗/poet.song.25000.json','["公豈不聰明，嗜好乃如此。", "若非以私餌，是物安至止。", "彼致者何人，定非端潔士。", "草木固爲塵，醜名終未已。"]'),
('8ee328fd-4abd-4c9c-84be-e866f78ed298','重過舊學山寺','文同','宋','宋诗','song-poetry','','[]','當年讀書處，古寺擁群峰。',48,'全唐诗/poet.song.25000.json','["當年讀書處，古寺擁群峰。", "不改歲寒色，可憐門外松。", "有僧皆老大，待客轉從容。", "又下白雲去，樓頭敲暮鐘。"]'),
('cf8bf0c9-851d-4295-8c11-d4c2b0df6e54','書隠者壁','文同','宋','宋诗','song-poetry','','[]','枳棘分三徑，猿猱結四鄰。',48,'全唐诗/poet.song.25000.json','["枳棘分三徑，猿猱結四鄰。", "茂林修竹地，枕石漱流人。", "看雨搘藤杖，迎風卸葛巾。", "我來懷愧甚，衣上有紅塵。"]'),
('5d8acee3-11a6-4025-aab9-932ff4cb585d','訪古寺老僧不遇書壁','文同','宋','宋诗','song-poetry','','[]','寂寂復寂寂，門前苔蘚積。',48,'全唐诗/poet.song.25000.json','["寂寂復寂寂，門前苔蘚積。", "巾鉢定何之，禪房封屈膝。", "蛛絲網窗戶，蝸涎篆牆壁。", "欲去重遲留，空中望歸錫。"]'),
('c891ddcb-1b17-4ee1-8f07-d8c9ee5da449','村居','文同','宋','宋诗','song-poetry','','[]','日影滿松窗，雲開雨初止。',48,'全唐诗/poet.song.25000.json','["日影滿松窗，雲開雨初止。", "晴林梨棗熟，曉巷兒童喜。", "牛羊深澗下，鳬雁寒塘裏。", "田父酒新成，瓶罌饋鄰里。"]'),
('952b6697-616a-47a3-b1bc-e04e360fd259','宿田家','文同','宋','宋诗','song-poetry','','[]','日落雲四起，牛羊下高原。',48,'全唐诗/poet.song.25000.json','["日落雲四起，牛羊下高原。", "今夜宿何處，孤烟生遠村。", "寥寥岩狖響，擾擾林鴉喧。", "危坐欲終夕，此意將誰論。"]'),
('868e7e47-fddf-47fe-ab9c-e482d5cdb31d','大熱','文同','宋','宋诗','song-poetry','','[]','大熱早復暮，幽居如火圍。',48,'全唐诗/poet.song.25000.json','["大熱早復暮，幽居如火圍。", "更無風稍快，只有汗頻揮。", "袒露憂生客，沾濡怕熟衣。", "何當生兩翼，直近廣寒飛。"]'),
('f681a60e-a94b-43e9-80f7-89efb3aedb5f','閑樂','文同','宋','宋诗','song-poetry','','[]','晝睡忽過午，好風吹竹床。',48,'全唐诗/poet.song.25000.json','["晝睡忽過午，好風吹竹床。", "溪雲生薄暮，山雨送微凉。", "粉裛衣裳潤，蘭薰簟席香。", "歸來閑且樂，多謝墨君堂。"]'),
('9f6d7124-2616-4332-bdc7-7ebeb8a7644e','寄楊歸一','文同','宋','宋诗','song-poetry','','[]','出處久異矣，居常勞所思。',48,'全唐诗/poet.song.25000.json','["出處久異矣，居常勞所思。", "烟霄惟子未，鬢髪已翁爲。", "世故豈須問，人生當自知。", "林泉聞幸好，足可樂明時。"]'),
('34ddd01c-7c2c-45d4-9acc-d610887b64f1','行李載書成咏','文同','宋','宋诗','song-poetry','','[]','於世已無用，何苦愛讀書。',48,'全唐诗/poet.song.25000.json','["於世已無用，何苦愛讀書。", "自笑身許大，所處如蟫魚。", "編簡補斷爛，卷軸收殘餘。", "又鎖十餘篋，作數隨行書。"]'),
('eb913586-4fd3-4279-90f9-d8eb214ae501','還友人詩卷','文同','宋','宋诗','song-poetry','','[]','作詩所患格不高，君今已得詩中格。',48,'全唐诗/poet.song.25000.json','["作詩所患格不高，君今已得詩中格。", "吾鄉風物最清麗，君向其間作詩客。", "定餘絕景在幽深，更欲煩君用刀尺。"]'),
('ed0b38ec-041c-42b7-9422-e9d9a52ab9d0','上亭北軒對月吹笛得才元舍人昭華引醉霜月草堂吟皆詩譜也  其一','文同','宋','宋诗','song-poetry','','[]','瀲灧金波瀉碧空，隔霜寒影下征鴻。',32,'全唐诗/poet.song.25000.json','["瀲灧金波瀉碧空，隔霜寒影下征鴻。", "夜深一笛昭華引，吹滿千岩萬壑中。"]'),
('75740e9a-ef23-435a-a5e3-1aa1cf97ef1e','上亭北軒對月吹笛得才元舍人昭華引醉霜月草堂吟皆詩譜也  其二','文同','宋','宋诗','song-poetry','','[]','群山暝色烟開後，遠水寒光雨過時。',32,'全唐诗/poet.song.25000.json','["群山暝色烟開後，遠水寒光雨過時。", "今夜何人醉霜月，卧聽緱嶺玉參差。"]'),
('74106c49-e004-44d2-9225-da2ffc2d6b1e','上亭北軒對月吹笛得才元舍人昭華引醉霜月草堂吟皆詩譜也  其三','文同','宋','宋诗','song-poetry','','[]','涪江東岸有雲林，巒嶺縈回澗谷深。',32,'全唐诗/poet.song.25000.json','["涪江東岸有雲林，巒嶺縈回澗谷深。", "何事遲留未歸去，强顔猶唱草堂吟。"]'),
('b8fc9368-385f-4527-9ea2-324faaf86cb1','苗子居運判歸宿州同赴武康西縣道中奉寄  其一','文同','宋','宋诗','song-poetry','','[]','霜風舞征袂，有客去符離。',48,'全唐诗/poet.song.25000.json','["霜風舞征袂，有客去符離。", "斜谷雪晴後，曲灘水滿時。", "亂山誰對酒，孤驛獨吟詩。", "不得陪清絕，悵然空所思。"]'),
('299601ef-fb76-4d18-82ca-719b2dd880bf','苗子居運判歸宿州同赴武康西縣道中奉寄  其二','文同','宋','宋诗','song-poetry','','[]','漢中爲會失兼程，雨雪曾無一日晴。',32,'全唐诗/poet.song.25000.json','["漢中爲會失兼程，雨雪曾無一日晴。", "拗項橋頭聊立馬，使車應已過褒城。"]'),
('c982cef6-b89a-47a1-8b55-c1f8baf5b355','孫懷悅紙本亂石','文同','宋','宋诗','song-poetry','','[]','孫老抱奇筆，臨紙恣揮灑。',48,'全唐诗/poet.song.25000.json','["孫老抱奇筆，臨紙恣揮灑。", "從頭掃亂石，磥砢隨墨下。", "焦頑與圓潤，無一不精者。", "誰信萬鈞重，卷之不盈把。"]'),
('14b81884-edec-4906-a217-3cb1e4a7e7bc','種榆詩','文同','宋','宋诗','song-poetry','','[]','昔我去守陵陽日，門前夾道初種榆。',128,'全唐诗/poet.song.25000.json','["昔我去守陵陽日，門前夾道初種榆。", "今年我自山南歸，向椽大者皆柱粗。", "兩邊合陰若深洞，滿地清影繁如鋪。", "是時暑氣正炎酷，無處容此煩病軀。", "晝摇清風夜篩月，日日不可離群株。", "閑邀親友坐其下，左右間設琴與壺。", "人生適意乃爲樂，此樂已恐他更無。", "霜飈未起枝葉在，且與諸君同此娛。"]'),
('ed41645f-943a-4ed7-9e3e-6d958fed6899','旱雷','文同','宋','宋诗','song-poetry','','[]','夏旱亦已久，衆懼非常災。',48,'全唐诗/poet.song.25000.json','["夏旱亦已久，衆懼非常災。", "茫茫大田中，赤風起炎埃。", "密雲徒滿空，甘澤竟不來。", "但聞南山下，日日喧怒雷。"]'),
('45834652-bbe0-4653-9092-c6a0f8b4b59c','久不雨喜見晚雲','文同','宋','宋诗','song-poetry','','[]','晚雲萬丈如銀山，日光返射紅孱顔。',64,'全唐诗/poet.song.25000.json','["晚雲萬丈如銀山，日光返射紅孱顔。", "莫誇突兀在天上，且放滂沱來人間。", "雷公施力已憤怒，風伯壞事休庸頑。", "我將待之至夜半，慎勿更似前時慳。"]'),
('81e3d88c-762f-4ca9-8966-aa89e2745991','賈佩蘭歌','文同','宋','宋诗','song-poetry','','[]','綠髪憶新梳，君前侍玉壺。',168,'全唐诗/poet.song.25000.json','["綠髪憶新梳，君前侍玉壺。", "相隨五色鳳，飛止帝宮梧。", "鳳時入紫烟，一舉萬羽趨。", "乘風恣敖盪，衆首傾雲衢。", "帝既天上行，留鳳不與俱。", "鎩翮下永巷，髡𩮜編鉗徒。", "赭衣舂且歌，北望鸑鷟呼。", "凜凜赤喙鴆，一杯死其鶵。", "鳳亦飲瘖藥，鞠域支體殊。", "娥姁豈不仁，幸此全賤軀。", "歸來南山下，秋風裂羅襦。", "寒床覆龍具，霜雪侵肌膚。", "忽自感時節，臨風只長吁。", "徒懷掖庭事，飲泣對民夫。"]'),
('c4764938-ca79-419e-95f1-7ff20ed325c8','徐太元','文同','宋','宋诗','song-poetry','','[]','彼徐太元者，杭州之參軍。',288,'全唐诗/poet.song.25000.json','["彼徐太元者，杭州之參軍。", "同僚曰張惠，犯贓抵深文。", "徐哀其母老，詣獄輒自陳。", "謂惠所受贓，太元本同分。", "今儻獨坐惠，此獄無乃冤。", "均之不滿法，惠遂減死論。", "太元亦坐免，不調十餘年。", "西臺李侍郎，典選世所賢。", "聞徐之所爲，特以不次遷。", "擢授鄭司功，太元名始傳。", "後爲申王師，德行人推先。", "嗟哉後世人，恩義日不完。", "初既同職事，言色殊相歡。", "諂酒與佞食，旦夕同杯盤。", "一有不得意，艱險立萬端。", "推之入網羅，又以毒箭攢。", "昂然了自得，衒露其術全。", "此等雖曰人，犬彘曾豈然。", "眼見與耳聞，天下何可言。", "我今作此詩，中有二義存。", "欲使在位者，此風幸相敦。", "勿令有識人，命爾爲蝎蚖。", "又欲彼正士，爲國掌三銓。", "須察此惡子，廢斥入冗員。"]'),
('a5959077-7976-40c7-a3db-7d79c7f7864a','蓋寬饒','文同','宋','宋诗','song-poetry','','[]','次公清而狂，其本出天性。',168,'全唐诗/poet.song.25000.json','["次公清而狂，其本出天性。", "惜哉公廉質，不以儒術正。", "陷害公峭刻，奸犯語堅勁。", "在位及貴戚，合然仇怨盛。", "稀遷愈失意，躁戾因以逞。", "王生識其趣，勸以全壽命。", "胡爲不開納，封事轉凌橫。", "五帝官天下，此語豈君聽。", "上怒以不改，章下求衆定。", "礭然金吾奏，直以大逆訂。", "雖爲鄭昌頌，萬嫉掩一諍。", "遂爾屬諸吏，羞復受笞榜。", "行當北闕下，輒引佩刀剄。", "時雖衆所憐，終爲端士病。"]'),
('0a7c270d-c339-4500-8f95-fc4713486571','諸葛豐','文同','宋','宋诗','song-poetry','','[]','少年名特立，初爲貢公起。',168,'全唐诗/poet.song.25000.json','["少年名特立，初爲貢公起。", "元帝擢司隸，刺舉無所避。", "間者何久闊，京師語如此。", "馳車下許章，去節自豐始。", "上書擿章惡，此舉誠可喜。", "奈何少恩恕，春夏常繫治。", "人多訟其短，遂徙城門尉。", "復列堪猛過，上爲之切齒。", "制詔白其罪，不忍下豐吏。", "豐初在朝時，數道堪猛美。", "失職乃自取，不內省諸己。", "反惑怨其他，轉譽以爲毀。", "不欲加以刑，上憐之老矣。", "庶人終於家，反覆豐可耻。"]'),
('52a16590-cb75-4b2d-bc80-e086ea416872','新津退思堂','文同','宋','宋诗','song-poetry','','[]','三江古劇邑，入籍生齒夥。',96,'全唐诗/poet.song.25000.json','["三江古劇邑，入籍生齒夥。", "詞源百端起，區處不可惰。", "子醇爲之宰，幽隠照必破。", "斷事精且密，有若麥歷磨。", "尚懼忽一失，退即此堂坐。", "戾者思改易，無使下罹禍。", "如此凡二載，不識有纖過。", "賢哉令之師，敢以此爲賀。"]'),
('a68dad64-a77f-46e9-8125-bd71753e9fcb','墨君堂晚晴憑欄','文同','宋','宋诗','song-poetry','','[]','墨君堂中看新霽，十里平林鋪凈綠。',64,'全唐诗/poet.song.25000.json','["墨君堂中看新霽，十里平林鋪凈綠。", "青烟一去抹遠岸，白鳥雙來立喬木。", "戴勝入園蠶已老，栗留過隴麥將熟。", "坐待月破東嶺雲，自取簾鈎更高軸。"]'),
('29c0b173-7ab8-454a-86a7-6343fc83a75c','山舍早起探晴','文同','宋','宋诗','song-poetry','','[]','山鳥囀晴日，獨行風滿林。',48,'全唐诗/poet.song.25000.json','["山鳥囀晴日，獨行風滿林。", "澗花薰野袂，岩水濺幽襟。", "側石驚新滑，垂蘿愛近深。", "蕭然此清興，不似戴華簪。"]'),
('41fd7718-b71a-44c3-b370-b81a2951c062','東谷獨往','文同','宋','宋诗','song-poetry','','[]','久不到東谷，晚晴欣細履。',48,'全唐诗/poet.song.25000.json','["久不到東谷，晚晴欣細履。", "陰陰夾路木，濺濺落溪水。", "幽涎界屏粉，亂喙刻窗紙。", "兀坐忘所歸，烟雲逼人起。"]'),
('9acf6e85-d6a4-4da6-9c62-f2d1f6594190','西崦道友','文同','宋','宋诗','song-poetry','','[]','西崦入深窅，幽茅藏隠仙。',48,'全唐诗/poet.song.25000.json','["西崦入深窅，幽茅藏隠仙。", "虛窗畫雲篆，凈几校靈編。", "絕巘聳玉幹，危岩瀉珠涎。", "相留飯青䭀，人世凡幾年。"]'),
('fa8d5f2b-76ae-4987-820d-a2d26b919b35','送李野夫兼簡公擇學士同年','文同','宋','宋诗','song-poetry','','[]','吾友野夫官滿歸，峽中風物正春時。',64,'全唐诗/poet.song.25000.json','["吾友野夫官滿歸，峽中風物正春時。", "莫因道路起長嘆，且對江山吟好詩。", "異日滑臺君若到，寄言別乘我相思。", "聲名已重更論底，但引冰堂金屈卮。"]'),
('106ccf56-2426-4799-a996-a4d8402f02d5','任居雲棲枝閣','文同','宋','宋诗','song-poetry','','[]','峨峨仙鸞山，杳杳山上閣。',192,'全唐诗/poet.song.25000.json','["峨峨仙鸞山，杳杳山上閣。", "道傍問耕者，居雲之所作。", "居雲倜儻士，韁鎖不可縛。", "讀書三十年，議論寫不涸。", "縱橫入衆藝，深曉不止略。", "自笑與世疏，回首念岩壑。", "安排事幽隠，終老期此託。", "結茅層巒巔，退比籬下雀。", "棲枝榜其號，意豈羨鵬鶚。", "時茲入岑絕，寄憤滿寥廓。", "江風拂危欄，澗月滿疏箔。", "獨橫古溜琴，遠意追淡泊。", "蕭蕭履霜操，隠隠天外落。", "飄揚雜仙籟，泛響度林薄。", "其誰共高興，唯此猿與鶴。", "願言解塵纓，一赴方外約。"]'),
('4ca15e71-abeb-4bdf-b1d2-601d98f50c91','朱康叔郎中棄官求母於金州因會華清宮作此詩送之','文同','宋','宋诗','song-poetry','','[]','蟠桃實在枝，蟠桃花已飛。',120,'全唐诗/poet.song.25000.json','["蟠桃實在枝，蟠桃花已飛。", "相隔五十春，一旦還相依。", "康叔視金龜，解去如糞土。", "徒步入嶢關，金州取其母。", "古人亦有此，比之康叔難。", "幾時有古人，能如公棄官。", "玉蓮仙宇中，相會談此事。", "使我發驚嘆，達曉不能寐。", "借問侍安輿，輦下何時過。", "我欲率諸君，扶服詣門賀。"]'),
('1f42ae9c-35a6-4dbd-98c4-fa4f42160683','蓬溪蘇令均利泉','文同','宋','宋诗','song-poetry','','[]','潛流蔽荒壤，嘉惠鬰所施。',96,'全唐诗/poet.song.25000.json','["潛流蔽荒壤，嘉惠鬰所施。", "邑人念遠汲，視此無以爲。", "蘇君作之令，大利收前遺。", "一日會衆鍤，茲焉發清漪。", "既已就新甃，瓶缶何纍纍。", "盡言彼污濁，豈爾同甘滋。", "比戶獲美飲，頌君皆一辭。", "何以紀君德，是泉無涸時。"]'),
('16d39908-e255-4f8b-8429-e452e55b326e','冤婦行','文同','宋','宋诗','song-poetry','','[]','婉婉西鄰女，韶顔艷朝霞。',288,'全唐诗/poet.song.25000.json','["婉婉西鄰女，韶顔艷朝霞。", "淑性自天與，少小傳令嘉。", "孝愛親黨重，巧慧閭里誇。", "其母最嬌憐，看若眼下花。", "自從掙冠笄，未始離窗紗。", "讀書佩箴戒，舉止無纖瑕。", "求媒不自審，得婿非良家。", "如以瓊樹枝，使之並蒹葭。", "憶初行嫁時，遺贈矜豪華。", "明珠蹙袿裾，雜寶裝簪珈。", "餘貲詎可數，但較輦以車。", "其姑本寒種，貪壑常谽谺。", "得婦不問好，求索惟無涯。", "侍奉四五年，叫物愈餓鴉。", "百欲一不應，用毒同虺蛇。", "豈惟被詬辱，抑亦遭笞撾。", "馳使執賤役，課責日夜加。", "手指盡禿瘃，鬢髪仍髟髿。", "一旦不任事，病骨枯若槎。", "委頓卧在床，尚爾磨怒牙。", "既死亦不顧，但恣攫且拏。", "聞之道路人，涕泗而咨嗟。", "養女擇所適，此事寧輕耶。", "家法要相委，在邇不在遐。"]'),
('cc49feb4-5f52-461f-ad77-baae34f50ce0','林居','文同','宋','宋诗','song-poetry','','[]','宿髪未暇梳，林居且辰詣。',48,'全唐诗/poet.song.25000.json','["宿髪未暇梳，林居且辰詣。", "鮮暉散清滴，濕濕滿衣袂。", "仄行蓋前礙，傾視因遠翳。", "野意浩盈懷，曾忘傲公退。"]'),
('eeab29dd-715b-4f05-9bd0-bf43b38ba36b','墨君堂','文同','宋','宋诗','song-poetry','','[]','嗜竹種復畫，渾如王掾居。',48,'全唐诗/poet.song.25000.json','["嗜竹種復畫，渾如王掾居。", "高堂倚空岩，素壁交扶疏。", "山影覆秋靜，月色澄夜虛。", "蕭爽只自適，誰能愛吾廬。"]'),
('f441d02d-b52c-427d-a129-7180efcf786d','鑒崖','文同','宋','宋诗','song-poetry','','[]','層崖瑩青瑶，泠滑不可捫。',48,'全唐诗/poet.song.25000.json','["層崖瑩青瑶，泠滑不可捫。", "秋光發凈照，林影摇晴暾。", "飛瀑滌吟肺，垂蘿清飲魂。", "惟憂漬愁霖，碎蘚來相痕。"]'),
('97107dbd-9ea2-4249-91f2-7bff95825f6e','宿超果山寺','文同','宋','宋诗','song-poetry','','[]','荒途涉沮洳，危嶺升坡阤。',120,'全唐诗/poet.song.25000.json','["荒途涉沮洳，危嶺升坡阤。", "愛此清凈居，不倦來往多。", "山僧見余喜，顛倒披乾陀。", "引我坐前軒，山果丹碧羅。", "食已步野徑，新柔踏晴莎。", "就石枕古稜，依松執長柯。", "是夕乃宿此，東山吐圓波。", "夜久不能寐，禽蟲伴幽哦。", "達旦鳴落葉，固非俗士歌。", "岩猿與溪鳥，應笑頻經過。"]'),
('d6770de0-3a4a-4048-bd20-ab71e1af4ee5','富樂山海師','文同','宋','宋诗','song-poetry','','[]','上人者何人，富樂之禪客。',120,'全唐诗/poet.song.25000.json','["上人者何人，富樂之禪客。", "成都昔嘗見，時已坐法席。", "別來二十年，嗟此出處隔。", "昨過芙蓉溪，捨楫得携策。", "盤盤轉危磴，上叩金仙宅。", "林間識孤標，梵眼老愈碧。", "引我翠壁下，煮茗拂蘚石。", "問之第二月，雄辯發古譯。", "無由從之遊，不得蒙久益。", "翻然入塵闠，俯首愧名迹。"]'),
('a26a1e53-c5ac-4837-a7e7-b20829214291','彭州南樓','文同','宋','宋诗','song-poetry','','[]','百尺壓城端，飛檐欲上摶。',48,'全唐诗/poet.song.25000.json','["百尺壓城端，飛檐欲上摶。", "湖光摇埤堄，山影轉欄桿。", "秀野含春煦，喬林擁暮寒。", "回頭大岷雪，千仞玉巑岏。"]'),
('0c0cee82-7c2d-49f7-8877-bb50edb0a699','大慈交師演古軒','文同','宋','宋诗','song-poetry','','[]','萬法一軒中，周回百座容。',48,'全唐诗/poet.song.25000.json','["萬法一軒中，周回百座容。", "曲燃薝蔔久，橫揭貝多重。", "信士供晨鉢，門人集午鐘。", "何時聽雄辨，幾柄換庭松。"]'),
('5d1aa33c-e65a-43cd-bb09-da3faf07d7d8','新晴後溪樹陰灑然覽景成韵','文同','宋','宋诗','song-poetry','','[]','雨後溪水急，晴光鬰如浮。',96,'全唐诗/poet.song.25000.json','["雨後溪水急，晴光鬰如浮。", "高林放繁陰，黮黮幢蓋稠。", "麥熟桑椹好，撩亂黄栗留。", "咿咿動新蜩，呴呴啼乳鳩。", "晚策貪靜境，緩带成獨遊。", "照影俯回淵，濯足臨漫流。", "願言懷世慮，逐此蕭灑休。", "定知今夕夢，不作塵土憂。"]'),
('ec305968-8c4f-42ee-9953-b5af8ec93bb2','黄秀才北郊書堂','文同','宋','宋诗','song-poetry','','[]','吾邑固僻陋，巉巉合群山。',240,'全唐诗/poet.song.25000.json','["吾邑固僻陋，巉巉合群山。", "苟無賢者居，孰能營幽閑。", "黄子治北郊，勝絕收其間。", "長溪斷谷口，囂譁隔塵闤。", "始至甚夷曠，漸往頗險艱。", "洞穴烟雲昏，澗壑松桂環。", "幽芳自芬馥，野哢常綿蠻。", "繚磴挂絕壁，孤彴飛遥灣。", "氣象奪天奧，景物搜鬼慳。", "築室貯群籍，軒窗面孱顔。", "朱黄列几案，坐把古穴刪。", "自取天爵高，下視五兩綸。", "處心固已定，詎恤時輩訕。", "伊余素無似，謬入文墨班。", "前得省親歸，屢此容追攀。", "時亦竊講議，始蹈賢聖關。", "譬之拉虎豹，所得纔一斑。", "自愧鄙樸姿，得涉道誼寰。", "余亦有東谷，對此何格頑。", "每來輒盡日，須步明月還。"]'),
('f94ecc89-e279-4b14-99f5-4ec692b8dab5','讀楊山人詩','文同','宋','宋诗','song-poetry','','[]','秋高群山空，衆籟吐天竅。',120,'全唐诗/poet.song.25000.json','["秋高群山空，衆籟吐天竅。", "霜飈擊林野，岩壑起哀嘂。", "蕭蕭寒月下，合若萬鬼嘯。", "疑是太古魂，㗀㗀此中弔。", "山人住中巘，側耳得清峭。", "譜之入文字，滿卷冷雪照。", "其聲太凄楚，勁澀皆古調。", "俗尚正淫靡，惑者自夸耀。", "山人持之歸，無乃取衆譙。", "會有知此音，相逢當一笑。"]'),
('6c029122-eaa0-4e7a-9caf-aae0304f5208','已師竹杖','文同','宋','宋诗','song-poetry','','[]','已師杖奇竹，坐亦不去手。',96,'全唐诗/poet.song.25000.json','["已師杖奇竹，坐亦不去手。", "循摩瑩且膩，瘦骨何蚴蟉。", "叢枝抱奇節，兩兩相對走。", "尋常出孤梢，上下分左右。", "如何此獨異，天産固非偶。", "師初得之誰，此實世未有。", "不爲師所用，亦共衆植朽。", "願師勿棄置，珍之比靈壽。"]'),
('4d5a1d8d-3175-4a58-acd7-d23b5d186055','晚至村家','文同','宋','宋诗','song-poetry','','[]','高原磽確石徑微，籬巷明滅餘殘暉。',64,'全唐诗/poet.song.25000.json','["高原磽確石徑微，籬巷明滅餘殘暉。", "舊裾飄風採桑去，白袷卷水秧稻歸。", "深葭繞澗牛散卧，積麥滿場鷄亂飛。", "前溪後谷暝烟起，稚子各出關柴扉。"]'),
('16fdaa65-7ef6-4629-9963-63aca3018333','雨喜客過','文同','宋','宋诗','song-poetry','','[]','積雨無所詣，十日不出屋。',60,'全唐诗/poet.song.25000.json','["積雨無所詣，十日不出屋。", "故人念端居，牢落如槁木。", "高軒過窮巷，下馬想慰沃。", "載酒酡楊顔，裹飯飽桑腹。", "日暮從者散，還尋舊書讀。"]'),
('e5f13d83-f090-41df-bd48-e2b856db0b26','墅居','文同','宋','宋诗','song-poetry','','[]','不復入城市，亂山圍一村。',48,'全唐诗/poet.song.25000.json','["不復入城市，亂山圍一村。", "雲霞供几席，水石佐琴樽。", "病久筋力緩，眠多頭目昏。", "無人來谷口，苔蘚上松門。"]'),
('7fb79956-2617-48b8-8f98-5c8acb1e7699','東窗','文同','宋','宋诗','song-poetry','','[]','叢榆落碎鈿，蔓柳撲輕綿。',48,'全唐诗/poet.song.25000.json','["叢榆落碎鈿，蔓柳撲輕綿。", "麗畹暗紅霧，曲堤橫翠烟。", "嘉樹正陰合，好禽新語圓。", "東窗日已滿，猶托隠囊眠。"]'),
('2bc5a756-a391-42ae-9620-babeddc657d3','大雨','文同','宋','宋诗','song-poetry','','[]','驚雲駕長風，大雨灑九有。',48,'全唐诗/poet.song.25000.json','["驚雲駕長風，大雨灑九有。", "崩騰百川倒，豪怒一雷走。", "茫茫草木亂，隠隠岩谷吼。", "高閣晝眠人，覺來但支肘。"]'),
('75ea1d09-8b77-46ec-8b1a-4577aec67e1b','芹嘆','文同','宋','宋诗','song-poetry','','[]','清霜入寒溪，水迹落一尺。',48,'全唐诗/poet.song.25000.json','["清霜入寒溪，水迹落一尺。", "飛沙上芹葉，脆卷如燎炙。", "孤根抱生意，春澤守遺瀝。", "願奉野人薦，充君盤中實。"]'),
('063c0468-2d35-49c4-b6f7-284ffc33c76d','憂居','文同','宋','宋诗','song-poetry','','[]','憂居向山林，蟲鳥日爲伍。',48,'全唐诗/poet.song.25000.json','["憂居向山林，蟲鳥日爲伍。", "形骸乍摧剝，骨肉慣辛苦。", "蔬盤羞客至，病榻厭人語。", "地僻誰往還，閑門閉深雨。"]'),
('88000564-c1d5-43f9-a99b-b3cd236f57d1','任氏鳴璫橋','文同','宋','宋诗','song-poetry','','[]','清溪漱碧崖，衮衮寒聲落。',48,'全唐诗/poet.song.25000.json','["清溪漱碧崖，衮衮寒聲落。", "子川愛溪聲，架橋橫絕壑。", "山風撼松月，倚檻聽噴薄。", "遂號曰鳴璫，古人無此作。"]'),
('57ca396c-9ca0-447b-9ba3-ad09eb73022a','過友人溪居','文同','宋','宋诗','song-poetry','','[]','籬巷接菰蒲，閑扉掩自娛。',48,'全唐诗/poet.song.25000.json','["籬巷接菰蒲，閑扉掩自娛。", "水蟲行插岸，林鳥過提壺。", "白浪摇秋艇，青烟蓋晚厨。", "主人誇野飯，爲我煮新蘆。"]'),
('97e4dd9b-5b7a-4cac-818d-17745a1e05ae','江上主人','文同','宋','宋诗','song-poetry','','[]','客路逢江國，人家占畫圖。',48,'全唐诗/poet.song.25000.json','["客路逢江國，人家占畫圖。", "青林隨遠岸，白水滿平湖。", "魚小猶論尺，鷗輕欲問銖。", "何時遂休去，來此伴潛夫。"]'),
('17770fc8-765a-46f0-ac40-095e6244df0e','詠月','文同','宋','宋诗','song-poetry','','[]','見說樓臺滿玉波，中間惟只鎖孀娥。',32,'全唐诗/poet.song.25000.json','["見說樓臺滿玉波，中間惟只鎖孀娥。", "可憐八萬二千戶，每到缺時爭奈何。"]'),
('f6294be7-970f-4232-92f0-06045541169f','五十','文同','宋','宋诗','song-poetry','','[]','生平曾不事悠悠，倏忽年華五十秋。',32,'全唐诗/poet.song.25000.json','["生平曾不事悠悠，倏忽年華五十秋。", "宦意文情俱淡泊，可憐渾似李蒙州。"]'),
('f1e0bd7e-fe3c-479a-9417-69cfc6378785','攬照','文同','宋','宋诗','song-poetry','','[]','耻將衰晚競青春，强把圓波拂曉塵。',32,'全唐诗/poet.song.25000.json','["耻將衰晚競青春，强把圓波拂曉塵。", "自笑年來鬚鬢白，王昭不解作官人。"]'),
('f9721605-48fe-484b-a843-d7705310c015','梁景和','文同','宋','宋诗','song-poetry','','[]','隋氏廷中列百官，幾人風節動朝端。',32,'全唐诗/poet.song.25000.json','["隋氏廷中列百官，幾人風節動朝端。", "越公事勢炎如火，獨有梁毗會忍寒。"]'),
('65fabb81-934f-4959-be94-ef002cfa2d6c','何桂林','文同','宋','宋诗','song-poetry','','[]','十萬餘工造羽儀，夾堤浮浪去參差。',32,'全唐诗/poet.song.25000.json','["十萬餘工造羽儀，夾堤浮浪去參差。", "堂堂送入江都去，渾忘當年攬頸時。"]'),
('9538b9a6-99ce-48c5-afbc-bcc3aae622b8','傲吏','文同','宋','宋诗','song-poetry','','[]','管馬心何在，排車意自閑。',24,'全唐诗/poet.song.25000.json','["管馬心何在，排車意自閑。", "問時將手板，柱頰對西山。"]'),
('51e61382-d030-4aa7-b3d4-e56d606aafcc','閬州東園十詠 錦屏閣','文同','宋','宋诗','song-poetry','','[]','茂林斑若錦，秀巘矗如屏。',24,'全唐诗/poet.song.25000.json','["茂林斑若錦，秀巘矗如屏。", "底處供登覽，闌干在杳冥。"]'),
('3c9ebfca-a7eb-417e-a41a-138f3bfc8947','閬州東園十詠 清風臺','文同','宋','宋诗','song-poetry','','[]','無時來見襲，有地更臨高。',24,'全唐诗/poet.song.25000.json','["無時來見襲，有地更臨高。", "坐客清談起，紛紛落麈毛。"]'),
('5db12e6f-72f0-43fa-a139-63c999531ae3','閬州東園十詠 四照亭','文同','宋','宋诗','song-poetry','','[]','畫箔褰何礙，珍叢發已圓。',24,'全唐诗/poet.song.25000.json','["畫箔褰何礙，珍叢發已圓。", "願公皆遍賞，莫爲一隅偏。"]'),
('33450e32-889b-4381-9ebd-48f0b33f1cf8','閬州東園十詠 柳橋','文同','宋','宋诗','song-poetry','','[]','挼風誇晚態，垂雨怯春寒。',24,'全唐诗/poet.song.25000.json','["挼風誇晚態，垂雨怯春寒。", "爲問題芳意，同誰倚畫欄。"]'),
('1b933f52-0065-450d-a331-06e42d18c878','閬州東園十詠 曲池','文同','宋','宋诗','song-poetry','','[]','水似珠璫入，池如玉磬開。',24,'全唐诗/poet.song.25000.json','["水似珠璫入，池如玉磬開。", "臨流唯自適，魚鳥莫相猜。"]'),
('c7c1347d-8b1e-4a7f-8948-e3eaf2b100de','閬州東園十詠 明月臺','文同','宋','宋诗','song-poetry','','[]','微稜生海角，圓魄到天心。',24,'全唐诗/poet.song.25000.json','["微稜生海角，圓魄到天心。", "共上唯佳客，無容照俗襟。"]'),
('044672e1-5647-40cc-b205-2a0a689231de','閬州東園十詠 三角亭','文同','宋','宋诗','song-poetry','','[]','合棟交生角，回欄互引牙。',24,'全唐诗/poet.song.25000.json','["合棟交生角，回欄互引牙。", "由來因地勢，不是故尖斜。"]'),
('62c21637-4e16-40b9-bc83-98f53d389544','閬州東園十詠 花塢','文同','宋','宋诗','song-poetry','','[]','繚繞穿紅萼，爛斑踏紫苔。',24,'全唐诗/poet.song.25000.json','["繚繞穿紅萼，爛斑踏紫苔。", "誰將錦步障，端爲使君開。"]'),
('5ef35e8d-e860-4c44-a722-bb1ea95d31d3','閬州東園十詠 藥欄','文同','宋','宋诗','song-poetry','','[]','玉笋齊抽日，金釭競列時。',24,'全唐诗/poet.song.25000.json','["玉笋齊抽日，金釭競列時。", "自然俱可愛，莫放畫簾垂。"]'),
('f51d0672-72a4-4db9-ac0c-8729712a9df3','閬州東園十詠 郎中庵','文同','宋','宋诗','song-poetry','','[]','已築環爲堵，仍裁月作床。',24,'全唐诗/poet.song.25000.json','["已築環爲堵，仍裁月作床。", "公來時隠几，身世在羲皇。"]'),
('8d236265-1d85-4f57-802f-7bd9eb3b0c9e','和仲蒙石龍渦','文同','宋','宋诗','song-poetry','','[]','群岡壓涇湄，於此聚衆首。',144,'全唐诗/poet.song.25000.json','["群岡壓涇湄，於此聚衆首。", "其間石屋露，遠視若呀口。", "林端躡絙上，却入勢愈斗。", "圍空豎古壁，闊可百人受。", "洪鐘誰倒仰，巨甕忽側剖。", "層岩寒泉飛，絕巘怪樹走。", "陰風喜復怒，野霧吞且嘔。", "晴嵐逼衣襟，欲住不得久。", "嘗聞耕者說，自昔藏蚴蟉。", "當年救旱事，有記刻不朽。", "近歲靈恐歇，百禱無一偶。", "至今閭里人，不復來奠酒。"]'),
('e07cc74b-1248-40cd-b8a0-0b67e14dc553','和仲蒙山城','文同','宋','宋诗','song-poetry','','[]','大曆年，忠武居豳捍逆氐。',122,'全唐诗/poet.song.25000.json','["大曆年，忠武居豳捍逆氐。", "盛平民，營板堵，斷賊閉迒蹊。", "連櫓橫，朱鳥飛。", "牆切紫霓縈紆圍，絕巘靡迤附深谿。", "外浚池隍險，旁聯堡障低。", "轒輼防藺石，埤堄礙雲梯。", "樹杪鳴巡鐸，崖端響守鼙。", "石頭何培塿，龍首太醯鷄。", "歲久蒼苔上，時平白草齊。", "全秦襟带地，惟此壯山西。"]'),
('78324bb7-9f9b-4444-b30e-ad86a6240034','和子山春日雨中書事見寄  其一','文同','宋','宋诗','song-poetry','','[]','菀菀冥冥雨氣沉，一春長是詠春陰。',64,'全唐诗/poet.song.25000.json','["菀菀冥冥雨氣沉，一春長是詠春陰。", "燕歸畫棟簾櫳靜，鶑下雕欄院宇深。", "鬥草玉釵應復約，看花金勒誤重尋。", "謝郎風調將誰奈，獨倚書床擁鼻吟。"]'),
('4b8e5061-4b71-4500-b1af-558fd430f81a','和子山春日雨中書事見寄  其二','文同','宋','宋诗','song-poetry','','["\u897f\u6e56"]','青春已破六十日，正好共携歌管遊。',64,'全唐诗/poet.song.25000.json','["青春已破六十日，正好共携歌管遊。", "鶑花有意欲惱亂，風雨何事相淹留。", "南園綵棚映綠樹，西湖畫舫臨清流。", "幾時雲陰得斂霽，願把一樽相獻酬。"]'),
('7a3e62c3-d557-45cf-8a04-2eb6a9b5be7e','馬子山爲余與賀順之書記李仲蒙察推同年同幕作題名記復有詩督程適之書石余因和兼謝','文同','宋','宋诗','song-poetry','','[]','太常舊得同科第，幕府今還次姓名。',64,'全唐诗/poet.song.25000.json','["太常舊得同科第，幕府今還次姓名。", "作記馬周文已贍，書丹程邈隸尤精。", "定知二美能傳久，從此三家覺轉榮。", "每對雄詞觀健筆，自慚孤迹附群英。"]'),
('6408af59-7d06-43c2-9386-3ea48457b17b','官舍春日書懷  其一','文同','宋','宋诗','song-poetry','','[]','自趨戎幙佐鞬櫜，四見新陰發舊柯。',64,'全唐诗/poet.song.25000.json','["自趨戎幙佐鞬櫜，四見新陰發舊柯。", "學飲不成歡意少，好吟無倦苦心多。", "舞傷池柳風圖甚，泣破庭蘭雨奈何。", "敢對青春嘆留滯，且須開口更狂歌。"]'),
('c5ddb457-3801-495f-85ce-2986e1265611','官舍春日書懷  其二','文同','宋','宋诗','song-poetry','','[]','琵琶泉水碧溶溶，又見春歸玉柱峰。',64,'全唐诗/poet.song.25000.json','["琵琶泉水碧溶溶，又見春歸玉柱峰。", "歡緒已闌羞老大，交期將近懶遊從。", "杏開暖萼融紅蠟，柳放晴花拆白茸。", "賦得上林佳景盡，不知誰爲薦臨邛。"]'),
('f8f68a85-53c9-4d42-93d9-a83e50d59df7','登邠州城樓','文同','宋','宋诗','song-poetry','','[]','試此望摇落，秋襟成惘然。',48,'全唐诗/poet.song.25000.json','["試此望摇落，秋襟成惘然。", "客懷傷薄莫，節物感窮邊。", "斷燒侵高壘，微陽入晚川。", "年來舊山意，常與雁翩翩。"]'),
('aa7247d3-5ac4-494b-88ea-121d831c51bb','秋盡日陪諸友登白佛閣','文同','宋','宋诗','song-poetry','','[]','危剎隠高阜，孤軒橫碧虛。',48,'全唐诗/poet.song.25000.json','["危剎隠高阜，孤軒橫碧虛。", "登臨賞秋杪，笑傲樂公餘。", "野外景入畫，坐中歡可書。", "重城已嚴鑰，歸馬尚踟躕。"]'),
('628388a0-8fd8-4fdc-b40d-ab7cd0b9d35c','極寒','文同','宋','宋诗','song-poetry','','[]','燈火宜冬杪，圖書稱夜長。',48,'全唐诗/poet.song.25000.json','["燈火宜冬杪，圖書稱夜長。", "簾鈎挂新月，窗紙漏飛霜。", "酒醴慚孤宦，皮毛逐異鄉。", "誰知舊山下，梅艷滿東牆。"]'),
('b4e84774-f327-4a0c-9164-ff60d0ac20c0','謝惠橘','文同','宋','宋诗','song-poetry','','[]','緗葉隠朱實，纍纍楚江澨。',48,'全唐诗/poet.song.25000.json','["緗葉隠朱實，纍纍楚江澨。", "寒香摘清露，奔走寄迢遞。", "琳腴滿金殻，咀嚼想佳惠。", "君未致此時，風已吹削肺。"]'),
('7ba218f8-0c00-4a10-aaf6-af4e4da7c74a','登山城書事','文同','宋','宋诗','song-poetry','','[]','節物感羈旅，連空生塞陰。',48,'全唐诗/poet.song.25000.json','["節物感羈旅，連空生塞陰。", "亂鴻寒渚遠，群雀晚叢深。", "霜重涇灘出，烟高隴樹沉。", "歲華徒自老，幽憤滿登臨。"]'),
('7ddb0643-eef7-4138-bf2f-bff8676123cb','送夏殿直','文同','宋','宋诗','song-poetry','','[]','霜樹東門曉，清寒滿客衣。',48,'全唐诗/poet.song.25000.json','["霜樹東門曉，清寒滿客衣。", "一樽從此別，百兩幾時歸。", "漆水魚初薦，梁園雪正飛。", "高堂今遠郡，須念報春暉。"]'),
('26a244cc-2715-41ba-a30c-69a0b28f0742','送錢規判官歸蜀覲親遂之岳陽','文同','宋','宋诗','song-poetry','','[]','嚴風吹玉柱，有客動歸裝。',48,'全唐诗/poet.song.25000.json','["嚴風吹玉柱，有客動歸裝。", "古道轉危阪，全家行曉霜。", "休嗟遊薄宦，且喜拜高堂。", "會合知何所，春江泛楚艎。"]'),
('1a913211-0c96-4100-8439-8150b68f1dab','和梨花','文同','宋','宋诗','song-poetry','','[]','素質靜相依，清香暖更飛。',48,'全唐诗/poet.song.25000.json','["素質靜相依，清香暖更飛。", "笑從風外歇，啼向雨中歸。", "江令歌瓊樹，甄妃夢玉衣。", "畫堂明月地，常此惜芳菲。"]'),
('451810e5-c9ef-4840-a60f-47a71dff27ce','山櫻','文同','宋','宋诗','song-poetry','','[]','巖壁自叢叢，年華寂寞中。',48,'全唐诗/poet.song.25000.json','["巖壁自叢叢，年華寂寞中。", "偶因移曉雨，似欲占春風。", "嫩葉藏輕綠，繁葩露淺紅。", "孤根知幸否，從此對雕櫳。"]'),
('8a79309e-ce68-46f1-9990-cb186a50385b','秋子','文同','宋','宋诗','song-poetry','','[]','裊裊復翻翻，封條壓樹繁。',48,'全唐诗/poet.song.25000.json','["裊裊復翻翻，封條壓樹繁。", "群芳非姊妹，亂實見兒孫。", "蔭日臨虛檻，披風拂短垣。", "主人無奈爾，常爲醉幽軒。"]'),
('976ca1a4-7fe7-4563-b29d-2cae92f020cf','桃花','文同','宋','宋诗','song-poetry','','[]','種近短牆邊，開臨小檻前。',48,'全唐诗/poet.song.25000.json','["種近短牆邊，開臨小檻前。", "倚風無限意，笑日有餘妍。", "枝軟圍深密，苞穠墮碎圓。", "祗應芳樹下，時見武陵仙。"]'),
('4922a0c8-f339-42c7-95c6-694c187b5974','杏花','文同','宋','宋诗','song-poetry','','[]','仙杏一番新，妖饒洗露晨。',48,'全唐诗/poet.song.25000.json','["仙杏一番新，妖饒洗露晨。", "待粧憂粉重，欲點要酥勻。", "月淡斜分影，池清倒寫真。", "君須憐舊物，曾伴曲江春。"]'),
('9082ca65-4442-4ab0-89bf-0c537e6af197','秋日寄呂永壽微中','文同','宋','宋诗','song-poetry','','[]','落日照容谷，寥然官署秋。',48,'全唐诗/poet.song.25000.json','["落日照容谷，寥然官署秋。", "開簾臨絕巘，憑几對寒流。", "古意深中得，詩中靜外遊。", "三年多少景，滿篋是冥搜。"]'),
('148f9ee6-dd25-4c6b-bd7a-0bd61b45e971','吟春','文同','宋','宋诗','song-poetry','','[]','春工運潛巧，是處有行迹。',48,'全唐诗/poet.song.25000.json','["春工運潛巧，是處有行迹。", "庭梢發新穎，巖溜融暖脈。", "晴湖影撥剌，曉樹音格磔。", "須知玉峰下，日有尋芳客。"]'),
('0acf11ee-f40b-478c-b0a3-2ab684dc7e67','琵琶泉','文同','宋','宋诗','song-poetry','','[]','險道入幽邃，深溪轉岑寂。',48,'全唐诗/poet.song.25000.json','["險道入幽邃，深溪轉岑寂。", "蒼烟鬰孤岩，秀石圍斷壁。", "古蘚甃碧潤，寒泉灑清滴。", "誰能厭塵襟，茲可供洗滌。"]'),
('8dcfcf5e-2f4b-4f95-a216-11c3324f890c','和子山種花  其一','文同','宋','宋诗','song-poetry','','[]','風流從事季長家，繞遍官居種盡花。',32,'全唐诗/poet.song.25000.json','["風流從事季長家，繞遍官居種盡花。", "應爲清才無比敵，擬將文彩競春華。"]'),
('c8d23402-0b54-466c-8524-c9f07ece086a','和子山種花  其二','文同','宋','宋诗','song-poetry','','[]','碾薄䄩圓粉色勻，一枝寒艷惱青春。',32,'全唐诗/poet.song.25000.json','["碾薄䄩圓粉色勻，一枝寒艷惱青春。", "曉來带雨四廂下，恰似蓬萊見太真。"]'),
('0450c2e2-65c3-4a96-8761-21a644d1b377','和子山種花  其三','文同','宋','宋诗','song-poetry','','[]','曾宴瓊林爛熳紅，寶津樓下看春風。',32,'全唐诗/poet.song.25000.json','["曾宴瓊林爛熳紅，寶津樓下看春風。", "今朝忽向君家見，猶憶當年醉眼中。"]'),
('e338dd11-474b-4ba0-b596-866142b3d0f1','和子山種花  其四','文同','宋','宋诗','song-poetry','','[]','幾樹山櫻曲檻前，花開如火葉如烟。',32,'全唐诗/poet.song.25000.json','["幾樹山櫻曲檻前，花開如火葉如烟。", "待將短句誇形似，已被休文道欲燃。"]'),
('224236ab-c1e3-4e58-8b8d-18006d01d2e5','和子山種花  其五','文同','宋','宋诗','song-poetry','','[]','新自涇州趁雨移，便開繁萼擁芳枝。',32,'全唐诗/poet.song.25000.json','["新自涇州趁雨移，便開繁萼擁芳枝。", "紅霞照地清香起，似到玄都觀裏時。"]'),
('7efcec59-0a0b-453a-9cc0-5599af511180','和張屯田雪中朝拜天慶觀  其一','文同','宋','宋诗','song-poetry','','[]','簌簌遥空墮碎瓊，一街寒色曉風清。',32,'全唐诗/poet.song.25000.json','["簌簌遥空墮碎瓊，一街寒色曉風清。", "題輿想入簫臺下，似駕飈輪向玉京。"]'),
('d430f3f5-a498-494f-8732-07c132ca1121','和張屯田雪中朝拜天慶觀  其二','文同','宋','宋诗','song-poetry','','[]','寶幢珠節共玲瓏，九虎嚴關有路通。',32,'全唐诗/poet.song.25000.json','["寶幢珠節共玲瓏，九虎嚴關有路通。", "遥望玉宸端象簡，宛然身在廣寒宮。"]'),
('54be834d-8a62-4f4e-ad5f-663c16f2fd50','送酒與呂令答所示詩  其一','文同','宋','宋诗','song-poetry','','[]','君無彭澤五十畝，我有謫仙三百杯。',32,'全唐诗/poet.song.25000.json','["君無彭澤五十畝，我有謫仙三百杯。", "聞道山中足春意，滿壺聊爲撥新醅。"]'),
('1d7f0da3-10ee-4da5-89b1-eed33b1b3bc2','送酒與呂令答所示詩  其二','文同','宋','宋诗','song-poetry','','[]','見說西溪裏，群花艷正繁。',24,'全唐诗/poet.song.25000.json','["見說西溪裏，群花艷正繁。", "不知紅影下，誰共醉芳樽。"]'),
('32d2517a-9b34-4f62-8bc9-31d1b0384d94','初雪','文同','宋','宋诗','song-poetry','','[]','一色陰雲蔽曉空，粉英瓊屑亂茸茸。',32,'全唐诗/poet.song.25000.json','["一色陰雲蔽曉空，粉英瓊屑亂茸茸。", "不知遊騎將何處，已失南城玉柱峰。"]'),
('5f63c99f-16f6-4d4b-973f-2d6bec4dea23','對雪獨酌','文同','宋','宋诗','song-poetry','','[]','雲陰低重玉花繁，獨擁貂裘對一樽。',32,'全唐诗/poet.song.25000.json','["雲陰低重玉花繁，獨擁貂裘對一樽。", "不語佳賓是何物，古書名畫滿西軒。"]'),
('1672932f-7a11-4955-b0e3-ebe47732c85e','槐莊渡口','文同','宋','宋诗','song-poetry','','[]','雲烟飄泊樹微茫，一岸人家带夕陽。',32,'全唐诗/poet.song.25000.json','["雲烟飄泊樹微茫，一岸人家带夕陽。", "欲上高原便回首，可憐風物似吾鄉。"]'),
('18016af9-cb2b-4b8f-be51-4e56edc7f5ea','約春','文同','宋','宋诗','song-poetry','','[]','去歲相違恨已賒，今年相遇喜無涯。',32,'全唐诗/poet.song.25000.json','["去歲相違恨已賒，今年相遇喜無涯。", "紅情綠意知多少，盡入涇川萬樹花。"]'),
('ad7d3aad-bc32-4004-95b6-f3b6fa36f50b','和子山陪使君遊西湖三絕正月晦日  其一','文同','宋','宋诗','song-poetry','','["\u897f\u6e56"]','柳色繞堤金粉明，湖光浮岸玉烟輕。',32,'全唐诗/poet.song.25000.json','["柳色繞堤金粉明，湖光浮岸玉烟輕。", "風柔日薄恰新霽，正好訪春來此行。"]'),
('f265a9e4-19aa-445b-a92e-57ad85e6b870','和子山陪使君遊西湖三絕正月晦日  其二','文同','宋','宋诗','song-poetry','','["\u897f\u6e56"]','遊騎翩翩從使君，娛賓亭上宴西曛。',32,'全唐诗/poet.song.25000.json','["遊騎翩翩從使君，娛賓亭上宴西曛。", "座中不用頻辭酒，明日青春已一分。"]'),
('584fbe19-3a87-41a8-8526-349448f3def9','和子山陪使君遊西湖三絕正月晦日  其三','文同','宋','宋诗','song-poetry','','["\u897f\u6e56"]','滿眼垂楊照綠波，就中春意此先多。',32,'全唐诗/poet.song.25000.json','["滿眼垂楊照綠波，就中春意此先多。", "不將歌管酬佳景，擬奈翠漪堂上何。"]'),
('3d93b401-baaf-4f00-b960-6a7652a3346c','探春','文同','宋','宋诗','song-poetry','','[]','豳郊寒重勒春遲，消息如今尚未知。',32,'全唐诗/poet.song.25000.json','["豳郊寒重勒春遲，消息如今尚未知。", "只是垂楊最先得，每朝來覓向東枝。"]'),
('c7496151-8e64-444e-92f9-886ceb6abe2d','春寒','文同','宋','宋诗','song-poetry','','[]','東風何事力猶微，凜凜邊寒犯客衣。',32,'全唐诗/poet.song.25000.json','["東風何事力猶微，凜凜邊寒犯客衣。", "舊雪未消新雪下，南園春色幾時歸。"]'),
('b28647f5-7337-49bc-a133-3f1432a7cad3','新秋讀書','文同','宋','宋诗','song-poetry','','[]','高風發遠籟，轉響爲清商。',120,'全唐诗/poet.song.25000.json','["高風發遠籟，轉響爲清商。", "隆曦減炎威，未晚先自凉。", "庭前碧桐樹，昨日聞早霜。", "朝來逐葉上，已暈一拂黄。", "壯歲覺時節，㸌若翻電光。", "自顧勿嗟惋，徒然攪中腸。", "官居幸少事，署案日幾行。", "公退清且閑，垂簾坐虛堂。", "解带輒傲兀，左右羅縑緗。", "所務唯討論，一燈從夜長。"]'),
('abe6cd92-cdd2-41c4-a5c3-91506463ec37','貧士行','文同','宋','宋诗','song-poetry','','[]','側身入窮閻，跼影守環堵。',96,'全唐诗/poet.song.25000.json','["側身入窮閻，跼影守環堵。", "日高齒未嚼，風勁骭猶露。", "胡爲迫凍餓，此道吾所素。", "出每駕鷄棲，歸仍伏龍具。", "原生本非病，董子蓋不遇。", "誰將斗升水，活此轍中鮒。", "不見裹糧人，欲死者亦屢。", "徒自諷詩書，區區立名譽。"]'),
('3dbe1978-00d3-4d65-a7a8-c5733ae08c8d','馮氏道中早行','文同','宋','宋诗','song-poetry','','[]','畏暑事晨役，高原動征羈。',96,'全唐诗/poet.song.25000.json','["畏暑事晨役，高原動征羈。", "遥遥歷廣博，浩浩長風吹。", "疏星才出沒，河漢西南垂。", "林端啟明上，飛光發丹曦。", "熒熒灑晴露，百物含華滋。", "爽氣入肝鬲，宿濁無一絲。", "寒泉漱清甘，洗滌俗慮遺。", "還憂火輪怒，萬里燒雲逵。"]'),
('8800212d-9af0-4e0f-95a8-dbd3bccfaa45','宿李同年蔭碧亭','文同','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','抱病出煩闠，投此青林間。',72,'全唐诗/poet.song.25000.json','["抱病出煩闠，投此青林間。", "高軒得清凉，坐致精爽還。", "主人止之宿，借與終南山。", "中宵皓月起，繞枕皆孱顔。", "望久氣自清，心胸無結頑。", "平明又西走，勝軌不可攀。"]'),
('569a193a-a5be-4127-9063-71519a94c41e','李生畫鶴','文同','宋','宋诗','song-poetry','','[]','昂昂青田姿，杳杳在輕素。',72,'全唐诗/poet.song.25000.json','["昂昂青田姿，杳杳在輕素。", "一身萬里意，雙目九霄顧。", "釤釤羽翮利，竦竦骨節露。", "君初本誰學，我恐必神悟。", "得於想像外，看在絕筆處。", "稷筌如復生，相與較獨步。"]'),
('879f5315-3173-4327-8a37-f05b4b695a8e','豳州','文同','宋','宋诗','song-poetry','','[]','昔年戎馬盡南豳，今日風光已太文。',64,'全唐诗/poet.song.25000.json','["昔年戎馬盡南豳，今日風光已太文。", "雅吹夜喧金府月，靚粧春艷玉峰雲。", "泉亭柳色濃將滴，水寨荷香遠更薰。", "邏候不驚烽燧息，高原閑獵舊將軍。"]'),
('146df8a9-f271-4f65-b64b-d64f4b1eb966','寄友人','文同','宋','宋诗','song-poetry','','[]','惟秦抵於蜀，間可歷萬巇。',72,'全唐诗/poet.song.25000.json','["惟秦抵於蜀，間可歷萬巇。", "遥懷嚮英義，潛想一夕馳。", "乏人探道奧，求合常苦奇。", "見謂可招納，欲與相塤篪。", "夫何屢乖絕，出處各一涯。", "秋風動孤况，西首勞所思。"]'),
('a490629d-b689-494b-8150-c74e1b048acc','和仲蒙夜坐','文同','宋','宋诗','song-poetry','','[]','宿鳥驚飛斷雁號，獨憑幽几靜塵勞。',64,'全唐诗/poet.song.25000.json','["宿鳥驚飛斷雁號，獨憑幽几靜塵勞。", "風鳴北戶霜威重，雲壓南山雪意高。", "少睡始知茶效力，大寒須遣酒爭豪。", "硯冰已合燈花老，猶對群書擁敝袍。"]'),
('baf7886e-421a-49e0-adc6-6b5042faef8e','明教院','文同','宋','宋诗','song-poetry','','[]','野徑欹危入谷斜，曲崗回嶺共交加。',64,'全唐诗/poet.song.25000.json','["野徑欹危入谷斜，曲崗回嶺共交加。", "經年不到爲隔水，此日獨遊因看花。", "兩岸烟雲閑景物，一軒泉石靜生涯。", "自憐冠珮嬰身者，直入樊籠老歲華。"]'),
('253e68f8-0885-4f8f-8429-64ee9f4ebc18','和仲蒙夏日即事','文同','宋','宋诗','song-poetry','','[]','簿領初休几案清，西軒移枕卧前楹。',64,'全唐诗/poet.song.25000.json','["簿領初休几案清，西軒移枕卧前楹。", "香從菡萏紅苞發，粉入篔簹翠節生。", "不分便衰聞蟻鬥，可嗟俱妄見蝸爭。", "日長景靜官曹冷，莫厭頻來對一枰。"]'),
('dfa81d8c-85a8-4d42-8153-341d5b5b73da','西軒秋日','文同','宋','宋诗','song-poetry','','[]','官舍蕭然似隠居，一軒秋色伴恬如。',64,'全唐诗/poet.song.25000.json','["官舍蕭然似隠居，一軒秋色伴恬如。", "深藏宿雨樹木暗，高灑夕陽籬落疏。", "景物靜思臨水石，光陰閑覺入圖書。", "此心只有雲相信，長畔吟魂繞太虛。"]'),
('fe6b3331-0afd-47a1-9d11-8a6c4fcf1f2b','和張屯田秋晚靈峰東閣閑望','文同','宋','宋诗','song-poetry','','[]','直欄橫絕紫微陰，憑久秋光照客襟。',64,'全唐诗/poet.song.25000.json','["直欄橫絕紫微陰，憑久秋光照客襟。", "一道山川寒色遠，萬家烟火夕陽深。", "涇灘水落群鴉集，秦嶺雲高斷雁沉。", "此興浩然須把酒，可憐難醉異鄉心。"]'),
('0bd8fc37-3df6-45bf-a9a2-4e2210400ea1','春庭','文同','宋','宋诗','song-poetry','','[]','春院陰陰翠靄低，春庭寂寂曉光迷。',64,'全唐诗/poet.song.25000.json','["春院陰陰翠靄低，春庭寂寂曉光迷。", "花間蜂去抱黄粉，苔上燕來銜綠泥。", "兩行高梧初蔭合，一番新草恰生齊。", "微禽已識幽人意，飛下欄干向裏啼。"]'),
('bf362619-fd24-499e-9bc9-d5e194077293','過永壽縣','文同','宋','宋诗','song-poetry','','[]','驅馬上危坂，暮鞭摇客愁。',48,'全唐诗/poet.song.25000.json','["驅馬上危坂，暮鞭摇客愁。", "峰巒驚滿目，咫尺擬回頭。", "紅樹擁野店，白雲藏縣樓。", "須知此北下，地底見豳州。"]'),
('b5eaa324-74a2-4f66-ab16-32e55709f269','東谷偶成','文同','宋','宋诗','song-poetry','','[]','府事幸稀簡，常爲東谷遊。',48,'全唐诗/poet.song.25000.json','["府事幸稀簡，常爲東谷遊。", "舊山茲彷彿，佳景每遲留。", "斷續溪雲起，縱橫野水流。", "拂衣知未得，聊此慰鄉愁。"]'),
('c5f4942c-590f-446c-874c-e40820b1f864','宜祿昭仁寺後軒','文同','宋','宋诗','song-poetry','','[]','危欄憑絕壑，欲奈此時何。',48,'全唐诗/poet.song.25000.json','["危欄憑絕壑，欲奈此時何。", "但有夕陽處，就中秋色多。", "與誰同徙倚，空自發吟哦。", "便覺成羈旅，歸心逐雁過。"]'),
('403a1185-be98-4562-ae84-1f8ad7ff605a','過高塶城','文同','宋','宋诗','song-poetry','','[]','頹壁乍高低，中間已亂蹊。',48,'全唐诗/poet.song.25000.json','["頹壁乍高低，中間已亂蹊。", "長原想鵝鸛，大塚記鯨鯢。", "黯澹寒雲結，蕭疏野草齊。", "興亡盡遺迹，立馬看扶犁。"]'),
('12c9c280-c11a-43d4-9bd6-ed0ca1562475','夏日翠漪堂','文同','宋','宋诗','song-poetry','','[]','湖水碧溶溶，寒漪四望通。',48,'全唐诗/poet.song.25000.json','["湖水碧溶溶，寒漪四望通。", "龜魚遊浩渺，鳬鶩下虛空。", "爽氣吟窗外，清光釣艇中。", "一襟時自快，多謝北軒風。"]'),
('76df2ad1-a654-415b-84e9-b87e1a128585','玉峰園經春不得一過因成詩呈同官約遊','文同','宋','宋诗','song-poetry','','[]','春來少嬉遊，俗事日相耗。',48,'全唐诗/poet.song.25000.json','["春來少嬉遊，俗事日相耗。", "南園只城外，累月不一到。", "花香雨後歇，樹色風中老。", "惟有岩下泉，猶能滌幽抱。"]'),
('e145f786-1259-4df3-8cb7-871348c20959','送張兢無悔秘校赴調','文同','宋','宋诗','song-poetry','','[]','無悔富道誼，卷藏無所施。',48,'全唐诗/poet.song.25000.json','["無悔富道誼，卷藏無所施。", "端笏拜上官，十年走階墀。", "人皆爲嗟惋，君獨安且怡。", "又執考書去，當衡誰與知。"]'),
('4b30a6ea-54af-4039-87c6-176433e3c57b','六月十日中伏玉峰園避暑值雨','文同','宋','宋诗','song-poetry','','[]','南園避中伏，意適晚忘歸。',48,'全唐诗/poet.song.25000.json','["南園避中伏，意適晚忘歸。", "牆外谷雲起，檐前山雨飛。", "興餘思秉燭，坐久欲添衣。", "爲愛東岩下，泉聲通翠微。"]'),
('4a27d920-50c4-439c-9b4d-72c426e7fd00','咸陽道上晚晴有作','文同','宋','宋诗','song-poetry','','[]','積靄晚盡散，南山明夕陽。',48,'全唐诗/poet.song.25000.json','["積靄晚盡散，南山明夕陽。", "秋容遍豐鎬，古恨入隋唐。", "草木咸摇落，風烟自渺茫。", "客亭須下馬，把酒慰殊鄉。"]'),
('40ac9dcc-48fc-4d14-a498-4ab9f1ba1ded','歲晚登清素院北閣','文同','宋','宋诗','song-poetry','','[]','雲端訪古寺，樹杪臨危閣。',48,'全唐诗/poet.song.25000.json','["雲端訪古寺，樹杪臨危閣。", "風厲懾草木，霜乾喜雕鶚。", "天時既悽慘，人意亦寂寞。", "回念故山遠，心隨日西落。"]'),
('677ebaea-d392-473f-a634-061ab454eab3','炭泉險道','文同','宋','宋诗','song-poetry','','[]','一澗呀然截亂峰，更於何處問途窮。',64,'全唐诗/poet.song.25000.json','["一澗呀然截亂峰，更於何處問途窮。", "高深出井又入井，曲直上弓還下弓。", "絕底乍臨渾偪仄，危顛纔徹似飛沖。", "我來行縣須經此，正在炎炎三伏中。"]'),
('45bb6a29-24b4-45f4-a5f1-f348dadc5436','玉峰園避暑','文同','宋','宋诗','song-poetry','','[]','伏日當飲酒，南城會群賢。',48,'全唐诗/poet.song.25000.json','["伏日當飲酒，南城會群賢。", "開樽蔭碧樹，移席臨清泉。", "浩意脫塵土，高懷軼雲烟。", "早歸休信俗，須待月娟娟。"]'),
('e6a9256b-8d28-4ebd-975b-46f765f1427f','早起覽物成詠','文同','宋','宋诗','song-poetry','','[]','移枕出幽幌，披衣步前楹。',48,'全唐诗/poet.song.25000.json','["移枕出幽幌，披衣步前楹。", "秋容草木靜，曉氣烟雲輕。", "蟬噪宿露滴，雁飛朝霞明。", "塵心幸未動，聊此納餘清。"]'),
('251310e5-6e2f-490d-9bf3-1e2a6047b8ac','寄馮永州','文同','宋','宋诗','song-poetry','','[]','山水永最善，守居聞更優。',48,'全唐诗/poet.song.25000.json','["山水永最善，守居聞更優。", "烟雲萬石古，風月九岩秋。", "几案少俗事，壺觴多雅遊。", "無因陪後乘，幽意滿湘流。"]'),
('a77466cd-05af-4bee-9799-b13e5a741846','暑夕待月庭下夜深方歸','文同','宋','宋诗','song-poetry','','[]','晝蠅方少夜蚊多，摇脫霜紈奈熱何。',32,'全唐诗/poet.song.25000.json','["晝蠅方少夜蚊多，摇脫霜紈奈熱何。", "獨向中庭待明月，一身清露瀉金波。"]'),
('12d4ef9c-02ab-4309-b66d-fcac120dc6ba','中伏日諸君會玉峰余以病不預作詩寄呈','文同','宋','宋诗','song-poetry','','[]','去年中伏在南園，同聽清泉引綠樽。',32,'全唐诗/poet.song.25000.json','["去年中伏在南園，同聽清泉引綠樽。", "今日諸君又高會，獨嗟移疾卧西軒。"]'),
('7967e380-f276-4e30-a7a3-c1fffe87ece8','興平原上赤熱因寄永壽同年','文同','宋','宋诗','song-poetry','','[]','日午終南翠色燃，滿襟飛土下秦川。',32,'全唐诗/poet.song.25000.json','["日午終南翠色燃，滿襟飛土下秦川。", "是時獨想君高尚，正在山亭弄野泉。"]'),
('7959fef6-6fff-4348-9a9c-a0ebf16de61c','亭口','文同','宋','宋诗','song-poetry','','[]','林下翩翩雁影斜，滿川紅葉映人家。',32,'全唐诗/poet.song.25000.json','["林下翩翩雁影斜，滿川紅葉映人家。", "岩頭孤寺見橫閣，有客獨來登暮霞。"]'),
('849f0e36-5c79-4ada-a14f-bd5d471b6927','淺水原','文同','宋','宋诗','song-poetry','','[]','鶉觚西北地鱗鱗，此處當年起戰塵。',32,'全唐诗/poet.song.25000.json','["鶉觚西北地鱗鱗，此處當年起戰塵。", "見說如今溝壠下，斷鋒殘鏃屬耕民。"]'),
('b831d31e-a755-434d-a50d-a43e9abe17ec','興平原上','文同','宋','宋诗','song-poetry','','[]','東西車馬走秦川，擾擾飛塵混曉烟。',32,'全唐诗/poet.song.25000.json','["東西車馬走秦川，擾擾飛塵混曉烟。", "我亦中間遊宦者，尚慚無語賦歸田。"]'),
('984bc511-3125-4da3-813e-787a743f7511','西湖荷花','文同','宋','宋诗','song-poetry','','["\u897f\u6e56"]','紅苞綠葉共低昂，滿眼寒波映碧光。',32,'全唐诗/poet.song.25000.json','["紅苞綠葉共低昂，滿眼寒波映碧光。", "應是西風拘管得，是人須與一襟香。"]'),
('10ee2553-2182-4812-9e98-2951e509316d','石龍渦','文同','宋','宋诗','song-poetry','','[]','嶮勢圍空斷壁圓，四時常見聚雲烟。',32,'全唐诗/poet.song.25000.json','["嶮勢圍空斷壁圓，四時常見聚雲烟。", "爲霖救旱今何在，徒有遺文記昔年。"]'),
('d0d58dc8-a476-4313-9d1f-6cbce4798553','水葓','文同','宋','宋诗','song-poetry','','[]','紅芳宵露清，翠節曉霜犯。',24,'全唐诗/poet.song.25000.json','["紅芳宵露清，翠節曉霜犯。", "雨後曬殘日，秋容滿庭楹。"]'),
('b0a6ce89-ec59-48af-9492-b3100074b008','黄蜀葵','文同','宋','宋诗','song-poetry','','[]','錦江何日別，漆水今朝見。',24,'全唐诗/poet.song.25000.json','["錦江何日別，漆水今朝見。", "清露染顔色，秋鵝一分淺。"]'),
('d5d4b6e9-13ad-40a3-8be3-2d0afa2a9486','鼓子','文同','宋','宋诗','song-poetry','','[]','柔條長百尺，秀萼包千葉。',24,'全唐诗/poet.song.25000.json','["柔條長百尺，秀萼包千葉。", "不惜作高架，爲君相引接。"]'),
('53ce20c2-99a1-4515-9ccd-5d0f5bbe1e52','鄠上懷古','文同','宋','宋诗','song-poetry','','[]','未曉南山去，從禽夜不歸。',24,'全唐诗/poet.song.25000.json','["未曉南山去，從禽夜不歸。", "凡行多少地，十二所更衣。"]'),
('d53edb5c-46c7-41eb-b02f-5de0387b1ce0','石竹','文同','宋','宋诗','song-poetry','','[]','蜂齧紅蕊爛，蟲啼碧叢短。',24,'全唐诗/poet.song.25000.json','["蜂齧紅蕊爛，蟲啼碧叢短。", "秋風略地起，惟有蒼苔管。"]'),
('07e21bd6-b447-4812-a18f-7b1047d4613b','邛州東園晚興','文同','宋','宋诗','song-poetry','','[]','公休時得岸輕紗，門外誰知吏隠家。',64,'全唐诗/poet.song.25000.json','["公休時得岸輕紗，門外誰知吏隠家。", "鬥鴨整群翻荇葉，乳烏無數墮松花。", "携琴秀野彈流水，設席芳洲詠落霞。", "向晚雙親共諸子，相將來此樂無涯。"]'),
('af16a317-a574-4d28-8f42-a7176459cdae','雨過側調','文同','宋','宋诗','song-poetry','','[]','陰車飛空載急雨，雨過林塘若新換。',64,'全唐诗/poet.song.25000.json','["陰車飛空載急雨，雨過林塘若新換。", "檉花浮波魚誤食，松子落屋烏驚彈。", "白雲挂樹久不起，青烟泊草殊未散。", "東園傲吏愛高竹，把卷倚風頭髪亂。"]'),
('0fe1d0d9-76a4-46f8-8cb4-e2345acf793b','題象耳山寺','文同','宋','宋诗','song-poetry','','[]','轉谷縈巖路始窮，隔林遥望一門通。',64,'全唐诗/poet.song.25000.json','["轉谷縈巖路始窮，隔林遥望一門通。", "溪山俱在見聞外，臺殿盡藏懷抱中。", "像閣罘罳明海日，經幢瓔珞撼天風。", "勞生又逐輕舠去，珍重高僧解苦空。"]'),
('5ec02f43-d3e4-4624-8fca-f51c1ba63edb','題晉原舒太博清溪閣','文同','宋','宋诗','song-poetry','','[]','危閣飛空羽翼開，下蟠波面影徘徊。',64,'全唐诗/poet.song.25000.json','["危閣飛空羽翼開，下蟠波面影徘徊。", "光摇畫板月深淺，聲繞曲欄風往來。", "暝色四郊烟莽蒼，曉雲千嶂雪崔嵬。", "主人好事民無訟，日夕登遊對酒杯。"]'),
('62335b78-01bb-4bae-b99d-287f7bd86f53','縣樓獨酌','文同','宋','宋诗','song-poetry','','[]','向晚無公事，身如太古閑。',48,'全唐诗/poet.song.25000.json','["向晚無公事，身如太古閑。", "縣樓明夕照，樽酒對南山。", "放意利名外，遊心天地間。", "生來不能飲，到此學酡顔。"]'),
('2f257ea4-b587-4b99-8242-52fc92b51f33','殘秋郊外','文同','宋','宋诗','song-poetry','','[]','蕭蕭風色弄寒威，見盡郊原向晚暉。',64,'全唐诗/poet.song.25000.json','["蕭蕭風色弄寒威，見盡郊原向晚暉。", "昨夜星霜和月落，滿林紅葉隔烟飛。", "已嗟北渚蓮初老，更惜東籬菊漸稀。", "休感歲華傷節物，眼前樽酒重相違。"]'),
('4ddff5b0-c22b-4496-b5f4-9e439c15e9a6','郊外','文同','宋','宋诗','song-poetry','','[]','城市壓塵土，高原聊振衣。',48,'全唐诗/poet.song.25000.json','["城市壓塵土，高原聊振衣。", "晚雲多淺碧，秋樹半深緋。", "江氣雜輕靄，山光明落暉。", "因成求好景，更就野橋歸。"]'),
('0e8e6ef2-a019-4597-aeaa-3ce1b9bdd4a1','靜林詩僧已老','文同','宋','宋诗','song-poetry','','[]','七十吟中老，清風滿舊林。',48,'全唐诗/poet.song.25000.json','["七十吟中老，清風滿舊林。", "倚筇秋岸遠，圍衲夜房深。", "未得雲空在，將成月已沉。", "生平苦如此，誰是識師心。"]'),
('348bb4ca-7df9-460d-a756-c2928051bb9d','高堂山兜率寺','文同','宋','宋诗','song-poetry','','[]','孤絕不可狀，此山餘舊聞。',48,'全唐诗/poet.song.25000.json','["孤絕不可狀，此山餘舊聞。", "因官多暇日，與客到深雲。", "門外一塵斷，座中千里分。", "勞生當自去，繚繞下西曛。"]'),
('7cad8b83-fb85-4aea-ba1a-753f39a1c9e7','閑居院上方晚景','文同','宋','宋诗','song-poetry','','[]','繞岩縈谷到禪扃，更上危顛最上亭。',64,'全唐诗/poet.song.25000.json','["繞岩縈谷到禪扃，更上危顛最上亭。", "風攪亂鴉盤古木，雨催群鷺下寒汀。", "秋田溝壠如棋局，晚岫峰巒若畫屏。", "詩已就成終夕去，遠村燈火一星星。"]'),
('1744ff5c-d6c2-4378-b821-1f87ecdc6b96','李道士惠琴軒集  其一','文同','宋','宋诗','song-poetry','','[]','驅役精魂入大幽，滿編奇絕盡冥搜。',64,'全唐诗/poet.song.25000.json','["驅役精魂入大幽，滿編奇絕盡冥搜。", "不教天地略容隠，應與鬼神同訪求。", "海藏光芒開寶玉，羽林鋒刃立戈矛。", "蕭臺自好携歸去，莫向人間苦暗投。"]'),
('465609e8-5b17-4d0b-8b24-b1479c28cc77','李道士惠琴軒集  其二','文同','宋','宋诗','song-poetry','','[]','壽寧孫老畫壁下，當日偶同君此行。',144,'全唐诗/poet.song.25000.json','["壽寧孫老畫壁下，當日偶同君此行。", "是時衆裏略一揖，自爾乃得君詩名。", "風馳雨絕十五載，此地忽爾相逢迎。", "見投琴軒兩大集，寶匣金鑰緘瑶瓊。", "未開試使道所有，毛髪寒豎肝膽驚。", "歸來燒燈讀至曉，句險字硬才力獰。", "君身長不滿三尺，萬象何術獨手擎。", "嗟我氣俗音韻淺，不敢與君相和鳴。", "聊書短歌報佳惠，它日願將朝七瓔。"]'),
('0b487689-98bd-4400-ac15-490b5be45fdc','彭山縣君居','文同','宋','宋诗','song-poetry','','[]','公館靜寥寥，園亭景物饒。',48,'全唐诗/poet.song.25000.json','["公館靜寥寥，園亭景物饒。", "溪光明短彴，樹影蔭危譙。", "山鳥忽雙下，池魚時一跳。", "主人王事簡，文酒日逍遥。"]'),
('533f4c19-0127-428d-8d06-eb0eac183735','下金鷄山','文同','宋','宋诗','song-poetry','','[]','峽束幾重烟，山分數尺天。',24,'全唐诗/poet.song.25000.json','["峽束幾重烟，山分數尺天。", "岩猿與溪鳥，一似過飛仙。"]'),
('19bb5d6a-54e7-4986-a4e0-f531e385d01d','過金鷄關','文同','宋','宋诗','song-poetry','','[]','關頭氣象古，關下風烟淡。',48,'全唐诗/poet.song.25000.json','["關頭氣象古，關下風烟淡。", "春深草木活，嵐重坑谷暗。", "禽聲著部奏，花色成窠勘。", "歸鞍雖若水，留此亦能暫。"]'),
('8cef205e-9062-4631-9263-896e52d75dc3','夜靜獨登小閣有所見因書','文同','宋','宋诗','song-poetry','','[]','危閣橫空蔽野扉，夜深來上久忘歸。',64,'全唐诗/poet.song.25000.json','["危閣橫空蔽野扉，夜深來上久忘歸。", "水光瀲灧和烟動，雲色褵褷夾月飛。", "隔岸葦村聞笛遠，背灣松塢見燈微。", "此間自得吟中樂，不覺霜華滿盡衣。"]'),
('426e4dd7-272b-48ba-94cb-f59d40a657d0','送黄夢得','文同','宋','宋诗','song-poetry','','[]','去年輕舳過巫山，今日羸驂度劍關。',64,'全唐诗/poet.song.25000.json','["去年輕舳過巫山，今日羸驂度劍關。", "孤客每嗟隨斷梗，慈親常把夢連環。", "蘭陔歲晚雖堪采，桂窟春深正好攀。", "决取榮科歸舊里，板輿迎侍且承顔。"]'),
('23fd1625-c327-45f7-ad9e-36862daf0939','送郭方叔南充簿','文同','宋','宋诗','song-poetry','','[]','六月東山道，炎風滿去鞍。',48,'全唐诗/poet.song.25000.json','["六月東山道，炎風滿去鞍。", "譙周之舊里，仇覽此初官。", "簿領無煩壅，圖書好燕安。", "清朝名路闊，慎勿學長嘆。"]'),
('aabd22fd-e5c3-40ff-bec2-76f3e7aa67ac','送張郭二秀才赴舉','文同','宋','宋诗','song-poetry','','[]','二子共齎刀，翩翩去意豪。',48,'全唐诗/poet.song.25000.json','["二子共齎刀，翩翩去意豪。", "負才皆萬選，入守定雙高。", "上道梅薰袖，還家草映袍。", "須知本鴻鵠，終不在蓬蒿。"]'),
('7a2ebb79-d6e5-4079-b93f-4aaedef5564c','謝人寄蒙頂新茶','文同','宋','宋诗','song-poetry','','[]','蜀土茶稱盛，蒙山味獨珍。',144,'全唐诗/poet.song.25000.json','["蜀土茶稱盛，蒙山味獨珍。", "靈根託高頂，勝地發先春。", "幾樹初驚暖，群籃競摘新。", "蒼條尋暗粒，紫萼落輕鱗。", "的皪香瓊碎，䰐鬖綠蠆勻。", "慢烘防熾炭，重碾敵輕塵。", "無錫泉來蜀，乾崤盞自秦。", "十分調雪粉，一啜咽雲津。", "沃睡迷無鬼，清吟健有神。", "冰霜疑入骨，羽翼要騰身。", "磊磊真賢宰，堂堂作主人。", "玉川喉吻澀，莫惜寄來頻。"]'),
('f5b1e6a3-7856-4dc8-a4fe-6f5974d038ae','謝許判官惠茶圖茶詩','文同','宋','宋诗','song-poetry','','[]','成圖畫茶器，滿幅寫茶詩。',48,'全唐诗/poet.song.25000.json','["成圖畫茶器，滿幅寫茶詩。", "會說工全妙，深諳句特奇。", "盡將爲遠贈，留與作閑資。", "便覺新來癖，渾如陸季疵。"]'),
('a1f65215-37b3-438d-990c-4b59bca34500','雨後看山因憶黄世南先生詩以相招','文同','宋','宋诗','song-poetry','','[]','新霜夜落群梢鳴，群風刮天爲早晴。',224,'全唐诗/poet.song.25000.json','["新霜夜落群梢鳴，群風刮天爲早晴。", "南山向曉盡張列，頹嶺斷壑當空橫。", "開軒一見喜無量，走上高閣臨飛甍。", "層欄倚遍不能下，狀貌秀活圍雙睛。", "奔騰遠近若波浪，愛極擬去中間行。", "此時只恨少佳客，相共叫笑誇崢嶸。", "我思黄子者奇士，趣向超越無俗情。", "手提詩筆若椽大，到處詠物物有名。", "我今此縣頗幽僻，復在歲杪天氣清。", "溪中魚蟹易尋覓，林下梨栗新收盛。", "子如訪我住旬浹，此品可備盤與觥。", "遂馳僕馬去邀子，願子爲我聊出城。", "私心不獨徒見子，亦願播此山之聲。", "子如不見不爲詠，可惜此山虛此生。"]'),
('7fd9670e-a6f1-4102-8f50-e828ce92efdd','送楊議卿赴舉','文同','宋','宋诗','song-poetry','','[]','寒日照殘樹，新霜結衰草。',60,'全唐诗/poet.song.25000.json','["寒日照殘樹，新霜結衰草。", "有客奉高薦，策馬奔遠道。", "聲名近轉大，文字素已好。", "壯歲雖可恃，榮科亦宜早。", "勉自報春暉，高堂親髪老。"]'),
('0e68e993-c3aa-42c9-a6e0-52b91a16243e','和楊仲軻春難度  其一','文同','宋','宋诗','song-poetry','','[]','春難度。',32,'全唐诗/poet.song.25000.json','["春難度。", "紅梢梢，尋縷縷。", "朝披烟，暮結雨。", "勸君飲酒莫用訴。", "春難度。"]'),
('c97d3391-1895-426f-8eda-fd47f4c62fc9','和楊仲軻春難度  其二','文同','宋','宋诗','song-poetry','','[]','春難度。',32,'全唐诗/poet.song.25000.json','["春難度。", "歌滿闋，酒萬舉。", "喉欲破，腸欲腐。", "風光滿天已不暮。", "春難度。"]'),
('42246f19-e494-42c1-a3d5-53be46e7f3d7','和楊仲軻春難度  其三','文同','宋','宋诗','song-poetry','','[]','春難度。',32,'全唐诗/poet.song.25000.json','["春難度。", "池浮花，牆擁絮。", "枕書睡，樹陰午。", "日長幾何萬尺許。", "春難度。"]'),
('28be6807-0804-4418-851d-d75edc844ccc','和何靖山人海棠','文同','宋','宋诗','song-poetry','','[]','爲愛香苞照地紅，倚欄終日對芳叢。',32,'全唐诗/poet.song.25000.json','["爲愛香苞照地紅，倚欄終日對芳叢。", "夜深忽憶高枝好，把酒更來明月中。"]'),
('ef06af96-2db0-4080-b808-500680c22149','訪李奐山人隠居','文同','宋','宋诗','song-poetry','','[]','多暇無所適，故來尋隠君。',48,'全唐诗/poet.song.25000.json','["多暇無所適，故來尋隠君。", "搴開壓屋樹，觸散擁門雲。", "狀貌不妨古，言談何太文。", "令人重高趣，歸去每斜曛。"]'),
('77a4f747-9dbd-40e8-a731-0326bb8c2349','冬晚書事','文同','宋','宋诗','song-poetry','','[]','倚杖立亭皋，寒威向曉豪。',48,'全唐诗/poet.song.25000.json','["倚杖立亭皋，寒威向曉豪。", "雪乾山色老，風烈樹聲高。", "殘日千鴉舞，孤雲一雁號。", "自然成感物，不覺首重搔。"]'),
('3b6d58d7-0251-46ec-93bb-242c6fec0d8e','晚次江上','文同','宋','宋诗','song-poetry','','[]','宛轉下江岸，霜風繞人衣。',48,'全唐诗/poet.song.25000.json','["宛轉下江岸，霜風繞人衣。", "翩翩渚鴻墮，冉冉林鴉歸。", "前壑已重靄，遠峰猶落暉。", "孤舟欲何處，劃浪去如飛。"]'),
('eff5cae2-5be8-4ecc-be5e-41f3088556b4','十月梅花','文同','宋','宋诗','song-poetry','','[]','十月凍牆隈，英英見早梅。',144,'全唐诗/poet.song.25000.json','["十月凍牆隈，英英見早梅。", "應從九地底，先領一陽來。", "紫膜紛紛脫，黄膚迤迤開。", "得風渾自變，與雪欲成堆。", "細暈輕檀口，濃粧膩粉腮。", "月娥身解寫，青女手能裁。", "冷艷浮冰沼，清香落玉杯。", "只憂融乳酪，不惜露瓊瑰。", "避妒情堪重，禁寒術可猜。", "有誰憐寂寞，盡日獨徘徊。", "共語誠無計，將題耻不才。", "東鄰夜夜客，莫放笛聲哀。"]'),
('f3e48608-d09c-400b-96c6-46f9e6c56518','吉祥院','文同','宋','宋诗','song-poetry','','[]','欹危一逕通，下馬轉深叢。',48,'全唐诗/poet.song.25000.json','["欹危一逕通，下馬轉深叢。", "便是塵寰外，可憐烟塢中。", "修篁寒滴雨，老柏靜吟風。", "日暮庭前樹，歸鴉自繞空。"]'),
('96bc1f51-7fa2-41f5-90e3-f086e0c7eebf','書鶴鳴化壁','文同','宋','宋诗','song-poetry','','[]','晚氣陰陰別作寒，夕陽林下動歸鞍。',32,'全唐诗/poet.song.25000.json','["晚氣陰陰別作寒，夕陽林下動歸鞍。", "忽然人報後山雪，更上上清宮上看。"]'),
('48f64e02-6df3-4fa8-a219-d8301ef95450','題鶴鳴化上清宮','文同','宋','宋诗','song-poetry','','[]','秘宇壓孱顔，飛梯上屈盤。',48,'全唐诗/poet.song.25000.json','["秘宇壓孱顔，飛梯上屈盤。", "清流抱山合，喬樹來雲寒。", "地古芝英折，岩秋石乳乾。", "飈輪遊底處，空自立層壇。"]'),
('84104195-25ba-49f1-9ac3-30bc58da5539','寄題何靖山人隠居','文同','宋','宋诗','song-poetry','','[]','門外鋪寒水，牆頭立好山。',48,'全唐诗/poet.song.25000.json','["門外鋪寒水，牆頭立好山。", "先生忘勢利，高隠寄中間。", "鳬鶩應同樂，烟雲已共閑。", "幾時能少暇，携酒到松關。"]'),
('bf025fbb-c96b-432c-b463-fd5492084c00','寄楞嚴大師','文同','宋','宋诗','song-poetry','','[]','錦官城裏寺，一室若雲峰。',48,'全唐诗/poet.song.25000.json','["錦官城裏寺，一室若雲峰。", "水縮秋吟鼎，霜低夜講松。", "住齋塵入鉢，出定蘚生筇。", "曾聽三摩義，居常夢曉鐘。"]'),
('1bc2c5e6-76a9-4aa4-b9e0-13b8675647a0','揖山閣','文同','宋','宋诗','song-poetry','','[]','一問此孤高，蒼蒼欲上摩。',48,'全唐诗/poet.song.25000.json','["一問此孤高，蒼蒼欲上摩。", "有時臨縹緲，盡日對嵯峨。", "絕底秋陰重，危層晚照多。", "無由從隠者，空自愧雲蘿。"]'),
('95cc3cd1-b2b5-4e48-bc3d-80cfd3db6550','杳杳堂','文同','宋','宋诗','song-poetry','','[]','杳杳堂何者，余常此養愚。',48,'全唐诗/poet.song.25000.json','["杳杳堂何者，余常此養愚。", "放身依曲几，忘慮若枯株。", "莊老題書冊，喬松列畫圖。", "客來休見問，非爾識于于。"]'),
('ae47048e-acdd-48c2-85f9-7a2c907721ce','安仁道中早行','文同','宋','宋诗','song-poetry','','[]','行馬江頭未曉時，好風無限滿輕衣。',64,'全唐诗/poet.song.25000.json','["行馬江頭未曉時，好風無限滿輕衣。", "寒蟬噪月成番起，野鴨驚沙作隊飛。", "揭揭酒旗當岸立，翩翩魚艇隔灣歸。", "此間物象皆新得，須信詩情不可違。"]'),
('92c1f8ac-ed15-4d04-acd5-15c37ed3b1ee','竹閣','文同','宋','宋诗','song-poetry','','[]','回廡抱曾閣，蕭然深且虛。',48,'全唐诗/poet.song.25000.json','["回廡抱曾閣，蕭然深且虛。", "畫欄憑曲曲，高竹愛疏疏。", "塵滓外不到，衣襟清有餘。", "每來聊自適，幽意滿琴書。"]'),
('4e20efb2-205e-4795-bb52-b88a3fbeac51','尋春','文同','宋','宋诗','song-poetry','','[]','馬行如疾輪，十里去尋春。',48,'全唐诗/poet.song.25000.json','["馬行如疾輪，十里去尋春。", "盎盎日光麗，鮮鮮雲色新。", "樓臺出花木，道路夾松筠。", "欲買前村酒，陶然作醉人。"]'),
('08f8af11-906d-41e5-b356-3f379a428a1a','太博孫公游火井因寄','文同','宋','宋诗','song-poetry','','[]','七盤雲道與雲浮，下見高林壓縣樓。',64,'全唐诗/poet.song.25000.json','["七盤雲道與雲浮，下見高林壓縣樓。", "覽景莫能陪後乘，臨風空自憶前遊。", "已聞去日謀詩席，更羨歸時就釣舟。", "好句定知酬不得，盡將奇詭入冥搜。"]'),
('7a80751e-e888-4b08-9a1e-a1b7d322333c','墅居','文同','宋','宋诗','song-poetry','','[]','林下覽清曠，此懷殊不羈。',48,'全唐诗/poet.song.25000.json','["林下覽清曠，此懷殊不羈。", "散行輕幘便，獨酌小甌宜。", "自可追三樂，何須作五噫。", "世情歌笑外，紛擾竟何爲。"]'),
('678fe604-1e6b-43db-a9e6-e3e6f776056b','面川亭','文同','宋','宋诗','song-poetry','','[]','幽亭最孤絕，直入亂叢間。',48,'全唐诗/poet.song.25000.json','["幽亭最孤絕，直入亂叢間。", "近晚獨來此，有誰相與閑。", "卷簾通大野，臨檻數前山。", "便欲教携酒，陶然踏月還。"]'),
('904eae63-b70b-406e-83a2-3ac22b2e2fc3','南亭','文同','宋','宋诗','song-poetry','','[]','晚衙初散吏人歸，獨立南亭著道衣。',32,'全唐诗/poet.song.25000.json','["晚衙初散吏人歸，獨立南亭著道衣。", "淺酒小詩聊自樂，此心渾欲外輕肥。"]'),
('c329b3fa-25d7-482c-816f-078808bb2c6a','北郭','文同','宋','宋诗','song-poetry','','[]','繞樹垂蘿蔭曲堤，暖烟深處亂禽啼。',32,'全唐诗/poet.song.25000.json','["繞樹垂蘿蔭曲堤，暖烟深處亂禽啼。", "何人來此共携酒，可惜拒霜花一谿。"]'),
('3e1720b2-b8d7-4ae0-95d9-decb77d76da3','讀史','文同','宋','宋诗','song-poetry','','[]','不得滎陽遂失秦，始知成敗盡由人。',32,'全唐诗/poet.song.25000.json','["不得滎陽遂失秦，始知成敗盡由人。", "可憐一擲贏天下，只使黄金四萬斤。"]'),
('095c7ed4-6548-4a15-b08b-b7cec1e49fc8','夜學','文同','宋','宋诗','song-poetry','','[]','已叨名第雖堪放，未到根原豈敢休。',32,'全唐诗/poet.song.25000.json','["已叨名第雖堪放，未到根原豈敢休。", "文字一床燈一盞，只應前世是深讎。"]'),
('86acffdd-5e09-4d61-ab57-016f01f1f109','畫眉禽','文同','宋','宋诗','song-poetry','','[]','盡日閑窗生好風，一聲初聽下高籠。',32,'全唐诗/poet.song.25000.json','["盡日閑窗生好風，一聲初聽下高籠。", "公庭事簡人皆散，如在千岩萬壑中。"]'),
('247a04fc-07e0-431a-af07-0d6dfe4764c3','鶑','文同','宋','宋诗','song-poetry','','[]','濃染羽毛深畫眉，曉來風日正晴時。',32,'全唐诗/poet.song.25000.json','["濃染羽毛深畫眉，曉來風日正晴時。", "只應自道新聲好，啼遍後園花萬枝。"]'),
('980d8062-dafd-4497-ac3d-53c1a656f6e2','佛頭','文同','宋','宋诗','song-poetry','','[]','公暇常來此處遊，碧波蒼巘解相留。',32,'全唐诗/poet.song.25000.json','["公暇常來此處遊，碧波蒼巘解相留。", "翩然又向城中去，回顧溪山只自羞。"]'),
('9853607a-f9c8-4f49-a182-6fd9aa2e6542','和子平弔猿','文同','宋','宋诗','song-poetry','','[]','去年汶山花平僧，求得匡猿遠相寄。',352,'全唐诗/poet.song.25000.json','["去年汶山花平僧，求得匡猿遠相寄。", "來時野性已馴熟，趫捷輕便殊可憙。", "呼來遣去會人語，一成已絕歸山意。", "置之眼前看不足，解去絛索令自恣。", "月明木杪倚風嘯，天暖花陰向陽睡。", "兒童圍繞賓客惜，倒挂橫跳衒嬉戲。", "豢夫每日費提舉，未始時節虧飲飼。", "前時忽來報之病，抱立階前自臨視。", "與之柿栗不肯顧，局脚埋頭交兩臂。", "毛焦色暗肉攣縮，斗覺精神變憔悴。", "尋常忽然遇小疾，不過蜘蛛噉三四。", "咽喉才下即無恙，何此不效况頻餌。", "今朝霜風冷入骨，早遣之問云已斃。", "人情不免爲傷怛，退自悔恨中且愧。", "重巒複岫本其樂，大薄長林違爾志。", "苦將韁鎖强維縶，不究天年良有自。", "遣人包裹瘞深僻，不使筋骸屬螻蟻。", "西鄰子平最好事，聞之搏髀嘆無已。", "再三慘怛來訪問，歸作長篇踰百字。", "其詞讀之甚悽愴，亦謂一鬰嘆其死。", "復推物理重相慰，聚有散無皆偶爾。", "把之庭下讀復讀，仰望高株一歔欷。"]'),
('2a1ce6b5-0240-4cac-bceb-48430f6f2f0a','和子平悼馬','文同','宋','宋诗','song-poetry','','[]','生來未嘗畜良馬，近得此駒誠可嘉。',208,'全唐诗/poet.song.25000.json','["生來未嘗畜良馬，近得此駒誠可嘉。", "骨節權奇毛肉好，此種無乃真渥洼。", "健蹄駸駸穩而疾，歷目一過如飛霞。", "自歸官下少出入，惟是芻粟意轉加。", "前時相期好天色，往返百里馳平沙。", "誰謂兵奴踠其足，針烙熨裏成瘢痂。", "立多氣毒憤入肺，雙膁攢縮兩鼻呀。", "庸工謬藥久不效，倒死櫪下鬃髟髿。", "敝帷一區瘞以贈，惜爾命薄如萎花。", "子平平時最愛爾，對客滿坐常洪誇。", "今朝見爾忽斃踣，重以好詩形嘆嗟。", "嗟余逐貧官職小，此馬豈合居余家。", "從今但只跨款段，壞轡破鞍仍短檛。"]'),
('f33e2752-4576-41cf-9f41-0421574eea4b','冷瓶','文同','宋','宋诗','song-poetry','','[]','海南有陶器，質狀矮而𡐦。',168,'全唐诗/poet.song.25000.json','["海南有陶器，質狀矮而𡐦。", "云初日炙就，鍛鑠不以火。", "水壺醜突兀，酒甒肥磥砢。", "山罍頸微腫，石鼎足已跛。", "圓如鴟夷形，大比康瓠顆。", "華元腹且皤，王莽口何哆。", "蕃胡入中國，萬里隨大舸。", "携之五羊市，巾匱費包裹。", "侏儷講其效，瀉辯若炙輠。", "課以沸泉沃，冰雪變立可。", "炙敲療中渴，其用豈幺麽。", "君凡幾錢得，不惜持遺我。", "曾將對佳客，屢試輒亦果。", "勿云遠且陋，幸可置之左。"]'),
('312b4231-719f-4b57-86a2-e8225227ae2e','中秋夜試院寄子平','文同','宋','宋诗','song-poetry','','[]','憶初我來時，夜色如墨障。',168,'全唐诗/poet.song.25000.json','["憶初我來時，夜色如墨障。", "心常念明月，幾日西南上。", "松梢倚樓角，一玦偃相向。", "漸見輪中物，依稀吐形狀。", "今宵東嶺外，灧灧金波漲。", "人間重此夕，一歲號佳賞。", "而我督秋試，鎖宿密如藏。", "細務紛滿前，約束甚鞿鞅。", "無由奉朋侶，徹曉坐清曠。", "之人富才華，筆力趫且壯。", "誰陪把樽酒，露下與酬唱。", "南牆咫尺地，使我起遐想。", "人生此良會，可惜已虛放。", "獨立中夜歸，俯首入書幌。"]'),
('28694a5f-ff64-4ff0-8e6d-afd612ab1067','贈城南觀音院庵主廣師','文同','宋','宋诗','song-poetry','','[]','簿領日嬰薄，紛然汩幽襟。',96,'全唐诗/poet.song.25000.json','["簿領日嬰薄，紛然汩幽襟。", "駕言出城南，聊欲清此心。", "平岡見凈剎，石逕鬰以深。", "中有苦空人，峭健奇骨森。", "十年一庵下，形迹了莫尋。", "兀如擁敗褐，口吐衆妙音。", "時下寂照堂，聲絕響亦沈。", "默矣蓋自得，其誰知少林。"]'),
('6178fdc6-8642-49fc-99be-6c16bb9931da','送韓震都官監渭州酒韓近悼亡','文同','宋','宋诗','song-poetry','','[]','士師每失官，未始有憂慍。',96,'全唐诗/poet.song.25000.json','["士師每失官，未始有憂慍。", "園吏既喪婦，何嘗復嗟憤。", "二子道義勝，一與天理順。", "之人乃其徒，心迹兩相近。", "區區赴窮塞，而使賣官醖。", "胸中浩然者，俗口不得問。", "好軍此開府，遇士以恩信。", "若訪禦戎策，請爲講三陣。"]'),
('d3847477-1499-4d2f-bc43-c8128a4bf2e6','成都楊氏江亭','文同','宋','宋诗','song-poetry','','[]','汀洲烟雨卷輕霏，遥望軒窗隠翠圍。',64,'全唐诗/poet.song.25000.json','["汀洲烟雨卷輕霏，遥望軒窗隠翠圍。", "萬嶺西來供曉色，一江南下載晴暉。", "鳬鷗慣入闌干宿，魚蟹長隨舴艋歸。", "我亦舊多滄海思，幾時如此得苔磯。"]'),
('657bc125-d57e-4b23-995e-bb0c5759593d','漢州王氏林亭','文同','宋','宋诗','song-poetry','','[]','短彴疏籬入野扃，竹烟松露滿襟清。',64,'全唐诗/poet.song.25000.json','["短彴疏籬入野扃，竹烟松露滿襟清。", "奔湍激險飛寒響，弱蔓穿深挂晚英。", "惜去更觀曾畫壁，記來重注舊題名。", "門前便是紅塵道，誰肯同過洗俗纓。"]'),
('35bfd3f9-a7ee-4302-83dc-dbe17c7f1b00','春雪呈知府龍圖','文同','宋','宋诗','song-poetry','','[]','朧朧玉魄沉霄彩，蔌蔌瑶花破曉陰。',64,'全唐诗/poet.song.25000.json','["朧朧玉魄沉霄彩，蔌蔌瑶花破曉陰。", "和氣所蒸緣異政，豐年之兆慰群心。", "畫樓卷白歡聲洽，遊騎障泥樂意深。", "太守安閑民訟息，錦城無限好園林。"]'),
('500f1b61-7bfb-45ef-b8a5-2e7b9f0a79e6','同蘇秘丞子平登延暉故亭','文同','宋','宋诗','song-poetry','','[]','城端有亭餘故基，吏曰舊榜題延暉。',64,'全唐诗/poet.song.25000.json','["城端有亭餘故基，吏曰舊榜題延暉。", "行穿蒙籠倚孤陴，霜風飄蕭吹我衣。", "高林滿郊目四圍，雲起日落晴烟飛。", "感今念往聊久之，埤堄昏黑群鴉歸。"]'),
('88238c54-4e3b-4b79-948a-9d693245a279','金桃','文同','宋','宋诗','song-poetry','','[]','雨染烟蒸萬實垂，丹硃爲骨菊爲衣。',64,'全唐诗/poet.song.25000.json','["雨染烟蒸萬實垂，丹硃爲骨菊爲衣。", "客疑麗水新淘得，人向瑶池舊带歸。", "只恐壓枝星欲落，最憐和葉露初晞。", "銀瓜玉李君休并，此品仙家亦自稀。"]'),
('618032af-bdbe-4032-99d0-6bd76891ae31','房公湖','文同','宋','宋诗','song-poetry','','[]','一頃清波四面平，宛然唐相舊經營。',64,'全唐诗/poet.song.25000.json','["一頃清波四面平，宛然唐相舊經營。", "高秋林木形容老，落日樓臺綵繪明。", "有景可尋蘭棹遠，無幽不入竹橋橫。", "二年所得官居樂，肯厭頻來緩带行。"]'),
('f44ca276-04e2-43ce-b103-23f747e717d4','錦鷄','文同','宋','宋诗','song-poetry','','[]','高原濯濯弄春暉，金碧冠纓綵繪衣。',64,'全唐诗/poet.song.25000.json','["高原濯濯弄春暉，金碧冠纓綵繪衣。", "石溜瀉烟晴自照，岩枝橫月夜相依。", "有時勃窣盤跚舞，忽地鈎輈格磔飛。", "寄語人間用矰繳，瑶臺鸞鳳好同歸。"]'),
('e6fdf03d-dc04-42f6-af7f-91212e2eeecb','竹棕','文同','宋','宋诗','song-poetry','','[]','秀榦扶疏綵檻新，琅玕一束凈無塵。',64,'全唐诗/poet.song.25000.json','["秀榦扶疏綵檻新，琅玕一束凈無塵。", "重苞吐實黄金穗，密葉圍條碧玉輪。", "凌犯雪霜持勁節，遮藏烟雨長輕筠。", "此名未入華林記，誰念西南寂寞春。"]'),
('2b4892fb-fd4e-46ca-9196-9a44546fcd7e','無爲山寺','文同','宋','宋诗','song-poetry','','[]','一絙危磴繞崢嶸，上徹幽深入化城。',64,'全唐诗/poet.song.25000.json','["一絙危磴繞崢嶸，上徹幽深入化城。", "烟外川原誰繡畫，雲中樓閣自陰晴。", "老僧高論都無著，古佛真身宛若生。", "聞道軍持新呪水，願傾涓滴灑塵纓。"]'),
('3e8630f0-3ce7-42f4-b4c3-70d528c38dc6','劍州東園','文同','宋','宋诗','song-poetry','','[]','群峰高擁碧嶙峋，亭宇清華氣象新。',64,'全唐诗/poet.song.25000.json','["群峰高擁碧嶙峋，亭宇清華氣象新。", "兩岸烟雲先向日，一林花木暗藏春。", "溪明夜閣軒窗月，風斷晴橋井邑塵。", "好酒滿樽詩滿軸，主人曾不倦行人。"]'),
('d3dab3ec-74a6-461a-a503-9a45b94a0db3','運判南園瞻民閣','文同','宋','宋诗','song-poetry','','[]','青都高與紫霄通，獨此危欄望不窮。',64,'全唐诗/poet.song.25000.json','["青都高與紫霄通，獨此危欄望不窮。", "萬嶺過雲秋色裏，一峰擎雪夕陽中。", "檐楹曉落天倉月，窗戶晴吹石闕風。", "民吏安閑財賦足，管弦時復在層空。"]'),
('6efb7019-f667-42b6-b1b5-9c5cdd0f61c6','讀淵明集','文同','宋','宋诗','song-poetry','','[]','吏人已散門闌靜，公事才休耳目清。',64,'全唐诗/poet.song.25000.json','["吏人已散門闌靜，公事才休耳目清。", "窗下好風無俗客，案頭遺集有先生。", "文章簡要惟華衮，滋味醇醲是太羹。", "也待將身學歸去，聖時爭奈正升平。"]'),
('c6d183c8-00e3-4430-b073-0ef08af362b7','張次公太博歸閬中','文同','宋','宋诗','song-poetry','','[]','制詔頻來試玉京，清途猶自滯豪英。',64,'全唐诗/poet.song.25000.json','["制詔頻來試玉京，清途猶自滯豪英。", "策高三道竟何用，恩拜二親方爾榮。", "嵇阮襟懷終曠達，儀秦才術本縱橫。", "閬中勝事知無限，且向城南爛漫行。"]'),
('d30057ef-9f66-4939-a5f3-ba5298d8e697','寄成都監庫石屯田遠叔','文同','宋','宋诗','song-poetry','','[]','一年同住夾城中，小圃高齋幸見容。',64,'全唐诗/poet.song.25000.json','["一年同住夾城中，小圃高齋幸見容。", "吟盡物題春唱和，講窮人事夜過從。", "尋芳待去門前約，訪古邀回道上逢。", "別後西樓不堪倚，滿川林木暮雲重。"]'),
('17622bd1-f884-4298-b50b-de9d1071ecc8','宿隆平精舍','文同','宋','宋诗','song-poetry','','[]','萬木羅青蓋，雙峰敞翠屏。',48,'全唐诗/poet.song.25000.json','["萬木羅青蓋，雙峰敞翠屏。", "風埃愁客路，鐘鼓喜禪扃。", "下馬穿蒙密，隨僧入杳冥。", "俗襟如見濯，試爲瀉銅瓶。"]'),
('f2532e82-b2e6-4ace-b0f3-a16f703e6614','弭蓋亭','文同','宋','宋诗','song-poetry','','[]','弭蓋長亭下，軒窗慰客心。',48,'全唐诗/poet.song.25000.json','["弭蓋長亭下，軒窗慰客心。", "田塍交遠日，水堋瀉清襟。", "北道雲千里，西山雪萬尋。", "塵衣無奈拂，去騎復駸駸。"]'),
('9a5fc048-c208-4887-87d7-74e444edb6a5','什邡道中','文同','宋','宋诗','song-poetry','','[]','驅馬下遥川，殘陽促晚鞭。',48,'全唐诗/poet.song.25000.json','["驅馬下遥川，殘陽促晚鞭。", "高林夾廣道，亂水入平田。", "村落晴如畫，桑林晝起烟。", "飛鴻正南下，歸意滿雲邊。"]'),
('a45cf82a-6df0-491e-8554-9fba2ab9fe7a','夜思寄蘇子平秘丞','文同','宋','宋诗','song-poetry','','[]','亂竹敲風遠，高松過雨凉。',48,'全唐诗/poet.song.25000.json','["亂竹敲風遠，高松過雨凉。", "檢書防落燼，下幕恐遺香。", "好月娟娟上，輕雲苒苒長。", "端令阻佳客，不得共清觴。"]'),
('c5487fd0-7761-4cb6-a6e2-ff0fb6c88fa6','西湖','文同','宋','宋诗','song-poetry','','["\u897f\u6e56"]','丞相淹回地，光容滿落暉。',48,'全唐诗/poet.song.25000.json','["丞相淹回地，光容滿落暉。", "池塘存舊夢，城郭嘆前非。", "烟靄陰晴出，鳬鷗遠近歸。", "松風殊有意，猶欲下金徽。"]'),
('d6b2e83f-5f92-4ffe-a109-19302a75c8e2','猿','文同','宋','宋诗','song-poetry','','[]','岷嶺高無敵，來從第幾層。',48,'全唐诗/poet.song.25000.json','["岷嶺高無敵，來從第幾層。", "攀緣殊不倦，趫捷爾誠能。", "晚嘯思危石，晴懸憶古藤。", "王孫非汝類，只可以文憎。"]'),
('536ed5b9-bb28-4556-8142-14a9b571ae5a','幽沼','文同','宋','宋诗','song-poetry','','[]','促促開幽沼，涓涓引細渠。',48,'全唐诗/poet.song.25000.json','["促促開幽沼，涓涓引細渠。", "無由安島嶼，才可活龜魚。", "秀荇新宜食，圓荷凈好書。", "時來坐高柳，濯足蔭扶疏。"]'),
('2d963c73-160a-43fc-9d95-7e2eda373909','步月','文同','宋','宋诗','song-poetry','','[]','掩卷下中庭，月色浩如水。',48,'全唐诗/poet.song.25000.json','["掩卷下中庭，月色浩如水。", "秋氣凉滿襟，松陰密鋪地。", "百蟲催夜去，一雁領寒起。", "靜念忘世紛，誰同此佳味。"]'),
('3e7472a4-2ca6-4a22-a503-4f8bb0cd1378','中秋對月懷寄鳳凰山鄧道人','文同','宋','宋诗','song-poetry','','[]','有客千岩萬壑中，綠毛丹臉紫方瞳。',32,'全唐诗/poet.song.25000.json','["有客千岩萬壑中，綠毛丹臉紫方瞳。", "不知今夜西樓月，幾處飛仙下碧空。"]'),
('bbef8284-193f-44e0-9215-9ab6ef7bb6a8','秋日晚晴呈同院','文同','宋','宋诗','song-poetry','','[]','秋風淅淅吹碧虛，白雲鱗鱗如卧魚。',32,'全唐诗/poet.song.25000.json','["秋風淅淅吹碧虛，白雲鱗鱗如卧魚。", "共君今夜賞明月，興來誰欲騎蟾蜍。"]'),
('54c0b57d-1f4a-49ed-bd18-31a77b12200d','戲呈鳳凰長老用師','文同','宋','宋诗','song-poetry','','[]','七十頭陀會語言，舌根流利口闌珊。',32,'全唐诗/poet.song.25000.json','["七十頭陀會語言，舌根流利口闌珊。", "羅浮居士最難奈，穩把無弦琴與彈。"]'),
('e3fb90e8-2fa1-4db8-bda7-6be2b260af2c','郡學鎖宿','文同','宋','宋诗','song-poetry','','[]','長柏高柟蔭廣庭，夜凉人靜夢魂清。',32,'全唐诗/poet.song.25000.json','["長柏高柟蔭廣庭，夜凉人靜夢魂清。", "不知山月幾時落，每到曉鐘聞雨聲。"]'),
('aee305f2-23d9-43b7-9abe-1315bf032ffc','子平棋負茶墨小章督之','文同','宋','宋诗','song-poetry','','[]','睡憶建茶斟瀲灧，畫思兖墨潑淋漓。',32,'全唐诗/poet.song.25000.json','["睡憶建茶斟瀲灧，畫思兖墨潑淋漓。", "可憐二物俱無有，記得南堂棋勝時。"]'),
('9165781d-6add-4c61-bab1-f0bcc394eb05','長安李晦叔醉老庵','文同','宋','宋诗','song-poetry','','[]','醉老名庵晦叔爲，庵中長是醉淋漓。',32,'全唐诗/poet.song.25000.json','["醉老名庵晦叔爲，庵中長是醉淋漓。", "扶頭未得日過午，門外萬端俱不知。"]'),
('4e324158-30e9-47e6-8db8-d387e7ad81cf','和邵興宗棋聲','文同','宋','宋诗','song-poetry','','[]','二客與棋酬，寒聲滿側楸。',48,'全唐诗/poet.song.25000.json','["二客與棋酬，寒聲滿側楸。", "急因隨行發，斷爲見遲休。", "花下鶑翻翼，林間鶴轉頭。", "丁丁竹樓下，不獨在黄州。"]'),
('f47ec55a-575a-48ad-ab40-ad84f8b45311','續青城山四詠 昭慶觀','文同','宋','宋诗','song-poetry','','[]','琳崖盤玉霄，彩翠接步武。',48,'全唐诗/poet.song.25000.json','["琳崖盤玉霄，彩翠接步武。", "雲霞不可畫，泉石固難譜。", "神幢逾百尋，帝轍歷萬古。", "靈瀑誰與窮，長飛六時雨。"]'),
('9cdd4213-d169-4263-9cdf-203580260345','續青城山四詠 天倉山威儀觀','文同','宋','宋诗','song-poetry','','[]','群峰削瓊瑶，老蘚抹古綠。',48,'全唐诗/poet.song.25000.json','["群峰削瓊瑶，老蘚抹古綠。", "應朝大岷去，簪笏儼相逐。", "珠宮秘仙仗，錦笈藏寶籙。", "上帝此爲倉，其田堪種玉。"]'),
('207eb658-9d13-4c36-9319-da1d454f26f8','續青城山四詠 飛赴寺','文同','宋','宋诗','song-poetry','','[]','平林露層巘，上獨置孤寺。',48,'全唐诗/poet.song.25000.json','["平林露層巘，上獨置孤寺。", "群仙馭飛駕，往往赴於此。", "風高幡影亂，日落鐘聲起。", "誰可謂詩豪，興來吟萬紙。"]'),
('149dc665-faf0-401f-ad0f-f046f601be17','續青城山四詠 香積寺','文同','宋','宋诗','song-poetry','','[]','道險轉詰曲，山深愈巑岏。',48,'全唐诗/poet.song.25000.json','["道險轉詰曲，山深愈巑岏。", "行松耳目清，入竹襟袖寒。", "殿閣紅芙蕖，岩巒碧琅玕。", "高僧把金字，擁衲對雲看。"]'),
('d61a7cb4-df92-49de-b76b-ec33ba057ba1','夏秀才江居五題 枕流亭','文同','宋','宋诗','song-poetry','','[]','愛此烟景佳，開軒故臨水。',48,'全唐诗/poet.song.25000.json','["愛此烟景佳，開軒故臨水。", "晴暉照寒浪，飛影動窗紙。", "倚檻見魚游，卷簾知雁起。", "憔悴笑湘纍，區區詠蘭芷。"]'),
('637533d3-242c-44ba-94a9-aa00a2a01a0d','夏秀才江居五題 鬥碧亭','文同','宋','宋诗','song-poetry','','[]','雨餘山景鮮，風定水光好。',48,'全唐诗/poet.song.25000.json','["雨餘山景鮮，風定水光好。", "晴陽破宿霧，秀色濃可掃。", "平時一樽酒，野客共傾倒。", "朝暮山水間，年華不知老。"]'),
('031506d9-b5ec-42a3-a528-1c68df754caa','夏秀才江居五題 天隠洞','文同','宋','宋诗','song-poetry','','[]','層崖削青瑶，誰昔此鎸鏤。',48,'全唐诗/poet.song.25000.json','["層崖削青瑶，誰昔此鎸鏤。", "潭潭鬥孤洞，中可百人受。", "巑岏列岫繞，洶涌大江漱。", "虞卿方著書，入此幾年就。"]'),
('a63626cb-76ab-4f84-9539-6d6614f1220a','夏秀才江居五題 直鈎磯','文同','宋','宋诗','song-poetry','','[]','盡知人鈎曲，獨見君鈎直。',48,'全唐诗/poet.song.25000.json','["盡知人鈎曲，獨見君鈎直。", "年年此磯上，萬掣無一得。", "持竿只自苦，吞餌何嘗識。", "試效人所爲，君魚不勝食。"]'),
('26ac66f0-ef46-4c45-8806-8229e1bd2eee','夏秀才江居五題 醉經庵','文同','宋','宋诗','song-poetry','','[]','垂茅緝爲庵，有類穹廬形。',48,'全唐诗/poet.song.25000.json','["垂茅緝爲庵，有類穹廬形。", "之人伏其中，日醉乎群經。", "世俗安爾知，但謂長不醒。", "寄此語二豪，渠非彼劉伶。"]'),
('0ad83f7d-caa4-452f-a53f-ca7baa41e7cc','寄題杭州通判胡學士官居詩四首 鳳咮堂','文同','宋','宋诗','song-poetry','','[]','胡侯外補來錢塘，所居之山名鳳凰。',128,'全唐诗/poet.song.25000.json','["胡侯外補來錢塘，所居之山名鳳凰。", "不知元本發何處，蛇頸魚尾盤高岡。", "婆娑欲下大江飲，萬里一息頭低昂。", "誰將浮圖壓兩翅，直使帖地不得翔。", "前人眼俗不知顧，會有賢者來形相。", "憐汝困欲共汝語，故近汝咮營斯堂。", "起居飲食不離上，外孰有耳聽琅琅。", "應云汝德未衰在，旦暮可起鳴朝陽。"]'),
('6c2f06ba-30c7-4d66-b291-f3e4c84ad58d','寄題杭州通判胡學士官居詩四首 濺玉齋','文同','宋','宋诗','song-poetry','','[]','石林犖犖森座隅，激水注射成飛渠。',64,'全唐诗/poet.song.25000.json','["石林犖犖森座隅，激水注射成飛渠。", "寒音琤然落環珮，爽氣颯爾生庭除。", "主人清標自可敵，底處勝概爲能如。", "想君不欲時暫去，其餘滿案堆文書。"]'),
('79ac91ea-9fb3-4e26-bf3a-ad3888f65943','寄題杭州通判胡學士官居詩四首 方庵','文同','宋','宋诗','song-poetry','','[]','衆人庵盡圓，君庵獨云方。',80,'全唐诗/poet.song.25000.json','["衆人庵盡圓，君庵獨云方。", "君雖樂其中，無乃太異常。", "勸君刓其角，使稱著月床。", "自然制度穩，名號亦可詳。", "東西南北不足辨，左右前後誰能防。", "願君見聽便如此，鼠蝎四面人恐傷。"]'),
('84af51d7-0eae-4ffd-bf41-d02970a4add8','寄題杭州通判胡學士官居詩四首 月岩齋','文同','宋','宋诗','song-poetry','','["\u897f\u6e56"]','月爲太陰精，石亦月之類。',401,'全唐诗/poet.song.25000.json','["月爲太陰精，石亦月之類。", "月常寄孕於石中，事理如此何足異。", "天地始分判，日月各一物。", "既名物乃入形器，安有形器不消沒。", "况此日與月，曉夜東西走。", "珠流璧轉無暫停，豈與天地同長久。", "其爲勞苦世共知，惟是月有生死時。", "既然須常換新者，人但不見神所爲。", "日須天上生，月必地中産。", "君不見虢州朱陽縣之山谷間，纔成未就知何限。", "石有不才者，往往其卵毈。", "靈媼棄置不復惜，任人取去爲珍玩。", "佳者留之待天取，藏滿庫樓千萬許。", "彥瞻博物天下稱更無，定不以予之說爲寱語。", "予恐世人不知嵩丘岩洞中，中有八萬二千修月戶。", "其人所食盡玉屑，昔有王生見之滿襆提斤斧。", "應是當年靈鷲山，直自天竺飛落西湖前。", "其上有石妊月月已滿，此人朅來就彼剜剔歸上天。", "所以此石拆𠠦不復合，至今神胞所附之處其痕圓。", "拋擲道傍凡幾歲，風刷雨淋塵土穢。", "子平一見初動心，輦致東齋自摩洗。", "更選他山相擁列，就中獨爾一峰最奇絕。", "每至瑶魄流光下照時，玉柱橫欹無少缺。", "子平謂我同所嗜，萬里書之特相寄。"]'),
('f4a5c1e6-de0b-4646-97fc-0b7f7e2adc15','寄員文饒屯田','文同','宋','宋诗','song-poetry','','[]','英英文饒江漢士，何者天教喪眸子。',160,'全唐诗/poet.song.25000.json','["英英文饒江漢士，何者天教喪眸子。", "用心專一性轉明，無所不知餘兩耳。", "能爲樂府勝張籍，暗誦史書過杜顗。", "棄官新自荆渚歸，萬里逆風衝峽水。", "峨峨全家載巨艑，坐卧吟詩滿千紙。", "自言從此生事足，可了芋栗及麻枲。", "數椽舊屋蔽風雨，一榻蕭然容隠几。", "丘明國語浩如雲，子夏門人紛若蟻。", "向人問口誇舌在，道義文章吾豈已。", "自知俗事無所觀，便落雙睛君亦喜。"]'),
('366e3721-17f2-42fd-9832-d7d206b1e404','奉送少訥還青神','文同','宋','宋诗','song-poetry','','[]','濕雲堆空洩淫雨，日與三嵎氣相軋。',224,'全唐诗/poet.song.25000.json','["濕雲堆空洩淫雨，日與三嵎氣相軋。", "春陽沈伏不得動，萬木屈蘗草藏茁。", "叢岡複嶺誰敢度，旦暮寒鷄叫泥滑。", "少訥胡爲犯此苦，特念我困來省察。", "延之累日對佳話，如侍大饗聽椌楬。", "彥瞻弟兄別已久，使我心胸昏莫刮。", "天將少訥愈我病，次第爲取蹊茅拔。", "長編巨軸寫治亂，筆墨揮灑何橫猾。", "詞章直如子長健，辯論不比仲連黠。", "我慚無琴類師曠，鶴誤銜珠投二八。", "酌泉煮蔬共家饌，敢用俗禮費烹殺。", "少訥忽爾道其去，歸轅在途不可揠。", "此懷作惡定數日，憒憒已覺漸磨戛。", "欲留少訥意無盡，更爲逡巡柅西轄。"]'),
('7e26924b-5299-4855-810b-f5315b4a068f','送無演歸成都','文同','宋','宋诗','song-poetry','','[]','曾讀契嵩輔教編，浮屠氏有不可忽。',384,'全唐诗/poet.song.25000.json','["曾讀契嵩輔教編，浮屠氏有不可忽。", "後於京師識懷璉，彼上人者尤奇倔。", "余嘗從容問其友，璉復爲余道居訥。", "是三大士才過人，所畜豈肯吾儒屈。", "文章汪洋道義富，不止區區事其佛。", "余思此等更誰似，蜀有人焉頗超越。", "成都敏行字無演，所謂萬星中一月。", "想嵩璉訥見須避，不爾往往被呵咄。", "通禪曉律兩無礙，前會定預耆闍崛。", "群經列史固汗漫，獨泛其深仍出沒。", "外之所精者書畫，不問不語常若吃。", "計其夏臘殊未幾，在大衆中誠突兀。", "余守陵陽至窮陋，雨浸一春泥汩汩。", "英磎磽磝磴道嶮，行客欷歔上崷崒。", "無演衝冒獨不顧，來款余門手持謁。", "呼之使前見已喜，相貌圓滿藏神骨。", "清譚坐久愈飄灑，頓遣塵襟落如拂。", "新詩古文覽嘉貺，氣格俊健凌霜鶻。", "觀其衮衮出論議，收斂便可與簪笏。", "試將邀之使從仕，笑指此頂安更髪。", "日招與語自無厭，何乃告去苦倉卒。", "西城曉日照高嶺，倒搭乾陀入深樾。", "師歸常宜見嘉祐，此老心中已無物。", "好音相與頻寄惠，余在空山正伊鬰。"]'),
('e778d24c-a2a4-4560-a8f2-5c68370d97f1','閻君見示岷山賦因爲小詩謝之','文同','宋','宋诗','song-poetry','','[]','大岷西南鎮，岩壑天下秀。',120,'全唐诗/poet.song.25000.json','["大岷西南鎮，岩壑天下秀。", "厥初造此者，以作神仙囿。", "相如子雲沒，李杜繼其後。", "欲賦俱未敢，於詞怯輕構。", "閻君通方士，才力誰可鬥。", "驅聯入健筆，萬狀無一漏。", "駸駸語趫勁，駿馬雜馳驟。", "太華楊已拙，天台孫亦謬。", "示余讀數過，驚聳肩縮脰。", "勉爲成短章，聊酬君意厚。"]'),
('1512d2d5-3ecd-451f-9311-ef24731fd5c7','閻生談黄庭','文同','宋','宋诗','song-poetry','','[]','茫茫誦靈文，誰爲抉久瞽。',48,'全唐诗/poet.song.25000.json','["茫茫誦靈文，誰爲抉久瞽。", "不能辨三一，豈復更知五。", "方迷得真指，忽悟有奇睹。", "自此日相親，赤龍交黑虎。"]'),
('d6f2d516-f11a-48e1-8880-f312a7400c8f','送范堯夫','文同','宋','宋诗','song-poetry','','[]','遝遝走閭巷，都人起中宵。',288,'全唐诗/poet.song.25000.json','["遝遝走閭巷，都人起中宵。", "相擁候府門，惟恐失此朝。", "盡言來送公，車馬城北橋。", "橋邊脂轄亭，大尹此相邀。", "歌管盛宴集，簪裾合群僚。", "四座酒既行，相顧魂已銷。", "亭前有楊柳，秋風減長條。", "折以持贈公，莫厭霜葉凋。", "節物雖謂晚，比春情更饒。", "遞起勸公飲，雙呼金翠翹。", "豈徒要公醉，恐公遽乘軺。", "借問何爾爲，重公若瓊瑶。", "美質未省變，與人存久要。", "既莫不可留，征衫遂飄飄。", "鳴騶過昇遷，群甿鬧如蜩。", "感公來二年，免我於無聊。", "今公舍我去，何由借諸朝。", "願君富且貴，壽命等松喬。", "直似先令公，巍巍佐唐堯。", "涕淚逐公行，不憚公更遥。", "公誠上下通，和如奏笙簫。", "所以得如此，人情不相遼。", "嗟同繆與公，一時赴弓招。", "于今二十年，不見有所超。"]'),
('ac03b406-f590-4582-983e-8c2a4ddaffe5','推官惠李庶子鄂州篆字','文同','宋','宋诗','song-poetry','','[]','天下有奇篆，陽冰書鄂州。',48,'全唐诗/poet.song.25000.json','["天下有奇篆，陽冰書鄂州。", "異獸呀五口，狂咬掉三頭。", "磥砢玻璃碗，詰屈珊瑚鈎。", "愧無希世寶，何以爲子酬。"]'),
('e2dac554-ee32-44a1-b054-964af4342f56','和提刑度支王店鷄詩','文同','宋','宋诗','song-poetry','','[]','王店有郵吏，養鷄殊可笑。',216,'全唐诗/poet.song.25000.json','["王店有郵吏，養鷄殊可笑。", "昂然處高襟，不肯以時嘂。", "官有宿此者，西征待初曉。", "鷄竟不一鳴，問吏吏已告。", "云此最荒絕，左右悉蓬蓼。", "狐狸占爲宅，恣橫不可道。", "前此三四鷄，一一遭其暴。", "尋聲即知處，盡獲爪牙弔。", "自後始得此，其若有人教。", "東方或未明，群醜尚騰趠。", "此鷄但鉗結，直伺太陽耀。", "雖然謂失旦，似得保身要。", "官曰此何用，不然則宜糶。", "不見不鳴雁，先死蓋自召。", "天下已明白，豈假更喧鬧。", "徒爾費稻粱，曾莫知所報。", "吏云官言是，且願勿嘲誚。", "知是本在人，此物何足校。"]'),
('ff5eb1c0-a868-4cf3-8a9c-f88160b9e21a','送李道士','文同','宋','宋诗','song-poetry','','[]','先生若孤雲，兩在隆山見。',48,'全唐诗/poet.song.25000.json','["先生若孤雲，兩在隆山見。", "清標瘦彌聳，秀骨老愈健。", "高談吐深詣，大句寫精鍊。", "忽起憶鵝池，肏飛石泉濺。"]'),
('7ef34991-0f6a-479c-b2af-85f4c3b42d97','送韓山人','文同','宋','宋诗','song-poetry','','[]','昌黎山人抱藜杖，三度訪我於三隅。',64,'全唐诗/poet.song.25000.json','["昌黎山人抱藜杖，三度訪我於三隅。", "端然入座更誰顧，談辯衮衮如流珠。", "靈丹嘗凝日月鼎，至寶自産乾坤爐。", "要行撇起不可逐，安得雙舄爲飛鳬。"]'),
('4b48da0c-88f5-47da-bfa6-9943e8726bab','二年陵陽不見中秋月','文同','宋','宋诗','song-poetry','','[]','陵陽亂山中，陰雺日夕發。',96,'全唐诗/poet.song.25000.json','["陵陽亂山中，陰雺日夕發。", "晴光尚希見，况復求夜月。", "二年逢中秋，曾不識皎潔。", "烟雲爾何事，常此作蓬勃。", "纔令薄中明，已遣濃處沒。", "群邪利幽暗，左右覺窸窣。", "清光若蒙蔽，誰爲我磨拂。", "庭下倚高株，露華霑鬢髪。"]'),
('9c3f13db-be05-496c-b745-16479cb96384','夜聲','文同','宋','宋诗','song-poetry','','[]','秋風動衰草，摵摵響夜月。',48,'全唐诗/poet.song.25000.json','["秋風動衰草，摵摵響夜月。", "其下有鳴蛩，到曉啼不歇。", "乃知摇落時，衆籟自感發。", "安得苦吟人，不能爲一吷。"]'),
('1c7c77d6-49d2-4027-8566-9019101fbdb9','送棋僧惟照','文同','宋','宋诗','song-poetry','','[]','學成九章開方訣，誦得一行乘除詩。',64,'全唐诗/poet.song.25000.json','["學成九章開方訣，誦得一行乘除詩。", "自然天性曉絕藝，可敵國手應吾師。", "窗前橫榻擁爐處，門外大雪壓屋時。", "獨翻舊局辨錯著，冷笑古人心許誰。"]'),
('25bbb5ab-106a-4de3-81e6-ee8e3b79b48e','送喻介夫','文同','宋','宋诗','song-poetry','','[]','介夫陵陽奇男子，節義素爲人所談。',64,'全唐诗/poet.song.25000.json','["介夫陵陽奇男子，節義素爲人所談。", "身長七尺氣萬丈，自謂流落誰能甘。", "去將舊學中新格，坐取高第如手探。", "明年西歸有光耀，且請爲我來山南。"]'),
('965c15f7-617d-4e93-baf4-be39684b2ed3','飛泉山寺','文同','宋','宋诗','song-poetry','','[]','東城兀高峰，爽氣浮翠微。',96,'全唐诗/poet.song.25000.json','["東城兀高峰，爽氣浮翠微。", "霞光射巖壁，中有寒泉飛。", "上方金仙家，煌煌啟雙扉。", "欄干出雲表，目可了四圍。", "我來久不下，幡影移斜暉。", "風吹月中桂，天香滿人衣。", "遠渚鳬雁落，前嶺牛羊歸。", "尚此戀幽勝，不能手聊揮。"]'),
('6733ca86-dec7-44fb-8379-870d5eec8f28','山雨','文同','宋','宋诗','song-poetry','','[]','山雨灑春城，潗潗聲頗急。',48,'全唐诗/poet.song.25000.json','["山雨灑春城，潗潗聲頗急。", "窗下讀書人，橫編揭陰濕。", "高鳶餓獨叫，遠燕寒雙入。", "南園有桃杏，盡抱群梢泣。"]'),
('e1750835-b8d6-46e5-9c36-edb9f9e545a8','送牟太素山人','文同','宋','宋诗','song-poetry','','[]','山人高迹若孤雲，聊問太虛求所止。',64,'全唐诗/poet.song.25000.json','["山人高迹若孤雲，聊問太虛求所止。", "昨因隨風起西北，翩然遠墮三隅裏。", "攬之不住瞥爾去，瞬息誰知幾千里。", "東遊必定遇鴻濛，請問無爲最深旨。"]'),
('fe8364c5-923c-4363-8b2a-2384843df140','送龐中秀才','文同','宋','宋诗','song-poetry','','[]','曼倩學精知蜥蜴，公明術妙識蜘蛛。',32,'全唐诗/poet.song.25000.json','["曼倩學精知蜥蜴，公明術妙識蜘蛛。", "臨邛復有龐成叔，萬事先將入卦圖。"]'),
('95d796a7-4ef5-4555-8b7e-94eb5cd3e700','遣興效樂天','文同','宋','宋诗','song-poetry','','[]','君莫學楊虞卿奉李宗閔，宗閔權勢豈能久。',179,'全唐诗/poet.song.25000.json','["君莫學楊虞卿奉李宗閔，宗閔權勢豈能久。", "君莫學劉栖楚附李逢吉，逢吉祿位寧長守。", "雖然一時身暫好，其奈千古名常醜。", "丈夫讀書要知道，所信不篤被其誘。", "大張富貴作羅網，愚者紛紛以身就。", "左纏右繞不可脫，誅竄還當逐其後。", "君不見虞卿須遇李固言，君不見栖楚終遭韋處厚。", "一朝摧折靈氣盡，龍如蛇兮虎如狗。", "勸君聖賢術內好潛心，勸君邪佞黨中休入手。", "豈不知潞州處士田佐時，喚與美官嫌不受。"]'),
('66044bed-3f5d-4299-94a4-79160ce8dd3b','遣興三首  其一','文同','宋','宋诗','song-poetry','','[]','惻惻抱伊鬰，試此登嶕嶢。',204,'全唐诗/poet.song.25000.json','["惻惻抱伊鬰，試此登嶕嶢。", "陰風吹繁雲，黯黯蒙泰霄。", "關河眇無際，節物何蕭蕭。", "過雁安所之，驚哀翻泬寥。", "幽懷漭如失，隨此群草凋。", "嗟予生胡爲，迹玷明盛朝。", "服職詎云補，赧然綴群寮。", "感此四序遷，一昏復一朝。", "寒霜入兩鬢，漸積不肯消。", "良辰乖所遇，慨嘆心魂飄。", "賤稟迂且介，於時信無庸。", "欲適閡所之，此道當何從。", "富貴諒非有，僻陋知可容。", "豈不愧上恩，耗此釜與鍾。", "昨歸得此州，滿眼皆亂峰。", "事物固瑣碎，敢茲任頑慵。", "報國祇自明，惟神諜其胸。"]'),
('08f35a21-4b68-4ad1-9483-7edf682f3716','遣興三首  其二','文同','宋','宋诗','song-poetry','','[]','少小事編簡，淵源極沿洄。',120,'全唐诗/poet.song.25000.json','["少小事編簡，淵源極沿洄。", "不自測其深，津涯信悠哉。", "既長務修省，日以德義培。", "一簣敢中畫，期之至崔嵬。", "振纓仕明庭，鴛鷺忝遊陪。", "蹇修無嗣者，誰可吾與媒。", "吐艷落晚春，蔫然抱枯荄。", "因人寔自耻，寂寞余敢哀。", "何當清泠泉，襟裾濯氛埃。", "故山有松菊，待賦歸去來。"]'),
('71871e75-9b2b-49b0-bb0b-0af7ae77f64f','遣興三首  其三','文同','宋','宋诗','song-poetry','','[]','連陰不肯解，山霧嘗霏霏。',48,'全唐诗/poet.song.25000.json','["連陰不肯解，山霧嘗霏霏。", "積潤日已滋，厭浥沾人衣。", "展轉厭早起，隔窗問晴暉。", "幸聞太陽出，身體輕欲飛。"]'),
('1178de1c-00af-4f5e-8fa8-ed76c516664c','中秋夜坐遣興','文同','宋','宋诗','song-poetry','','[]','素紈不摇風滿襟，露氣中夜寒相侵。',32,'全唐诗/poet.song.25000.json','["素紈不摇風滿襟，露氣中夜寒相侵。", "予懷浩然杳莫寄，伴月直到青天心。"]'),
('e35ba3ab-6cdb-480e-be65-7c55f21eb7d0','臨闤閣','文同','宋','宋诗','song-poetry','','[]','絕壑迎朱檻，高林拂畫楹。',48,'全唐诗/poet.song.25000.json','["絕壑迎朱檻，高林拂畫楹。", "卷簾千嶂遠，入座一川平。", "蜺綵緣雲斷，霞光射水明。", "不須誇曠望，爲語謝宣城。"]'),
('e74349a9-2e50-400e-896c-040e4b466418','野逕','文同','宋','宋诗','song-poetry','','[]','山圃饒秋色，林亭近晚晴。',48,'全唐诗/poet.song.25000.json','["山圃饒秋色，林亭近晚晴。", "禽蟲依月令，藥草带人名。", "排石鋪衣坐，看雲緩带行。", "官閑惟此樂，與世欲無營。"]'),
('451290e7-4b4a-4dbc-973d-277fd53ae01e','寒蜩','文同','宋','宋诗','song-poetry','','[]','山月滿地流金波，寒蜩向秋鳴更多。',32,'全唐诗/poet.song.25000.json','["山月滿地流金波，寒蜩向秋鳴更多。", "大都時節使如此，止爾不得將奈何。"]'),
('2c35215e-a222-4ad4-b513-7e37e0302778','辛亥孟秋戊子有虹下天繞飛泉山入東谷飲古井良久去作大雨咄之以詩','文同','宋','宋诗','song-poetry','','[]','長虹落天帔，萬丈截群嶺。',168,'全唐诗/poet.song.25000.json','["長虹落天帔，萬丈截群嶺。", "蟠身下深谷，俯首飲古井。", "居人莫之指，况復敢引領。", "幡然繞空去，雲霧變俄頃。", "乾坤爲之黑，噴雨極暴猛。", "崩流匯溝瀾，巨漲沒四境。", "民田一漂蕩，多稼不可省。", "此物蓋蟲類，聞亦具頭頸。", "淫沴之所生，詩傳載爲眚。", "朝西暮東出，輒與日對影。", "夫何此凶孽，得使乘時逞。", "高風掃寥廓，一帚昏穢凈。", "煌煌太陽起，隙穴被光景。", "群陰逐海內，此物應遠屏。"]'),
('de57c672-edd9-431c-984d-309f7ac24b36','寄何首烏丸與友人','文同','宋','宋诗','song-poetry','','[]','此草有奇效，嘗聞於習之。',216,'全唐诗/poet.song.25000.json','["此草有奇效，嘗聞於習之。", "陵陽亦舊産，其地尤所宜。", "翠蔓走岩壁，芳叢蔚參差。", "下有根如拳，赤白相雄雌。", "斸之高秋後，氣味乃不虧。", "斷以苦竹刀，蒸曝凡九爲。", "夾羅下香屑，石密相和治。", "入臼杵萬過，盈盤走纍纍。", "日進豈厭屢，初若無所滋。", "漸久覺膚革，鮮潤如凝脂。", "既已鬚髪換，白者無一絲。", "耳目固聰明，步履欲走馳。", "十年親友別，忽見皆生疑。", "問胡得爾術，容貌曾莫衰。", "爲之講靈苗，不爲世俗知。", "蓋以多見賤，蓬藋同一虧。", "君如聽予服，此語不敢欺。", "勿信柳子厚，但誇仙靈脾。"]'),
('89d8182e-d90c-4eba-b476-f2c13d103fda','霜柏亭試墨','文同','宋','宋诗','song-poetry','','[]','山風吹早晴，裌服覺微凜。',48,'全唐诗/poet.song.25000.json','["山風吹早晴，裌服覺微凜。", "烟雲有佳尚，竹石得幽稟。", "閑窗覆舊局，晚閣試新品。", "幾欲賦郊居，奇詞未如沈。"]'),
('7cbf5f5d-5369-418a-8756-34f84c35ca0c','閱史感事','文同','宋','宋诗','song-poetry','','[]','世間諸味已全疏，惟愛縑緗似蠹魚。',64,'全唐诗/poet.song.25000.json','["世間諸味已全疏，惟愛縑緗似蠹魚。", "名霸者來爲御史，姓關人去作尚書。", "晉師嘿嘿曾何害，楚客昂昂只自如。", "安得漢陰歸抱甕，滿園青甲灌新蔬。"]'),
('5f042dea-278a-4aff-8b53-9c1183d89ec8','富春山人爲予道其所獲石於江中者狀甚怪偉欲予作詩言若可得持歸刻其上當相與傳無窮余夜坐平雲閣是時山月清凜啼蟲正苦余因此景物索筆硯爲山人賦之','文同','宋','宋诗','song-poetry','','[]','奇礓巑岏倚秋江，俗眼過幾多所忽。',128,'全唐诗/poet.song.25000.json','["奇礓巑岏倚秋江，俗眼過幾多所忽。", "風霜鍛鍊愈堅重，怒浪噴激不可沒。", "富春山人好尚古，見此便以作吾物。", "鎸鑱牽挽置庭下，犀角鯨牙蛟蜃骨。", "精金凝滑露筋膂，老玉磥砢開竅窟。", "狂螭奔拏勢夭矯，猛兕摶生氣蓬勃。", "山人誇我謂如此，欲我詩之慚拙訥。", "何當走到山人家，撫月摩烟觀突兀。"]'),
('96311d8c-b2d6-45c3-ac56-b551152c68d1','平雲閣偶作','文同','宋','宋诗','song-poetry','','[]','陵陽郡事全稀少，懶守長贏半日閑。',32,'全唐诗/poet.song.25000.json','["陵陽郡事全稀少，懶守長贏半日閑。", "晚後須來上高閣，就中無厭是雲山。"]'),
('2c69f48e-0ccf-4f19-81d8-ca3e720be1aa','聞陳山人定命丹成試以詩乞','文同','宋','宋诗','song-poetry','','[]','水火相交養大還，已聞神汞滿爐乾。',32,'全唐诗/poet.song.25000.json','["水火相交養大還，已聞神汞滿爐乾。", "彘肪穀漆尋常得，敢服靈丹二萬丸。"]'),
('efe848bf-6e87-4f2c-be55-ce5be8dda26e','厭蟲','文同','宋','宋诗','song-poetry','','[]','月出松塢明，露下蓮塘清。',48,'全唐诗/poet.song.25000.json','["月出松塢明，露下蓮塘清。", "今宵好風色，獨繞林下行。", "百蟲爾胡爲，嘖嘖饒秋聲。", "求靜不能得，我詩何由成。"]'),
('9d70661c-1ca5-4333-9457-55d8322abcf4','新晴山月','文同','宋','宋诗','song-poetry','','[]','高松漏疏月，落影如畫地。',48,'全唐诗/poet.song.25000.json','["高松漏疏月，落影如畫地。", "徘徊愛其下，及久不能寐。", "怯風池荷卷，病雨山果墜。", "誰伴予苦吟，滿林啼絡緯。"]'),
('38be4dd5-2d26-4c58-8c5e-2306ed19ec77','送堯夫二章  其一','文同','宋','宋诗','song-poetry','','[]','有志深沉定，無心出處同。',48,'全唐诗/poet.song.25000.json','["有志深沉定，無心出處同。", "廟堂應爲國，臺省復還公。", "肖似家聲重，端方士論雄。", "上如留左右，風采壯朝中。"]'),
('db24d836-5d50-4014-8578-ccdb2145bfcf','送堯夫二章  其二','文同','宋','宋诗','song-poetry','','[]','欲與民爲利，先求正所妨。',48,'全唐诗/poet.song.25000.json','["欲與民爲利，先求正所妨。", "紛更初下議，旁午遂交章。", "不爾毛安傅，其如體自傷。", "西南餘弊在，歸爲對明光。"]'),
('3f3c9ab3-78be-4d34-bad8-621971a53efa','秋日田家','文同','宋','宋诗','song-poetry','','[]','淘漉溝源築野塘，滿坡烟草卧牛羊。',32,'全唐诗/poet.song.25000.json','["淘漉溝源築野塘，滿坡烟草卧牛羊。", "今年且喜輸官辦，豆莢繁多粟穗長。"]'),
('2bc72343-d7c7-4934-8741-67333f87c0ae','和吳龍圖韵五首 二色芙蓉','文同','宋','宋诗','song-poetry','','[]','蜀國芙蓉名二色，重陽前後始盈枝。',64,'全唐诗/poet.song.25000.json','["蜀國芙蓉名二色，重陽前後始盈枝。", "畫調粉筆分妝處，繡引紅針間刺時。", "落晚自憐窺露沼，忍寒誰念倚霜籬。", "主人日有西園客，得爾方於勸酒宜。"]'),
('967c6574-58bc-4ad9-a3f9-88e494a1518b','和吳龍圖韵五首 洗竹','文同','宋','宋诗','song-poetry','','[]','斤斧從來到此稀，爲撩疏密繞藩籬。',64,'全唐诗/poet.song.25000.json','["斤斧從來到此稀，爲撩疏密繞藩籬。", "已繁不用饒新笋，縱礙何妨惜舊枝。", "風外清音聞曲閣，月中寒影下方池。", "想公日在琅玕徑，正是棠陰訟少時。"]'),
('437fbaed-908a-47ab-8f3e-b0352988e527','和吳龍圖韵五首 明堂肆赦不得預觀感而成詩','文同','宋','宋诗','song-poetry','','[]','季秋陽館事嚴禋，能饗洪惟上至仁。',64,'全唐诗/poet.song.25000.json','["季秋陽館事嚴禋，能饗洪惟上至仁。", "游廟衣冠參帝坐，侍祠簪佩儼星辰。", "歡聲被宇和於律，協氣流天藹若春。", "即見陪鑾千萬祀，豈長如此在遐垠。"]'),
('7df282a4-5f40-4318-b256-f7d73fa2190d','和吳龍圖韵五首 經史閣','文同','宋','宋诗','song-poetry','','[]','自持金節此爲州，小善何嘗不見收。',64,'全唐诗/poet.song.25000.json','["自持金節此爲州，小善何嘗不見收。", "更起麗譙連石室，盛藏縑帙擬蓬丘。", "師延舊德皆高誼，士集他邦盡久留。", "當念河南嚮儒意，莫教弦誦少時休。"]'),
('b7f70ddb-cf0a-42a8-a146-7c5db59c4db2','和吳龍圖韵五首 有懷致政景仁侍郎','文同','宋','宋诗','song-poetry','','[]','一生名籍占風流，爲識莊環可自由。',64,'全唐诗/poet.song.25000.json','["一生名籍占風流，爲識莊環可自由。", "几杖未銷容早退，廟堂將近肯中休。", "有人把酒思高節，何處揮毫詠素秋。", "故國岷峨最佳絕，幾時歸伴赤松游。"]'),
('fd0070cd-730a-4c7d-aec2-92fb1744e856','吳公惠酒因謝','文同','宋','宋诗','song-poetry','','[]','山城物色正嚴冬，梅放長梢露小紅。',64,'全唐诗/poet.song.25000.json','["山城物色正嚴冬，梅放長梢露小紅。", "破萼未深聊敵雪，收香不密任隨風。", "盡教插滿金釵上，休管吹殘玉笛中。", "須至開筵召佳客，爲公連夜賞郫筒。"]'),
('1c5120ec-c789-42b2-b021-f0bd392e8bb7','登陵陽雲山閣寄上吳尹','文同','宋','宋诗','song-poetry','','[]','雲山高閣倚危牆，晚意無窮在渺茫。',64,'全唐诗/poet.song.25000.json','["雲山高閣倚危牆，晚意無窮在渺茫。", "極望不知雲幾許，滿空惟見雁交相。", "與誰把酒邀明月，獨自吟詩到夕陽。", "因念平臺有佳興，鄒生枚叟奉梁王。"]'),
('69a23382-b40a-4e10-9075-8fa0b41ed4bd','和寄白聖均','文同','宋','宋诗','song-poetry','','[]','年來雙鬢已絲絲，頭角低摧羽翼垂。',64,'全唐诗/poet.song.25000.json','["年來雙鬢已絲絲，頭角低摧羽翼垂。", "無命不窮常自笑，有謀皆拙敢求知。", "榮途謾說居三館，僻郡還甘守一麾。", "頼是山城好風物，不能逢子共吟詩。"]'),
('862b807d-abbe-4596-bedf-97df4f69c125','和提刑郎中閱兵之什','文同','宋','宋诗','song-poetry','','[]','曉營金革列周遭，大纛長牙擁帳高。',64,'全唐诗/poet.song.25000.json','["曉營金革列周遭，大纛長牙擁帳高。", "虎豹用韜傳妙略，龍蛇供陣役群豪。", "言初撫處如蕭纊，恩盡均時若楚醪。", "敢謂施行剪諸盜，亡之纔比一牛毛。"]'),
('b74b762a-44c7-4ecf-b1fe-0370c2e18c51','晚坐山亭口占','文同','宋','宋诗','song-poetry','','[]','嶺上生來月似磨，岩前斷去雲如削。',32,'全唐诗/poet.song.25000.json','["嶺上生來月似磨，岩前斷去雲如削。", "遥聞褐吏叩高林，應是雷公催采藥。"]'),
('6336ab87-3fe7-4d0e-a9d9-258d2369cea7','送王晦叔','文同','宋','宋诗','song-poetry','','[]','豈無舊德爲清望，亦有彊親在要流。',64,'全唐诗/poet.song.25000.json','["豈無舊德爲清望，亦有彊親在要流。", "班簿至今纔博士，郡書猶自許諸侯。", "貧甘遠宦冰盈腹，老憶高堂雪滿頭。", "不恃交期便求去，趁歸春圃奉蘭羞。"]'),
('a0146cd3-3eb1-497d-808c-800831c3e3d7','重送  其一','文同','宋','宋诗','song-poetry','','[]','一生自守至如此，惟道外皆非所親。',32,'全唐诗/poet.song.25000.json','["一生自守至如此，惟道外皆非所親。", "顧己通塞盡有命，是身可忍求因人。"]'),
('fdf6b9ad-3605-4e73-af0d-922543d6cf9a','重送  其二','文同','宋','宋诗','song-poetry','','[]','燕尾歸艎正穩，鴨頭春水方深。',28,'全唐诗/poet.song.25000.json','["燕尾歸艎正穩，鴨頭春水方深。", "不得同摇楚棹，與君齊到山陰。"]'),
('0e1f2f88-5b7c-4ee3-a5cf-3e1acc83571a','登山亭','文同','宋','宋诗','song-poetry','','[]','登臨平楚外，徙倚夕陽間。',48,'全唐诗/poet.song.25000.json','["登臨平楚外，徙倚夕陽間。", "歸鳥亂飛葉，暮雲凝遠山。", "行知筋力倦，愁欲鬢毛斑。", "坐久成搔首，疏慵好强顔。"]'),
('6d6bd6f9-f7e3-4be4-b37b-2339b13a4ed3','文領相仍意慮煩濁聊携野策獨訪山園因睹霜柏亭殘梅憶公向時有詩酒之惠感物成詩繕寫拜呈知府龍圖諫議吳公','文同','宋','宋诗','song-poetry','','[]','昨日梅開飲公酒，今朝梅謝念公詩。',64,'全唐诗/poet.song.25000.json','["昨日梅開飲公酒，今朝梅謝念公詩。", "眼前光景急如水，案上簿書棼若絲。", "且試輟忙來此地，可憐遺恨滿殘枝。", "西園想已成青實，敢問調羹去幾時。"]'),
('689a6853-133d-4629-b3b9-17d7181277c6','依韵和張推官元夕','文同','宋','宋诗','song-poetry','','[]','山郡上元榮樂事，大開金地作遨場。',64,'全唐诗/poet.song.25000.json','["山郡上元榮樂事，大開金地作遨場。", "烟雲向曉誰教霽，燈燭乘春自有香。", "紫陌熒煌隨步遠，綵棚佳麗鬥眉長。", "遊人莫惜酬高直，買取銀蟾一寸光。"]'),
('98e2dd68-0bcb-4951-8524-86eacdf5bef6','小閣戲書','文同','宋','宋诗','song-poetry','','[]','閑揭新刊集，時裝舊窨香。',24,'全唐诗/poet.song.25000.json','["閑揭新刊集，時裝舊窨香。", "還如到茂灌，無物在床旁。"]'),
('7b90f6cb-687b-46b3-aeec-522f0e274c30','伐枯株','文同','宋','宋诗','song-poetry','','[]','層崖垂空石壁牢，上有大木百丈高。',64,'全唐诗/poet.song.25000.json','["層崖垂空石壁牢，上有大木百丈高。", "古荔全身裹鐵甲，頑薑滿腹鋪金毛。", "空根老蟒露擁腫，曲枿怪𪀢爭呼嗥。", "一朝壯士揮巨斧，無限隨死蓬與蒿。"]'),
('169c9576-10d4-4629-bf30-cc7c63003d2f','可笑口號  其一','文同','宋','宋诗','song-poetry','','[]','可笑庭前小兒女，栽盆貯水種浮萍。',32,'全唐诗/poet.song.25000.json','["可笑庭前小兒女，栽盆貯水種浮萍。", "不知何處聞人說，一夜一根生七莖。"]');
